import { getProduct } from '../../shared/utils/api/products.js';
import { addToCart } from '../../shared/utils/api/cart.js';

document.addEventListener('DOMContentLoaded', async () => {
    // helpers
    const getQueryParam = (param) => {
        const urlParams = new URLSearchParams(window.location.search);
        return urlParams.get(param);
    };

    const productId = getQueryParam('id');
    const container = document.getElementById('product-content');
    const loading = document.getElementById('loading-indicator');
    const errorEl = document.getElementById('error-message');

    if (!productId) {
        loading.style.display = 'none';
        errorEl.classList.remove('d-none');
        return;
    }

    try {
        const product = await getProduct(productId);

        if (!product) {
            throw new Error('Product not found');
        }

        renderProduct(product);
        loading.style.display = 'none';
        container.classList.remove('d-none');

    } catch (error) {
        console.error(error);
        loading.style.display = 'none';
        errorEl.classList.remove('d-none');
    }
});

let selectedColor = null;
let selectedSize = null;
let quantity = 1;

const renderProduct = (product) => {
    // Basic Info
    document.title = `${product.name} - ShopHub`;
    document.getElementById('breadcrumb-product-name').textContent = product.name;
    document.getElementById('product-category').textContent = product.category;
    document.getElementById('product-name').textContent = product.name;
    document.getElementById('product-price').textContent = `$${parseFloat(product.price).toFixed(2)}`;
    document.getElementById('product-description').textContent = product.description;

    // Image
    const imgEl = document.getElementById('main-image');
    imgEl.src = product.image_url || `https://via.placeholder.com/600x600?text=${encodeURIComponent(product.name)}`;
    imgEl.alt = product.name;

    // Badges
    const badgeContainer = document.getElementById('product-badges');
    if (product.tags && product.tags.length > 0) {
        product.tags.forEach(tag => {
            const span = document.createElement('span');
            span.className = `detail-badge badge-${tag}`; // e.g., badge-new
            span.textContent = tag;
            badgeContainer.appendChild(span);
        });
    }

    // Rating (Randomized for demo as data doesn't have it)
    const rating = (Math.random() * 1.5 + 3.5).toFixed(1); // 3.5 to 5.0
    const reviews = Math.floor(Math.random() * 200) + 10;
    document.getElementById('product-rating').innerHTML = `★ ★ ★ ★ ☆ <span style="font-size: 0.875rem; color: #6b7280; margin-left: 0.5rem;">(${reviews} reviews)</span>`;

    // Options Logic
    renderOptions(product);

    // Quantity Logic
    setupQuantity();

    // Add to Cart
    const addBtn = document.getElementById('add-to-cart-btn');
    addBtn.addEventListener('click', () => handleAddToCart(product));
};

const renderOptions = (product) => {
    // Colors
    const colorContainer = document.getElementById('color-options');
    const colorLabel = document.getElementById('selected-color-name');
    const colorSection = document.getElementById('color-options-container');

    if (product.colors && product.colors.length > 0) {
        // Select first by default
        selectedColor = product.colors[0];
        colorLabel.textContent = selectedColor;

        product.colors.forEach(color => {
            const btn = document.createElement('button');
            btn.className = `color-option ${color === selectedColor ? 'selected' : ''}`;
            btn.title = color;

            // Try to map color names to CSS colors, or use a default
            // In a real app, this mapping would be robust or come from DB (hex codes)
            btn.style.backgroundColor = mapColorToCss(color);

            btn.addEventListener('click', () => {
                // Update selection
                document.querySelectorAll('.color-option').forEach(b => b.classList.remove('selected'));
                btn.classList.add('selected');
                selectedColor = color;
                colorLabel.textContent = color;
            });

            colorContainer.appendChild(btn);
        });
    } else {
        colorSection.style.display = 'none';
    }

    // Sizes
    const sizeContainer = document.getElementById('size-options');
    const sizeLabel = document.getElementById('selected-size-name');
    const sizeSection = document.getElementById('size-options-container');

    if (product.sizes && product.sizes.length > 0) {
        // Select first by default
        selectedSize = product.sizes[0];
        sizeLabel.textContent = selectedSize;

        product.sizes.forEach(size => {
            const btn = document.createElement('button');
            btn.className = `text-option ${size === selectedSize ? 'selected' : ''}`;
            btn.textContent = size;

            btn.addEventListener('click', () => {
                document.querySelectorAll('.text-option').forEach(b => b.classList.remove('selected'));
                btn.classList.add('selected');
                selectedSize = size;
                sizeLabel.textContent = size;
            });

            sizeContainer.appendChild(btn);
        });
    } else {
        sizeSection.style.display = 'none';
    }

    // Hide options wrapper if neither exist
    if ((!product.colors || product.colors.length === 0) && (!product.sizes || product.sizes.length === 0)) {
        document.getElementById('product-options').style.display = 'none';
    }
};

const setupQuantity = () => {
    const min = document.getElementById('qty-minus');
    const plus = document.getElementById('qty-plus');
    const input = document.getElementById('qty-input');

    min.addEventListener('click', () => {
        let val = parseInt(input.value);
        if (val > 1) {
            input.value = val - 1;
            quantity = val - 1;
        }
    });

    plus.addEventListener('click', () => {
        let val = parseInt(input.value);
        if (val < 10) { // Max limit
            input.value = val + 1;
            quantity = val + 1;
        }
    });

    input.addEventListener('change', (e) => {
        let val = parseInt(e.target.value);
        if (val < 1) val = 1;
        if (val > 10) val = 10;
        e.target.value = val;
        quantity = val;
    });
};

const handleAddToCart = async (product) => {
    const btn = document.getElementById('add-to-cart-btn');
    const originalText = btn.textContent;

    btn.disabled = true;
    btn.textContent = 'Adding...';

    // Construct item with options
    // Note: The generic addToCart API might just take ID and Qty. 
    // If we wanted to support options in the cart, we'd need to update the cart logic to store options.
    // For now, we'll assume the basic cart and just add the item.
    // In a real app, we'd pass { id, qty, color: selectedColor, size: selectedSize }

    try {
        console.log(`Adding to cart: ${product.name} (Color: ${selectedColor}, Size: ${selectedSize}, Qty: ${quantity})`);

        await addToCart(product.id, quantity);

        btn.textContent = 'Added! ✓';
        btn.classList.remove('btn-primary');
        btn.classList.add('btn-success'); // Assuming we have this class or similar style
        btn.style.backgroundColor = 'var(--color-success-base)'; // Inline fail-safe
        btn.style.borderColor = 'var(--color-success-base)';

        setTimeout(() => {
            btn.textContent = originalText;
            btn.disabled = false;
            btn.classList.add('btn-primary');
            btn.classList.remove('btn-success');
            btn.style.backgroundColor = '';
            btn.style.borderColor = '';
        }, 2000);

    } catch (error) {
        console.error(error);
        btn.textContent = 'Error';
        setTimeout(() => {
            btn.textContent = originalText;
            btn.disabled = false;
        }, 2000);
    }
};

// Simple helper to map color names to CSS values
const mapColorToCss = (name) => {
    const lower = name.toLowerCase();
    if (lower.includes('black')) return '#000000';
    if (lower.includes('white')) return '#ffffff';
    if (lower.includes('red')) return '#ef4444';
    if (lower.includes('blue')) return '#3b82f6';
    if (lower.includes('green')) return '#22c55e';
    if (lower.includes('gray') || lower.includes('grey') || lower.includes('silver')) return '#9ca3af';
    if (lower.includes('gold') || lower.includes('starlight')) return '#fde047';
    if (lower.includes('pink')) return '#f9a8d4';
    if (lower.includes('purple') || lower.includes('violet')) return '#a855f7';
    if (lower.includes('navy')) return '#1e3a8a';
    if (lower.includes('khaki')) return '#d4d4aa';
    if (lower.includes('olive')) return '#808000';
    // Default fallback
    return '#e5e7eb';
};



import { getProducts } from '../../shared/utils/api/products.js';
import { addToCart } from '../../shared/utils/api/cart.js';

const initProducts = async () => {
  const container = document.getElementById('products-grid');
  const searchInput = document.getElementById('search-input');
  const maxPriceInput = document.getElementById('max-price-input');
  const applyBtn = document.getElementById('apply-filters-btn');
  const clearBtn = document.getElementById('clear-filters-btn');
  const countEl = document.getElementById('product-count');

  const render = async (filterParams = {}) => {
    container.innerHTML = '<p style="text-align: center; grid-column: 1/-1;"><span class="loading"></span> Loading products...</p>';

    try {
      const products = await getProducts(filterParams);

      if (!products || products.length === 0) {
        container.innerHTML = '<p style="text-align: center; grid-column: 1/-1; color: #6b7280;">No products found. Try adjusting your filters.</p>';
        countEl.textContent = 'No products found';
        return;
      }

      countEl.textContent = `Showing ${products.length} product${products.length !== 1 ? 's' : ''}`;

      container.innerHTML = products.map((product, index) => {
        const discount = Math.random() > 0.7 ? Math.floor(Math.random() * 40) + 10 : 0;
        const originalPrice = discount ? (parseFloat(product.price) / (1 - discount/100)).toFixed(2) : null;
        const isExpress = Math.random() > 0.6;
        const rating = (Math.random() * 2 + 3).toFixed(1);
        const reviews = Math.floor(Math.random() * 500) + 10;

        return `
        <article class="product-card" data-product-id="${product.id}" data-category="${product.category || 'general'}">
          <a href="./detail.html?id=${product.id}" class="product-link" data-product-id="${product.id}">
            <div class="product-image">
              <img 
                ${index > 3 ? 'data-src' : 'src'}="${product.image_url || 'https://via.placeholder.com/400x400?text=' + encodeURIComponent(product.name)}"
                alt="${product.name}"
                loading="${index > 3 ? 'lazy' : 'eager'}"
                decoding="async"
                ${index > 3 ? 'class="skeleton"' : ''}
              >
              ${isExpress ? '<span class="badge badge-express">Express</span>' : ''}
              ${discount > 0 ? `<span class="badge badge-deal">-${discount}%</span>` : ''}
            </div>
            <div class="product-info">
              <h3 class="product-name">${product.name}</h3>
              <div class="product-pricing">
                <p class="price">$${parseFloat(product.price).toFixed(2)}</p>
                ${originalPrice ? `<span class="price-original">$${originalPrice}</span>` : ''}
                <button class="btn btn-primary" data-action="add-to-cart" data-product-id="${product.id}">Add to Cart</button>
              </div>
              <div class="product-meta">
                <span class="rating" title="${rating} out of 5 stars">★★★★☆ (${reviews})</span>
              </div>
            </div>
          </a>
        </article>
      `;
      }).join('');

      // Initialize lazy loading for images
      initLazyLoading();

      // Add event listeners to product links
      container.querySelectorAll('.product-link').forEach(link => {
        link.addEventListener('click', (e) => {
          // Prevent navigation if the click was on the "Add to Cart" button
          if (e.target.closest('[data-action="add-to-cart"]')) {
            return;
          }
          // Allow native navigation to the details page
          // e.preventDefault(); // Removed to allow navigation
        });
      });

      // Add event listeners to all Add to Cart buttons
      container.querySelectorAll('[data-action="add-to-cart"]').forEach(btn => {
        btn.addEventListener('click', async (e) => {
          const originalText = btn.textContent;
          const productId = btn.dataset.productId;

          btn.disabled = true;
          btn.textContent = 'Adding...';

          try {
            await addToCart(productId, 1);
            btn.textContent = 'Added! ✓';
            btn.classList.add('btn-success');
            setTimeout(() => {
              btn.textContent = originalText;
              btn.disabled = false;
              btn.classList.remove('btn-success');
            }, 2000);
          } catch (err) {
            console.error(err);
            btn.textContent = 'Error';
            setTimeout(() => {
              btn.textContent = originalText;
              btn.disabled = false;
            }, 2000);
          }
        });
      });
    } catch (error) {
      console.error('Error loading products:', error);
      container.innerHTML = '<p style="text-align: center; grid-column: 1/-1; color: #ef4444;">Failed to load products. Please try again.</p>';
      countEl.textContent = 'Error loading products';
    }
  };

  await render();

  if (applyBtn) {
    applyBtn.addEventListener('click', () => {
      const keyword = searchInput.value.trim();
      const maxPrice = maxPriceInput.value;
      render({ keyword, maxPrice });
    });
  }

  if (clearBtn) {
    clearBtn.addEventListener('click', () => {
      searchInput.value = '';
      maxPriceInput.value = '';
      render();
    });
  }

  // Allow Enter key to apply filters
  [searchInput, maxPriceInput].forEach(input => {
    if (input) {
      input.addEventListener('keypress', (e) => {
        if (e.key === 'Enter') {
          applyBtn.click();
        }
      });
    }
  });
};

// Lazy Loading Implementation
const initLazyLoading = () => {
  if ('IntersectionObserver' in window) {
    const imageObserver = new IntersectionObserver((entries) => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          const img = entry.target;
          if (img.dataset.src) {
            img.src = img.dataset.src;
            img.classList.remove('skeleton');
            imageObserver.unobserve(img);
          }
        }
      });
    }, {
      rootMargin: '50px'
    });

    document.querySelectorAll('img[data-src]').forEach(img => {
      imageObserver.observe(img);
    });
  } else {
    // Fallback for browsers without IntersectionObserver
    document.querySelectorAll('img[data-src]').forEach(img => {
      img.src = img.dataset.src;
      img.classList.remove('skeleton');
    });
  }
};

// Search debouncing
let searchDebounceTimer;
const initSearchAutocomplete = (searchInput) => {
  if (!searchInput) return;

  searchInput.addEventListener('input', (e) => {
    clearTimeout(searchDebounceTimer);
    const value = e.target.value.trim();

    if (value.length > 2) {
      searchDebounceTimer = setTimeout(() => {
        console.log('Search for:', value);
        // Future: Implement autocomplete API call
      }, 300);
    }
  });
};

document.addEventListener('DOMContentLoaded', () => {
  initProducts();
  initSearchAutocomplete(document.getElementById('search-input'));
});



