'use client';

import React, { useEffect, useState } from 'react';
import Image from 'next/image';
import Link from 'next/link';
import Icon from '@/components/Icon';
import { collection, query, where, getDocs, doc, getDoc } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import { Product } from '@/types/schema';

interface ServiceWithMerchant extends Product {
  storeName: string;
}

const formatDuration = (mins: number) => {
  if (!mins) return 'N/A';
  if (mins < 60) return `${mins} min`;
  const h = Math.floor(mins / 60);
  const m = mins % 60;
  return m ? `${h}h ${m}m` : `${h}h`;
};

export default function ServicesPage() {
  const [services, setServices] = useState<ServiceWithMerchant[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedCategory, setSelectedCategory] = useState('All');

  useEffect(() => {
    const fetchServices = async () => {
      try {
        const servicesQuery = query(collection(db, "products"), where("itemType", "==", "service"));
        const snapshot = await getDocs(servicesQuery);

        const servicesList: ServiceWithMerchant[] = [];

        for (const docSnap of snapshot.docs) {
          const data = docSnap.data() as Product;
          const serviceData = { id: docSnap.id, ...data } as ServiceWithMerchant;

          // Fetch merchant info
          if (data.merchantId) {
            try {
              const userDoc = await getDoc(doc(db, "users", data.merchantId));
              if (userDoc.exists()) {
                serviceData.storeName = userDoc.data().storeName || 'Independent Professional';
              } else {
                serviceData.storeName = 'Independent Professional';
              }
            } catch (e) {
              serviceData.storeName = 'Independent Professional';
            }
          } else {
            serviceData.storeName = 'Independent Professional';
          }

          servicesList.push(serviceData);
        }

        setServices(servicesList);
      } catch (error) {
        console.error("Error fetching services:", error);
      } finally {
        setLoading(false);
      }
    };

    fetchServices();
  }, []);

  const categories = ['All', ...Array.from(new Set(services.map(s => s.category || 'Other')))];

  const filteredServices = selectedCategory === 'All' 
    ? services 
    : services.filter(s => (s.category || 'Other') === selectedCategory);

  if (loading) {
    return (
      <div className="min-h-screen bg-surface flex items-center justify-center">
        <div className="text-center">
          <div className="w-16 h-16 border-4 border-on-surface border-t-primary-container rounded-full animate-spin mx-auto mb-6 shadow-[4px_4px_0px_0px_var(--color-on-surface)]"></div>
          <h2 className="font-headline-md font-black uppercase text-on-surface tracking-widest text-xl">
            Loading Services...
          </h2>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-surface px-6 py-12 md:px-16 max-w-[1440px] mx-auto">
      <div className="mb-12 border-b-4 border-on-surface pb-6 inline-block w-full">
        <h1 className="font-headline-lg font-black text-5xl uppercase text-on-surface">Premium Services</h1>
        <p className="mt-4 text-xl font-bold text-secondary">Discover and book expert services from trusted merchants.</p>
      </div>

      {services.length > 0 ? (
        <>
          <div className="flex flex-wrap gap-4 mb-10">
            {categories.map(category => (
              <button
                key={category}
                onClick={() => setSelectedCategory(category)}
                className={`px-6 py-2 border-2 border-on-surface font-bold uppercase transition-all duration-200 active:translate-y-1 active:shadow-none ${
                  selectedCategory === category
                    ? 'bg-primary-container text-on-primary-container shadow-[4px_4px_0px_0px_var(--color-on-surface)] translate-y-[-2px]'
                    : 'bg-surface hover:bg-surface-container text-on-surface'
                }`}
              >
                {category}
              </button>
            ))}
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {filteredServices.map(service => (
              <div 
                key={service.id}
                className="flex flex-col bg-surface border-4 border-on-surface shadow-[8px_8px_0px_0px_var(--color-on-surface)] hover:-translate-y-2 hover:shadow-[12px_12px_0px_0px_var(--color-on-surface)] transition-all duration-300"
              >
                <div className="relative w-full h-64 border-b-4 border-on-surface bg-surface-dim overflow-hidden flex items-center justify-center">
                  {service.imageUrls?.[0] ? (
                    <Image
                      src={service.imageUrls[0]}
                      alt={service.name}
                      fill
                      className="object-cover"
                      sizes="(max-width: 768px) 100vw, (max-width: 1200px) 50vw, 33vw"
                    />
                  ) : (
                    <Icon name="design_services" className="text-6xl text-on-surface opacity-20" />
                  )}
                  <div className="absolute top-4 left-4 bg-primary-container text-on-primary-container px-3 py-1 font-bold text-sm border-2 border-on-surface uppercase shadow-[2px_2px_0px_0px_var(--color-on-surface)]">
                    {service.category || 'Service'}
                  </div>
                </div>

                <div className="p-6 flex flex-col flex-grow">
                  <div className="flex justify-between items-start mb-4">
                    <h2 className="font-black text-2xl uppercase leading-tight line-clamp-2">{service.name}</h2>
                  </div>

                  <div className="flex items-center gap-2 mb-4 text-secondary font-semibold border-b-2 border-on-surface pb-4">
                    <Icon name="storefront" className="text-lg" />
                    <span className="uppercase text-sm tracking-wider">{service.storeName}</span>
                  </div>

                  <p className="text-on-surface font-medium line-clamp-3 mb-6 flex-grow whitespace-pre-line">
                    {service.description}
                  </p>

                  <div className="grid grid-cols-2 gap-4 mb-6 bg-surface-container border-2 border-on-surface p-4">
                    <div>
                      <span className="block text-xs uppercase font-bold text-secondary mb-1">Duration</span>
                      <div className="flex items-center gap-2 font-black">
                        <Icon name="schedule" className="text-lg" />
                        {formatDuration(service.duration || 60)}
                      </div>
                    </div>
                    <div>
                      <span className="block text-xs uppercase font-bold text-secondary mb-1">Starting At</span>
                      <div className="flex items-center gap-2 font-black text-primary-container text-xl">
                        Ksh {service.price.toFixed(2)}
                      </div>
                    </div>
                  </div>

                  <Link 
                    href={`/services/${service.id}`}
                    className="w-full inline-block text-center bg-primary-container text-on-primary-container font-black uppercase tracking-wider py-4 border-2 border-on-surface shadow-[4px_4px_0px_0px_var(--color-on-surface)] hover:bg-[#ffb05c] active:shadow-none active:translate-x-[4px] active:translate-y-[4px] transition-all"
                  >
                    View Details
                  </Link>
                </div>
              </div>
            ))}
          </div>
        </>
      ) : (
        <div className="text-center py-20 bg-surface border-4 border-on-surface shadow-[8px_8px_0px_0px_var(--color-on-surface)]">
          <Icon name="build" className="text-6xl text-secondary mb-4" />
          <h2 className="font-headline-md font-black text-2xl uppercase mb-2">No Services Available</h2>
          <p className="text-secondary font-bold">Check back later or register as a merchant to add your own services!</p>
        </div>
      )}
    </div>
  );
}



import React, { useState } from 'react';
import { SystemCategory, CategoryNode } from '@/types/schema';
import { createSystemCategory, updateSystemCategory, deleteSystemCategory, seedCategories } from '@/lib/api/categories';
import Icon from '@/components/Icon';

interface Props {
  categories: SystemCategory[];
  loading: boolean;
  onRefresh: () => void;
}

export default function CategoryManager({ categories, loading, onRefresh }: Props) {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editData, setEditData] = useState<Partial<SystemCategory>>({});
  const [isSaving, setIsSaving] = useState(false);
  const [activeType, setActiveType] = useState<'goods' | 'services'>('goods');

  const handleEdit = (cat: SystemCategory) => {
    setEditingId(cat.id!);
    setEditData(cat);
  };

  const handleAddNew = () => {
    setEditingId('new');
    setEditData({ type: activeType, name: '', categories: [] });
  };

  const handleSave = async () => {
    if (!editData.name) return;
    setIsSaving(true);
    try {
      if (editingId === 'new') {
        await createSystemCategory(editData as Omit<SystemCategory, 'id'>);
      } else {
        await updateSystemCategory(editingId!, editData);
      }
      setEditingId(null);
      setEditData({});
      onRefresh();
    } catch (e) {
      console.error(e);
    } finally {
      setIsSaving(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm('Are you sure you want to delete this category group?')) return;
    try {
      await deleteSystemCategory(id);
      onRefresh();
    } catch (e) {
      console.error(e);
    }
  };

  const handleSeed = async () => {
    await seedCategories();
    onRefresh();
  };

  const addSubcategory = () => {
    setEditData(prev => ({
      ...prev,
      categories: [...(prev.categories || []), { name: '', subcategories: [] }]
    }));
  };

  const updateSubcategoryName = (index: number, name: string) => {
    const updated = [...(editData.categories || [])];
    updated[index].name = name;
    setEditData(prev => ({ ...prev, categories: updated }));
  };

  const removeSubcategory = (index: number) => {
    const updated = [...(editData.categories || [])];
    updated.splice(index, 1);
    setEditData(prev => ({ ...prev, categories: updated }));
  };

  const addNestedSubcategory = (index: number) => {
    const updated = [...(editData.categories || [])];
    updated[index].subcategories = [...(updated[index].subcategories || []), ''];
    setEditData(prev => ({ ...prev, categories: updated }));
  };

  const updateNestedSubcategory = (catIndex: number, subIndex: number, val: string) => {
    const updated = [...(editData.categories || [])];
    const subs = [...(updated[catIndex].subcategories || [])];
    subs[subIndex] = val;
    updated[catIndex].subcategories = subs;
    setEditData(prev => ({ ...prev, categories: updated }));
  };

  const removeNestedSubcategory = (catIndex: number, subIndex: number) => {
    const updated = [...(editData.categories || [])];
    const subs = [...(updated[catIndex].subcategories || [])];
    subs.splice(subIndex, 1);
    updated[catIndex].subcategories = subs;
    setEditData(prev => ({ ...prev, categories: updated }));
  };

  if (loading) {
    return (
      <div className="bg-surface border-2 border-on-surface p-10 text-center shadow-[4px_4px_0px_0px_var(--color-on-surface)]">
        <Icon name="sync" className="text-4xl animate-spin text-primary-container mx-auto" />
      </div>
    );
  }

  const filteredCategories = categories.filter(c => c.type === activeType);

  return (
    <div className="space-y-6">
      <header className="flex justify-between items-end mb-4">
        <div>
          <p className="font-extrabold text-xs text-primary-container uppercase tracking-widest mb-1.5">Taxonomy</p>
          <h2 className="font-headline-md text-3xl font-black text-on-surface uppercase tracking-tight">Category Management</h2>
        </div>
        <div className="flex gap-2">
          {categories.length === 0 && (
            <button onClick={handleSeed} className="bg-surface-container text-on-surface border-2 border-on-surface px-4 py-2 font-bold text-xs uppercase hover:bg-surface-dim">
              Seed Defaults
            </button>
          )}
          <button onClick={handleAddNew} className="bg-primary-container text-on-primary-container border-2 border-on-surface px-4 py-2 font-bold text-xs uppercase hover:brightness-110 shadow-[2px_2px_0px_0px_var(--color-on-surface)]">
            + New Category Group
          </button>
        </div>
      </header>

      {/* Tabs for Goods / Services */}
      <div className="flex gap-4 border-b-2 border-on-surface mb-6">
        <button 
          onClick={() => setActiveType('goods')}
          className={`px-4 py-2 font-black uppercase text-sm ${activeType === 'goods' ? 'bg-on-surface text-surface' : 'hover:bg-surface-container'}`}
        >
          Goods
        </button>
        <button 
          onClick={() => setActiveType('services')}
          className={`px-4 py-2 font-black uppercase text-sm ${activeType === 'services' ? 'bg-on-surface text-surface' : 'hover:bg-surface-container'}`}
        >
          Services
        </button>
      </div>

      {editingId ? (
        <div className="bg-surface border-2 border-on-surface shadow-[4px_4px_0px_0px_var(--color-on-surface)] p-6">
          <h3 className="font-black text-xl mb-6 uppercase border-b-2 border-on-surface pb-2">
            {editingId === 'new' ? 'Add New Category Group' : 'Edit Category Group'}
          </h3>
          <div className="space-y-4">
            <div>
              <label className="block text-xs font-bold uppercase tracking-wider mb-1">Group Name</label>
              <input 
                type="text" 
                value={editData.name || ''} 
                onChange={(e) => setEditData({ ...editData, name: e.target.value })}
                className="w-full bg-surface-container border-2 border-on-surface p-2 font-medium focus:outline-none focus:border-primary-container"
                placeholder="e.g. Electronics"
              />
            </div>

            <div className="pt-4">
              <label className="block text-xs font-bold uppercase tracking-wider mb-4 border-b border-surface-container pb-2">Top-Level Categories</label>
              {(editData.categories || []).map((cat, i) => (
                <div key={i} className="mb-6 p-4 border-2 border-surface-container-highest bg-surface-container-lowest relative">
                  <button onClick={() => removeSubcategory(i)} className="absolute top-2 right-2 text-error hover:text-red-700">
                    <Icon name="delete" className="text-[18px]" />
                  </button>
                  <div className="mb-3 pr-8">
                     <label className="block text-[10px] font-bold uppercase tracking-wider mb-1">Category Name</label>
                     <input 
                       type="text" 
                       value={cat.name} 
                       onChange={(e) => updateSubcategoryName(i, e.target.value)}
                       className="w-full bg-surface border border-on-surface p-1.5 text-sm"
                     />
                  </div>
                  <div className="pl-4 border-l-2 border-secondary-container">
                     <label className="block text-[10px] font-bold uppercase tracking-wider mb-2 text-secondary">Nested Subcategories</label>
                     <div className="space-y-2 mb-2">
                       {(cat.subcategories || []).map((sub, j) => (
                         <div key={j} className="flex gap-2">
                           <input 
                             type="text" 
                             value={sub} 
                             onChange={(e) => updateNestedSubcategory(i, j, e.target.value)}
                             className="flex-1 bg-surface border border-surface-container-highest p-1 text-xs"
                             placeholder="Subcategory name"
                           />
                           <button onClick={() => removeNestedSubcategory(i, j)} className="text-secondary hover:text-error">
                             <Icon name="close" className="text-[16px]" />
                           </button>
                         </div>
                       ))}
                     </div>
                     <button onClick={() => addNestedSubcategory(i)} className="text-[10px] font-bold uppercase text-primary-container hover:underline flex items-center gap-1">
                       <Icon name="add" className="text-[14px]" /> Add Subcategory
                     </button>
                  </div>
                </div>
              ))}
              <button onClick={addSubcategory} className="mt-2 text-xs font-bold uppercase border-2 border-secondary text-secondary px-3 py-1.5 hover:bg-secondary hover:text-white transition-colors">
                + Add Top-Level Category
              </button>
            </div>

            <div className="flex justify-end gap-3 pt-6 border-t-2 border-on-surface">
              <button onClick={() => setEditingId(null)} className="px-6 py-2 border-2 border-on-surface font-bold text-xs uppercase hover:bg-surface-container">Cancel</button>
              <button onClick={handleSave} disabled={isSaving} className="px-6 py-2 bg-on-surface text-surface border-2 border-on-surface font-bold text-xs uppercase hover:bg-surface-dim flex items-center gap-2">
                {isSaving ? <Icon name="sync" className="animate-spin text-[14px]" /> : <Icon name="save" className="text-[14px]" />} Save Group
              </button>
            </div>
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredCategories.map(cat => (
            <div key={cat.id} className="bg-surface border-2 border-on-surface shadow-[4px_4px_0px_0px_var(--color-on-surface)] flex flex-col relative group">
              <div className="p-4 border-b-2 border-surface-container flex justify-between items-center bg-surface-container-low">
                <h4 className="font-black text-lg uppercase tracking-tight truncate pr-4">{cat.name}</h4>
                <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={() => handleEdit(cat)} className="text-secondary hover:text-primary-container">
                    <Icon name="edit" className="text-[18px]" />
                  </button>
                  <button onClick={() => handleDelete(cat.id!)} className="text-secondary hover:text-error">
                    <Icon name="delete" className="text-[18px]" />
                  </button>
                </div>
              </div>
              <div className="p-4 flex-1">
                <div className="flex flex-wrap gap-2">
                  {cat.categories.slice(0, 8).map((sub, i) => (
                    <span key={i} className="text-[10px] font-bold bg-surface-container px-2 py-1 uppercase border border-surface-container-highest">
                      {sub.name}
                    </span>
                  ))}
                  {cat.categories.length > 8 && (
                    <span className="text-[10px] font-bold text-secondary px-2 py-1 uppercase">
                      +{cat.categories.length - 8} more
                    </span>
                  )}
                </div>
              </div>
            </div>
          ))}
          {filteredCategories.length === 0 && (
             <div className="col-span-full text-center py-12 text-secondary">
               <Icon name="category" className="text-4xl mb-2 opacity-50" />
               <p className="text-sm font-bold uppercase tracking-wider">No {activeType} categories found.</p>
             </div>
          )}
        </div>
      )}
    </div>
  );
}



'use client';

import { useState, useEffect } from 'react';
import { getUserProfile, updateProfile, User } from '@/lib/api/auth';
import Icon from '@/components/Icon';

interface ProfileModalProps {
  isOpen: boolean;
  onClose: () => void;
  userAuth: { uid: string } | null;
}

export default function ProfileModal({ isOpen, onClose, userAuth }: ProfileModalProps) {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);

  const [formData, setFormData] = useState({
    first_name: '',
    last_name: '',
    username: '',
    location: '',
    phone: ''
  });

  useEffect(() => {
    if (isOpen && userAuth) {
      setLoading(true);
      setError(null);
      setSuccess(null);

      const fetchProfile = async () => {
        try {
          const profile = await getUserProfile(userAuth.uid);
          if (profile) {
            setUser(profile);
            setFormData({
              first_name: profile.first_name || '',
              last_name: profile.last_name || '',
              username: profile.username || '',
              location: profile.location || '',
              phone: profile.phone || ''
            });
          }
        } catch (err) {
          console.error("Failed to load profile", err);
          setError("Failed to load profile data.");
        } finally {
          setLoading(false);
        }
      };

      fetchProfile();
    }
  }, [isOpen, userAuth]);

  if (!isOpen) return null;

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    setError(null);
    setSuccess(null);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!user) return;

    setSaving(true);
    setError(null);
    setSuccess(null);

    try {
      await updateProfile(user.uid, formData);
      setSuccess('Profile updated successfully!');
      setUser(prev => prev ? { ...prev, ...formData } : null);
      setTimeout(() => {
        onClose();
      }, 1500);
    } catch (err: unknown) {
      if (err instanceof Error) {
        setError(err.message || 'Failed to update profile.');
      } else {
        setError('Failed to update profile.');
      }
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
      <div className="w-full max-w-lg bg-surface border-2 border-on-surface/10 rounded-2xl shadow-xl overflow-hidden flex flex-col max-h-[90vh]">
        <div className="px-6 py-4 border-b-2 border-on-surface/10 flex justify-between items-center bg-surface sticky top-0 z-10">
          <h2 className="text-2xl font-black font-headline-md text-on-surface tracking-tight">Edit Profile</h2>
          <button 
            onClick={onClose}
            className="p-2 hover:bg-surface-container rounded-full transition-colors"
            aria-label="Close"
          >
            <Icon name="close" className="text-on-surface" />
          </button>
        </div>

        <div className="p-6 overflow-y-auto">
          {loading ? (
            <div className="flex justify-center items-center py-12">
              <div className="w-8 h-8 border-4 border-on-surface/20 border-t-on-surface rounded-full animate-spin"></div>
            </div>
          ) : (
            <>
              {error && (
                <div className="mb-6 p-4 bg-error/10 border-l-4 border-error text-error text-sm font-semibold flex items-center gap-3">
                  <Icon name="error" />
                  {error}
                </div>
              )}

              {success && (
                <div className="mb-6 p-4 bg-primary-container/10 border-l-4 border-primary-container text-primary-container text-sm font-semibold flex items-center gap-3">
                  <Icon name="check_circle" />
                  {success}
                </div>
              )}

              <form onSubmit={handleSubmit} className="space-y-5">
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1.5">
                    <label className="block text-xs font-bold text-on-surface uppercase tracking-wider" htmlFor="first_name">
                      First Name
                    </label>
                    <input
                      type="text"
                      id="first_name"
                      name="first_name"
                      value={formData.first_name}
                      onChange={handleChange}
                      className="w-full bg-surface border-2 border-on-surface/20 rounded-none px-3 py-2 text-sm text-on-surface focus:border-primary-container focus:ring-1 focus:ring-primary-container transition-all outline-none"
                    />
                  </div>

                  <div className="space-y-1.5">
