                  >
                    {saving ? (
                      <>
                        <div className="w-3.5 h-3.5 border-2 border-surface/30 border-t-surface rounded-full animate-spin"></div>
                        Saving...
                      </>
                    ) : (
                      'Save Changes'
                    )}
                  </button>
                </div>
              </form>
            </>
          )}
        </div>
      </div>
    </div>
  );
}



'use client';

import { useState, useEffect } from 'react';

export default function Countdown() {
  // Target date: September 1st, 2026
  const targetDate = new Date('2026-09-01T00:00:00').getTime();

  const [mounted, setMounted] = useState(false);
  const [timeLeft, setTimeLeft] = useState({
    days: 0,
    hours: 0,
    minutes: 0,
    seconds: 0
  });

  useEffect(() => {
    setMounted(true);

    const calculateTimeLeft = () => {
      const difference = targetDate - new Date().getTime();
      if (difference > 0) {
        setTimeLeft({
          days: Math.floor(difference / (1000 * 60 * 60 * 24)),
          hours: Math.floor((difference / (1000 * 60 * 60)) % 24),
          minutes: Math.floor((difference / 1000 / 60) % 60),
          seconds: Math.floor((difference / 1000) % 60)
        });
      } else {
        setTimeLeft({ days: 0, hours: 0, minutes: 0, seconds: 0 });
      }
    };

    calculateTimeLeft();
    const timer = setInterval(calculateTimeLeft, 1000);

    return () => clearInterval(timer);
  }, [targetDate]);

  if (!mounted) {
    return <div className="h-28"></div>; // Placeholder space
  }

  return (
    <div className="flex gap-2 sm:gap-4 justify-center items-center my-8">
      <div className="flex flex-col items-center w-20 sm:w-24 py-4 bg-surface border-2 border-on-surface shadow-[4px_4px_0px_0px_var(--color-on-surface)]">
        <span className="font-headline-md text-3xl sm:text-4xl font-black text-primary-container">{timeLeft.days}</span>
        <span className="text-[10px] sm:text-xs font-bold uppercase tracking-wider text-secondary mt-1">Days</span>
      </div>
      <div className="text-xl sm:text-2xl font-black text-on-surface/50 animate-pulse">:</div>

      <div className="flex flex-col items-center w-20 sm:w-24 py-4 bg-surface border-2 border-on-surface shadow-[4px_4px_0px_0px_var(--color-on-surface)]">
        <span className="font-headline-md text-3xl sm:text-4xl font-black text-primary-container">{timeLeft.hours.toString().padStart(2, '0')}</span>
        <span className="text-[10px] sm:text-xs font-bold uppercase tracking-wider text-secondary mt-1">Hours</span>
      </div>
      <div className="text-xl sm:text-2xl font-black text-on-surface/50 animate-pulse">:</div>

      <div className="flex flex-col items-center w-20 sm:w-24 py-4 bg-surface border-2 border-on-surface shadow-[4px_4px_0px_0px_var(--color-on-surface)]">
        <span className="font-headline-md text-3xl sm:text-4xl font-black text-primary-container">{timeLeft.minutes.toString().padStart(2, '0')}</span>
        <span className="text-[10px] sm:text-xs font-bold uppercase tracking-wider text-secondary mt-1">Mins</span>
      </div>
      <div className="text-xl sm:text-2xl font-black text-on-surface/50 animate-pulse">:</div>

      <div className="flex flex-col items-center w-20 sm:w-24 py-4 bg-surface border-2 border-on-surface shadow-[4px_4px_0px_0px_var(--color-on-surface)]">
        <span className="font-headline-md text-3xl sm:text-4xl font-black text-primary-container">{timeLeft.seconds.toString().padStart(2, '0')}</span>
        <span className="text-[10px] sm:text-xs font-bold uppercase tracking-wider text-secondary mt-1">Secs</span>
      </div>
    </div>
  );
}



"use client";

import { useEffect, useState } from "react";
import Link from "next/link";
import { doc, getDoc } from "firebase/firestore";
import { auth, db } from "@/lib/firebase";

export default function OnboardingPopup() {
  const [loading, setLoading] = useState(true);
  const [needsOnboarding, setNeedsOnboarding] = useState(false);

  useEffect(() => {
    const checkOnboarding = async () => {
      const user = auth.currentUser;
      if (!user) {
        setLoading(false);
        return;
      }

      try {
        const userDoc = await getDoc(doc(db, "users", user.uid));
        if (userDoc.exists()) {
          const data = userDoc.data();
          if (data.role === "merchant" && !data.onboardingComplete) {
            setNeedsOnboarding(true);
          }
        }
      } catch (error) {
        console.error("Error checking onboarding status:", error);
      } finally {
        setLoading(false);
      }
    };

    if (auth.currentUser) {
      checkOnboarding();
    } else {
      const unsubscribe = auth.onAuthStateChanged((user) => {
        if (user) checkOnboarding();
        else setLoading(false);
      });
      return () => unsubscribe();
    }
  }, []);

  if (loading || !needsOnboarding) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
      <div className="max-w-md w-full bg-surface border-4 border-on-surface shadow-[8px_8px_0px_0px_var(--color-on-surface)] p-8 text-center animate-in zoom-in-95 duration-200">
        <div className="w-16 h-16 bg-primary-container rounded-full flex items-center justify-center mx-auto mb-6 border-4 border-on-surface shadow-[4px_4px_0px_0px_var(--color-on-surface)]">
          <svg className="w-8 h-8 text-on-surface" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="square" strokeLinejoin="miter" strokeWidth="3" d="M13 10V3L4 14h7v7l9-11h-7z" />
          </svg>
        </div>
        <h2 className="font-headline-md font-black text-2xl uppercase tracking-tight mb-4 text-on-surface">
          Action Required
        </h2>
        <p className="font-body-md text-on-surface/80 mb-8 font-medium">
          Welcome to your Merchant Dashboard! Before you can start adding products and accepting orders, you need to complete your store profile.
        </p>
        <Link 
          href="/apply-merchant"
          className="inline-block w-full bg-primary-container text-on-surface py-4 font-black uppercase tracking-widest border-4 border-on-surface shadow-[4px_4px_0px_0px_var(--color-on-surface)] hover:translate-y-[2px] hover:translate-x-[2px] hover:shadow-[2px_2px_0px_0px_var(--color-on-surface)] transition-all"
        >
          Complete Profile
        </Link>
      </div>
    </div>
  );
}



'use client';

import { useEffect, useState } from 'react';
import { getReviewStats, ReviewStats } from '@/lib/api/reviews';
import Icon from '@/components/Icon';

interface ProductRatingBadgeProps {
  productId: string | number;
  showCount?: boolean;
}

export default function ProductRatingBadge({ productId, showCount = true }: ProductRatingBadgeProps) {
  const [stats, setStats] = useState<ReviewStats | null>(null);

  useEffect(() => {
    let mounted = true;
    const fetchStats = async () => {
      try {
        const s = await getReviewStats(productId);
        if (mounted) setStats(s);
      } catch (err) {
        console.error('Error fetching review stats:', err);
      }
    };
    fetchStats();
    return () => { mounted = false; };
  }, [productId]);

  if (!stats || stats.totalReviews === 0) {
    return (
      <div className="flex items-center gap-1.5 text-xs font-semibold text-secondary/50">
        <span>No reviews yet</span>
      </div>
    );
  }

  return (
    <div className="flex items-center gap-1.5 text-xs font-semibold text-primary-container">
      <div className="flex items-center">
        <span className="font-bold mr-1">{stats.averageRating.toFixed(1)}</span>
        <Icon name="star" className="text-[14px]" />
      </div>
      {showCount && (
        <span className="text-secondary text-[10px]">({stats.totalReviews} {stats.totalReviews === 1 ? 'review' : 'reviews'})</span>
      )}
    </div>
  );
}



import { useState, useEffect } from 'react';
import { SystemCategory } from '@/types/schema';
import { getSystemCategories } from '@/lib/api/categories';

export function useCategories() {
  const [categories, setCategories] = useState<SystemCategory[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let isMounted = true;

    const fetchCategories = async () => {
      try {
        const data = await getSystemCategories();
        if (isMounted) {
          setCategories(data);
        }
      } catch (err) {
        console.error('Failed to fetch categories', err);
      } finally {
        if (isMounted) {
          setLoading(false);
        }
      }
    };

    fetchCategories();

    return () => {
      isMounted = false;
    };
  }, []);

  return { categories, loading };
}



import { getProduct } from './products';
import { Product } from '@/lib/data/products-data';
import { auth, db } from '@/lib/firebase';
import { collection, doc, getDocs, getDoc, setDoc, deleteDoc, Timestamp } from 'firebase/firestore';

export interface CartItem {
  id: number | string;
  product_id: number | string;
  quantity: number;
  Product?: Product;
}

export interface Cart {
  CartItems: CartItem[];
}

const CART_STORAGE_KEY = 'shop_cart_local';

// LOCAL STORAGE HELPERS
const getLocalCart = (): CartItem[] => {
  if (typeof window === 'undefined') return [];
  const cartJson = localStorage.getItem(CART_STORAGE_KEY);
  return cartJson ? JSON.parse(cartJson) : [];
};

const dispatchCartUpdate = () => {
  if (typeof window !== 'undefined') {
    window.dispatchEvent(new Event('cartUpdated'));
  }
};

const saveLocalCart = (cart: CartItem[]) => {
  if (typeof window !== 'undefined') {
    localStorage.setItem(CART_STORAGE_KEY, JSON.stringify(cart));
    dispatchCartUpdate(); // trigger UI updates
  }
};

export const getCart = async (): Promise<Cart> => {
  const user = auth.currentUser;

  if (!user) {
    const items = getLocalCart();
    // Resolve products for local items to have complete data
    const populatedItems: CartItem[] = [];
    for (const item of items) {
      const product = await getProduct(item.product_id);
      if (product) {
        populatedItems.push({ ...item, Product: product });
      }
    }
    return { CartItems: populatedItems };
  }

  try {
    const cartRef = collection(db, 'users', user.uid, 'cart');
    const snapshot = await getDocs(cartRef);
    const items: CartItem[] = [];

    for (const docSnap of snapshot.docs) {
      const data = docSnap.data();
      const product = await getProduct(data.productId);
      if (product) {
        items.push({
          id: docSnap.id,
          product_id: data.productId,
          quantity: data.quantity,
          Product: product
        });
      }
    }
    return { CartItems: items };
  } catch (error) {
    console.error('Error fetching cart from Firestore:', error);
    return { CartItems: [] };
  }
};

export const addToCart = async (productId: number | string, quantity = 1) => {
  const user = auth.currentUser;

  if (!user) {
    const items = getLocalCart();
    const existing = items.find(i => i.product_id == productId);
    if (existing) {
      existing.quantity += quantity;
    } else {
      items.push({ id: Date.now(), product_id: productId, quantity });
    }
    saveLocalCart(items);
    return { message: 'Item added to local cart' };
  }

  try {
    const cartDocRef = doc(db, 'users', user.uid, 'cart', productId.toString());
    const docSnap = await getDoc(cartDocRef);

    if (docSnap.exists()) {
      const existingData = docSnap.data();
      await setDoc(cartDocRef, {
        productId: productId.toString(),
        quantity: existingData.quantity + quantity,
        addedAt: Timestamp.now()
      }, { merge: true });
    } else {
      await setDoc(cartDocRef, {
        productId: productId.toString(),
        quantity: quantity,
        addedAt: Timestamp.now()
      });
    }

    dispatchCartUpdate();
    return { message: 'Item added to cloud cart' };
  } catch (error) {
    console.error('Error adding to cloud cart:', error);
    throw error;
  }
};

export const removeFromCart = async (productId: number | string) => {
  const user = auth.currentUser;

  if (!user) {
    let items = getLocalCart();
    items = items.filter(i => i.product_id != productId);
    saveLocalCart(items);
    return { message: 'Item removed from local cart' };
  }

  try {
    await deleteDoc(doc(db, 'users', user.uid, 'cart', productId.toString()));
    dispatchCartUpdate();
    return { message: 'Item removed from cloud cart' };
  } catch (error) {
    console.error('Error removing from cloud cart:', error);
    throw error;
  }
};

export const updateCartItem = async (productId: number | string, quantity: number) => {
  const user = auth.currentUser;

  if (!user) {
    const items = getLocalCart();
    const existing = items.find(i => i.product_id == productId);
    if (existing) {
      existing.quantity = quantity;
      saveLocalCart(items);
    }
    return { message: 'Local cart updated' };
  }

  try {
    await setDoc(doc(db, 'users', user.uid, 'cart', productId.toString()), {
      quantity: quantity
    }, { merge: true });
    dispatchCartUpdate();
    return { message: 'Cloud cart updated' };
  } catch (error) {
    console.error('Error updating cloud cart:', error);
    throw error;
  }
};

export const clearCart = async () => {
  const user = auth.currentUser;

  if (!user) {
    if (typeof window !== 'undefined') {
      localStorage.removeItem(CART_STORAGE_KEY);
      window.dispatchEvent(new Event('cartUpdated'));
    }
    return;
  }

  try {
    const cartRef = collection(db, 'users', user.uid, 'cart');
    const snapshot = await getDocs(cartRef);
    const deletePromises = snapshot.docs.map(docSnap => deleteDoc(docSnap.ref));
    await Promise.all(deletePromises);
    dispatchCartUpdate();
  } catch (error) {
    console.error('Error clearing cloud cart:', error);
  }
};

export const syncLocalCartToFirestore = async (userId: string) => {
  const localItems = getLocalCart();
  if (localItems.length === 0) return;

  try {
    for (const item of localItems) {
      const cartDocRef = doc(db, 'users', userId, 'cart', item.product_id.toString());
      const docSnap = await getDoc(cartDocRef);

      if (docSnap.exists()) {
        const existingData = docSnap.data();
        await setDoc(cartDocRef, {
          productId: item.product_id.toString(),
          quantity: existingData.quantity + item.quantity,
          updatedAt: Timestamp.now()
        }, { merge: true });
      } else {
        await setDoc(cartDocRef, {
          productId: item.product_id.toString(),
          quantity: item.quantity,
          addedAt: Timestamp.now()
        });
      }
    }
    // Clear local storage after successful sync
    if (typeof window !== 'undefined') {
      localStorage.removeItem(CART_STORAGE_KEY);
      dispatchCartUpdate();
    }
    console.log("Local cart synced to Firestore successfully.");
  } catch (error) {
    console.error("Error syncing local cart to Firestore:", error);
  }
};



import { collection, doc, getDocs, setDoc, deleteDoc, updateDoc, query, where } from 'firebase/firestore';
import { db } from '../firebase';
import { SystemCategory } from '@/types/schema';
import { CATEGORIES_DATA } from '../data/categories';

const COLLECTION_NAME = 'categories';

export const getSystemCategories = async (): Promise<SystemCategory[]> => {
  try {
    const q = collection(db, COLLECTION_NAME);
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as SystemCategory));
  } catch (error) {
    console.error('Error fetching categories:', error);
    return [];
  }
};

export const createSystemCategory = async (category: Omit<SystemCategory, 'id'>): Promise<string> => {
  try {
    const docRef = doc(collection(db, COLLECTION_NAME));
    await setDoc(docRef, { ...category, createdAt: new Date().toISOString() });
    return docRef.id;
  } catch (error) {
    console.error('Error creating category:', error);
    throw error;
  }
};

export const updateSystemCategory = async (id: string, updates: Partial<SystemCategory>): Promise<void> => {
  try {
    const docRef = doc(db, COLLECTION_NAME, id);
    await updateDoc(docRef, { ...updates, updatedAt: new Date().toISOString() });
  } catch (error) {
    console.error('Error updating category:', error);
    throw error;
  }
};

export const deleteSystemCategory = async (id: string): Promise<void> => {
  try {
    const docRef = doc(db, COLLECTION_NAME, id);
    await deleteDoc(docRef);
  } catch (error) {
    console.error('Error deleting category:', error);
    throw error;
  }
};

// Utility to seed initial data if collection is empty
export const seedCategories = async (): Promise<void> => {
  const existing = await getSystemCategories();
  if (existing.length > 0) {
    console.log('Categories already seeded.');
    return;
  }

  console.log('Seeding categories from local data...');
  for (const group of CATEGORIES_DATA.goods) {
    await createSystemCategory({
      name: group.name,
      type: 'goods',
      categories: group.categories
    });
  }

  for (const group of CATEGORIES_DATA.services) {
    await createSystemCategory({
      name: group.name,
      type: 'services',
      categories: group.categories
    });
  }
  console.log('Finished seeding categories.');
};



import { auth, db } from '@/lib/firebase';
import {
  collection,
  addDoc,
  getDocs,
  query,
  orderBy,
  where,
  Timestamp,
  doc,
  deleteDoc,
} from 'firebase/firestore';

export interface Review {
  id?: string;
  userId: string;
  userName: string;
  rating: number; // 1-5
  comment: string;
  createdAt: Timestamp | Date;
}

export interface ReviewStats {
  averageRating: number;
  totalReviews: number;
  distribution: number[]; // [1-star count, 2-star count, ..., 5-star count]
}

/**
 * Fetches all reviews for a product, sorted by newest first.
 */
export async function getProductReviews(productId: string | number): Promise<Review[]> {
  const reviewsRef = collection(db, 'products', String(productId), 'reviews');
  const q = query(reviewsRef, orderBy('createdAt', 'desc'));
  const snapshot = await getDocs(q);

  return snapshot.docs.map((doc) => ({
    id: doc.id,
    ...doc.data(),
  })) as Review[];
}

/**
 * Adds a review for a product. Requires authentication.
 * Enforces one review per user per product.
 */
export async function addReview(
  productId: string | number,
  rating: number,
  comment: string
): Promise<Review> {
  const user = auth.currentUser;
  if (!user) {
    throw new Error('You must be logged in to write a review.');
  }

  // Enforce one review per user per product
  const alreadyReviewed = await hasUserReviewed(productId);
  if (alreadyReviewed) {
    throw new Error('You have already reviewed this product.');
  }

  const reviewsRef = collection(db, 'products', String(productId), 'reviews');

  const reviewData: Omit<Review, 'id'> = {
    userId: user.uid,
    userName: user.displayName || user.email || 'Anonymous',
    rating,
    comment,
    createdAt: Timestamp.now(),
  };

  const docRef = await addDoc(reviewsRef, reviewData);

  return {
    id: docRef.id,
    ...reviewData,
  };
}

/**
 * Calculates average rating and star distribution for a product.
 */
export async function getReviewStats(productId: string | number): Promise<ReviewStats> {
  const reviews = await getProductReviews(productId);

  if (reviews.length === 0) {
    return {
      averageRating: 0,
      totalReviews: 0,
      distribution: [0, 0, 0, 0, 0],
    };
  }

  const distribution = [0, 0, 0, 0, 0]; // index 0 = 1-star, index 4 = 5-star
  let totalRating = 0;

  for (const review of reviews) {
    const starIndex = Math.max(0, Math.min(4, review.rating - 1));
    distribution[starIndex]++;
    totalRating += review.rating;
  }

  return {
    averageRating: totalRating / reviews.length,
    totalReviews: reviews.length,
    distribution,
  };
}

/**
 * Deletes a review. Only the review author can delete their own review.
 */
export async function deleteReview(
  productId: string | number,
  reviewId: string
): Promise<void> {
  const user = auth.currentUser;
  if (!user) {
    throw new Error('You must be logged in to delete a review.');
  }

  const reviewRef = doc(db, 'products', String(productId), 'reviews', reviewId);
  await deleteDoc(reviewRef);
}

/**
 * Checks if the current user has already reviewed a product.
 */
export async function hasUserReviewed(productId: string | number): Promise<boolean> {
  const user = auth.currentUser;
  if (!user) return false;

  const reviewsRef = collection(db, 'products', String(productId), 'reviews');
  const q = query(reviewsRef, where('userId', '==', user.uid));
  const snapshot = await getDocs(q);

  return !snapshot.empty;
}



import { auth, db } from '@/lib/firebase';
import { collection, doc, setDoc, deleteDoc, getDocs, getDoc, Timestamp } from 'firebase/firestore';
import { getProduct } from './products';
import { Product } from '@/lib/data/products-data';

const WISHLIST_STORAGE_KEY = 'shop_wishlist_local';

// ── LOCAL STORAGE HELPERS ──────────────────────────────────────────

const getLocalWishlist = (): string[] => {
  if (typeof window === 'undefined') return [];
  const data = localStorage.getItem(WISHLIST_STORAGE_KEY);
  return data ? JSON.parse(data) : [];
};

const saveLocalWishlist = (ids: string[]) => {
  if (typeof window !== 'undefined') {
    localStorage.setItem(WISHLIST_STORAGE_KEY, JSON.stringify(ids));
    dispatchWishlistUpdate();
  }
};

const dispatchWishlistUpdate = () => {
  if (typeof window !== 'undefined') {
    window.dispatchEvent(new Event('wishlistUpdated'));
  }
};

// ── PUBLIC API ─────────────────────────────────────────────────────

/**
 * Get all wishlisted products, resolved with full Product data.
 */
export const getWishlist = async (): Promise<Product[]> => {
  const user = auth.currentUser;

  if (!user) {
    const ids = getLocalWishlist();
    const products: Product[] = [];
    for (const id of ids) {
      try {
        const product = await getProduct(id);
        if (product) products.push(product);
      } catch {
        // Product may have been deleted — skip silently
      }
    }
    return products;
  }

  try {
    const wishlistRef = collection(db, 'users', user.uid, 'wishlist');
    const snapshot = await getDocs(wishlistRef);
    const products: Product[] = [];

    for (const docSnap of snapshot.docs) {
      try {
        const data = docSnap.data();
        const product = await getProduct(data.productId);
        if (product) products.push(product);
      } catch {
        // Product may have been deleted — skip silently
      }
    }
    return products;
  } catch (error) {
    console.error('Error fetching wishlist from Firestore:', error);
    return [];
  }
};

/**
 * Add a product to the wishlist.
 */
export const addToWishlist = async (productId: number | string): Promise<void> => {
  const id = productId.toString();
  const user = auth.currentUser;

  if (!user) {
    const ids = getLocalWishlist();
    if (!ids.includes(id)) {
      ids.push(id);
      saveLocalWishlist(ids);
    }
    return;
  }

  try {
    const wishlistDocRef = doc(db, 'users', user.uid, 'wishlist', id);
    await setDoc(wishlistDocRef, {
      productId: id,
      addedAt: Timestamp.now(),
    });
    dispatchWishlistUpdate();
  } catch (error) {
    console.error('Error adding to wishlist:', error);
    throw error;
  }
};

/**
 * Remove a product from the wishlist.
 */
export const removeFromWishlist = async (productId: number | string): Promise<void> => {
  const id = productId.toString();
  const user = auth.currentUser;

  if (!user) {
    let ids = getLocalWishlist();
    ids = ids.filter(i => i !== id);
    saveLocalWishlist(ids);
    return;
  }

  try {
    await deleteDoc(doc(db, 'users', user.uid, 'wishlist', id));
    dispatchWishlistUpdate();
  } catch (error) {
    console.error('Error removing from wishlist:', error);
    throw error;
  }
};

/**
 * Check whether a product is currently in the wishlist.
 */
export const isInWishlist = async (productId: number | string): Promise<boolean> => {
  const id = productId.toString();
  const user = auth.currentUser;

  if (!user) {
    return getLocalWishlist().includes(id);
  }

  try {
    const wishlistDocRef = doc(db, 'users', user.uid, 'wishlist', id);
    const docSnap = await getDoc(wishlistDocRef);
    return docSnap.exists();
  } catch (error) {
    console.error('Error checking wishlist:', error);
    return false;
  }
};

/**
 * Get total count of wishlisted items.
 */
export const getWishlistCount = async (): Promise<number> => {
  const user = auth.currentUser;

  if (!user) {
    return getLocalWishlist().length;
  }

  try {
    const wishlistRef = collection(db, 'users', user.uid, 'wishlist');
    const snapshot = await getDocs(wishlistRef);
    return snapshot.size;
  } catch (error) {
    console.error('Error getting wishlist count:', error);
    return 0;
  }
};

/**
 * Sync local wishlist to Firestore after login.
 */
export const syncLocalWishlistToFirestore = async (userId: string): Promise<void> => {
  const localIds = getLocalWishlist();
  if (localIds.length === 0) return;

  try {
    for (const id of localIds) {
      const wishlistDocRef = doc(db, 'users', userId, 'wishlist', id);
      const docSnap = await getDoc(wishlistDocRef);

      if (!docSnap.exists()) {
        await setDoc(wishlistDocRef, {
          productId: id,
          addedAt: Timestamp.now(),
        });
      }
    }
    // Clear local storage after successful sync
    if (typeof window !== 'undefined') {
      localStorage.removeItem(WISHLIST_STORAGE_KEY);
      dispatchWishlistUpdate();
    }
    console.log('Local wishlist synced to Firestore successfully.');
  } catch (error) {
    console.error('Error syncing local wishlist to Firestore:', error);
  }
};



