.pt-0 { padding-top: var(--space-0); }
.pt-1 { padding-top: var(--space-1); }
.pt-2 { padding-top: var(--space-2); }
.pt-3 { padding-top: var(--space-3); }
.pt-4 { padding-top: var(--space-4); }
.pt-5 { padding-top: var(--space-5); }
.pt-6 { padding-top: var(--space-6); }
.pt-8 { padding-top: var(--space-8); }

.pb-0 { padding-bottom: var(--space-0); }
.pb-1 { padding-bottom: var(--space-1); }
.pb-2 { padding-bottom: var(--space-2); }
.pb-3 { padding-bottom: var(--space-3); }
.pb-4 { padding-bottom: var(--space-4); }
.pb-5 { padding-bottom: var(--space-5); }
.pb-6 { padding-bottom: var(--space-6); }
.pb-8 { padding-bottom: var(--space-8); }

.pl-0 { padding-left: var(--space-0); }
.pl-1 { padding-left: var(--space-1); }
.pl-2 { padding-left: var(--space-2); }
.pl-3 { padding-left: var(--space-3); }
.pl-4 { padding-left: var(--space-4); }
.pl-5 { padding-left: var(--space-5); }
.pl-6 { padding-left: var(--space-6); }
.pl-8 { padding-left: var(--space-8); }

.pr-0 { padding-right: var(--space-0); }
.pr-1 { padding-right: var(--space-1); }
.pr-2 { padding-right: var(--space-2); }
.pr-3 { padding-right: var(--space-3); }
.pr-4 { padding-right: var(--space-4); }
.pr-5 { padding-right: var(--space-5); }
.pr-6 { padding-right: var(--space-6); }
.pr-8 { padding-right: var(--space-8); }

/* Full Width Utility */
.w-full { width: 100%; }
.h-full { height: 100%; }

/* ============================================================================
   5. COMPONENT FRAMEWORK
   ============================================================================ */

/* Buttons */
.btn {
  display: inline-block;
  padding: var(--space-3) var(--space-6);
  font-size: var(--font-size-base);
  font-weight: var(--font-weight-medium);
  line-height: 1.5;
  text-align: center;
  border: 2px solid transparent;
  border-radius: var(--radius-md);
  cursor: pointer;
  transition: all var(--transition-base);
  text-decoration: none;
}

.btn-primary {
  background-color: var(--color-primary-500);
  color: white;
  border-color: var(--color-primary-500);
}

.btn-primary:hover {
  background-color: var(--color-primary-600);
  border-color: var(--color-primary-600);
  transform: translateY(-2px);
  box-shadow: var(--shadow-md);
}

.btn-primary:active {
  background-color: var(--color-primary-700);
  transform: translateY(0);
}

.btn-secondary {
  background-color: var(--color-secondary-900);
  color: white;
  border-color: var(--color-secondary-900);
}

.btn-secondary:hover {
  background-color: var(--color-secondary-800);
  border-color: var(--color-secondary-800);
  transform: translateY(-2px);
  box-shadow: var(--shadow-md);
}

.btn-outline {
  background-color: transparent;
  color: var(--color-primary-500);
  border-color: var(--color-primary-500);
}

.btn-outline:hover {
  background-color: var(--color-primary-500);
  color: white;
  transform: translateY(-2px);
  box-shadow: var(--shadow-md);
}

.btn-sm {
  padding: var(--space-2) var(--space-4);
  font-size: var(--font-size-sm);
}

.btn-lg {
  padding: var(--space-4) var(--space-8);
  font-size: var(--font-size-lg);
}

.btn-block {
  display: block;
  width: 100%;
}

.btn:disabled {
  opacity: 0.5;
  cursor: not-allowed;
  pointer-events: none;
}

/* Forms */
.form-group {
  margin-bottom: var(--space-5);
}

.form-label {
  display: block;
  margin-bottom: var(--space-2);
  font-weight: var(--font-weight-medium);
  color: var(--color-text-primary);
}

.form-input,
.form-textarea,
.form-select {
  display: block;
  width: 100%;
  padding: var(--space-3) var(--space-4);
  font-size: var(--font-size-base);
  line-height: 1.5;
  color: var(--color-text-primary);
  background-color: var(--color-bg-primary);
  border: 2px solid var(--color-border-base);
  border-radius: var(--radius-md);
  transition: border-color var(--transition-base), box-shadow var(--transition-base);
}

.form-input:focus,
.form-textarea:focus,
.form-select:focus {
  outline: none;
  border-color: var(--color-primary-500);
  box-shadow: 0 0 0 3px rgba(255, 107, 0, 0.1);
}

.form-input.is-valid,
.form-textarea.is-valid,
.form-select.is-valid {
  border-color: var(--color-success-base);
}

.form-input.is-invalid,
.form-textarea.is-invalid,
.form-select.is-invalid {
  border-color: var(--color-danger-base);
}

.form-textarea {
  resize: vertical;
  min-height: 120px;
}

.form-help {
  display: block;
  margin-top: var(--space-1);
  font-size: var(--font-size-sm);
  color: var(--color-text-secondary);
}

/* Alerts */
.alert {
  padding: var(--space-4) var(--space-5);
  margin-bottom: var(--space-4);
  border: 1px solid transparent;
  border-radius: var(--radius-md);
  font-size: var(--font-size-base);
}

.alert-success {
  background-color: rgba(76, 175, 80, 0.1);
  border-color: var(--color-success-light);
  color: var(--color-success-dark);
}

.alert-danger {
  background-color: rgba(244, 67, 54, 0.1);
  border-color: var(--color-danger-light);
  color: var(--color-danger-dark);
}

.alert-warning {
  background-color: rgba(255, 193, 7, 0.1);
  border-color: var(--color-warning-light);
  color: var(--color-warning-dark);
}

.alert-info {
  background-color: rgba(33, 150, 243, 0.1);
  border-color: var(--color-info-light);
  color: var(--color-info-dark);
}

/* Cards */
.card {
  background-color: var(--color-bg-primary);
  border: 1px solid var(--color-border-light);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-sm);
  overflow: hidden;
  transition: box-shadow var(--transition-base), transform var(--transition-base);
}

.card:hover {
  box-shadow: var(--shadow-lg);
  transform: translateY(-4px);
}

.card-header {
  padding: var(--space-5);
  border-bottom: 1px solid var(--color-border-light);
  background-color: var(--color-bg-secondary);
}

.card-body {
  padding: var(--space-5);
}

.card-footer {
  padding: var(--space-5);
  border-top: 1px solid var(--color-border-light);
  background-color: var(--color-bg-secondary);
}

/* Navigation */
.nav {
  display: flex;
  flex-wrap: wrap;
  padding-left: 0;
  margin-bottom: 0;
  list-style: none;
}

.nav-link {
  display: block;
  padding: var(--space-2) var(--space-4);
  color: var(--color-text-primary);
  text-decoration: none;
  transition: color var(--transition-base);
}

.nav-link:hover {
  color: var(--color-primary-500);
}

.nav-link.active {
  color: var(--color-primary-500);
  font-weight: var(--font-weight-semibold);
}

/* ============================================================================
   E-COMMERCE COMPONENTS
   ============================================================================ */

/* Product Grid - Mobile First */
.product-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: var(--space-3);
  width: 100%;
}

@media (min-width: 768px) {
  .product-grid {
    grid-template-columns: repeat(3, 1fr);
    gap: var(--space-4);
  }
}

@media (min-width: 1024px) {
  .product-grid {
    grid-template-columns: repeat(4, 1fr);
  }
}

@media (min-width: 1200px) {
  .product-grid {
    grid-template-columns: repeat(5, 1fr);
  }
}

@media (min-width: 1400px) {
  .product-grid {
    grid-template-columns: repeat(6, 1fr);
  }
}

/* Product Card */
.product-card {
  background: var(--color-bg-primary);
  border: 1px solid var(--color-border-light);
  border-radius: var(--radius-lg);
  overflow: hidden;
  transition: transform var(--transition-fast), box-shadow var(--transition-fast);
  display: flex;
  flex-direction: column;
  position: relative;
}

.product-card:hover {
  transform: translateY(-4px);
  box-shadow: var(--shadow-lg);
}

.product-link {
  text-decoration: none;
  color: inherit;
  display: flex;
  flex-direction: column;
  height: 100%;
}

.product-image {
  position: relative;
  width: 100%;
  padding-top: 100%; /* 1:1 Aspect Ratio */
  overflow: hidden;
  background: var(--color-bg-secondary);
}

.product-image img {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform var(--transition-base);
}

.product-card:hover .product-image img {
  transform: scale(1.05);
}

.product-info {
  padding: var(--space-3);
  display: flex;
  flex-direction: column;
  gap: var(--space-2);
  flex: 1;
}

.product-name {
  font-size: var(--font-size-sm);
  font-weight: var(--font-weight-medium);
  line-height: var(--line-height-tight);
  margin: 0;
  color: var(--color-text-primary);
  display: -webkit-box;
  -webkit-line-clamp: 2;
  line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}

.product-pricing {
  display: flex;
  align-items: center;
  gap: var(--space-2);
  flex-wrap: wrap;
}

.price {
  font-size: var(--font-size-xl);
  font-weight: var(--font-weight-bold);
  color: var(--color-primary-500);
  line-height: 1;
}

.price-original {
  font-size: var(--font-size-sm);
  color: var(--color-text-tertiary);
  text-decoration: line-through;
  line-height: 1;
}

.product-meta {
  display: flex;
  align-items: center;
  gap: var(--space-2);
  font-size: var(--font-size-xs);
  color: var(--color-text-secondary);
}

.rating {
  display: flex;
  align-items: center;
  gap: var(--space-1);
  color: var(--color-warning-base);
}

/* Badges */
.badge {
  display: inline-block;
  padding: var(--space-1) var(--space-2);
  font-size: var(--font-size-xs);
  font-weight: var(--font-weight-semibold);
  border-radius: var(--radius-sm);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  line-height: 1;
  transition: transform var(--transition-fast);
}

.badge-express {
  background: linear-gradient(135deg, var(--color-primary-500), var(--color-primary-600));
  color: white;
  box-shadow: var(--shadow-sm);
}

.badge-deal {
  background: linear-gradient(135deg, var(--color-danger-base), var(--color-danger-dark));
  color: white;
  box-shadow: var(--shadow-sm);
}

.badge-new {
  background: linear-gradient(135deg, var(--color-success-base), var(--color-success-dark));
  color: white;
  box-shadow: var(--shadow-sm);
}

.badge-sale {
  background: linear-gradient(135deg, var(--color-warning-base), var(--color-warning-dark));
  color: white;
  box-shadow: var(--shadow-sm);
}

/* Badge positioning in product cards */
.product-image .badge {
  position: absolute;
  top: var(--space-2);
  left: var(--space-2);
  z-index: 1;
}

.product-image .badge:nth-of-type(2) {
  top: calc(var(--space-2) + 28px);
}

/* Search Components */
.search-container {
  position: relative;
  width: 100%;
  max-width: 600px;
}

.search-form {
  position: relative;
  display: flex;
  align-items: center;
}

.search-form input {
  width: 100%;
  padding: var(--space-3) var(--space-12) var(--space-3) var(--space-4);
  font-size: var(--font-size-base);
  border: 2px solid var(--color-border-base);
  border-radius: var(--radius-lg);
  background: var(--color-bg-primary);
  transition: border-color var(--transition-base), box-shadow var(--transition-base);
}

.search-form input:focus {
  outline: none;
  border-color: var(--color-primary-500);
  box-shadow: 0 0 0 4px rgba(255, 107, 0, 0.1);
}

.search-form button {
  position: absolute;
  right: var(--space-2);
  padding: var(--space-2);
  background: var(--color-primary-500);
  color: white;
  border: none;
  border-radius: var(--radius-md);
  cursor: pointer;
  transition: background var(--transition-base), transform var(--transition-fast);
  display: flex;
  align-items: center;
  justify-content: center;
  width: 40px;
  height: 40px;
}

.search-form button:hover {
  background: var(--color-primary-600);
  transform: scale(1.05);
}

.search-form button:active {
  transform: scale(0.95);
}

.autocomplete-container {
  position: absolute;
  top: calc(100% + var(--space-2));
  left: 0;
  right: 0;
  background: var(--color-bg-primary);
  border: 1px solid var(--color-border-light);
  border-radius: var(--radius-lg);
  box-shadow: var(--shadow-lg);
  max-height: 400px;
  overflow-y: auto;
  z-index: var(--z-dropdown);
}

.autocomplete-item {
  padding: var(--space-3) var(--space-4);
  cursor: pointer;
  transition: background var(--transition-fast);
  display: flex;
  align-items: center;
  gap: var(--space-3);
  border-bottom: 1px solid var(--color-border-light);
}

.autocomplete-item:last-child {
  border-bottom: none;
}

.autocomplete-item:hover {
  background: var(--color-bg-secondary);
}

.autocomplete-item img {
  width: 40px;
  height: 40px;
  object-fit: cover;
  border-radius: var(--radius-sm);
}

/* Skeleton Loaders */
.skeleton {
  background: linear-gradient(
    90deg,
    var(--color-bg-secondary) 0%,
    var(--color-bg-tertiary) 50%,
    var(--color-bg-secondary) 100%
  );
  background-size: 200% 100%;
  animation: skeleton-loading 1.5s ease-in-out infinite;
  border-radius: var(--radius-sm);
}

@keyframes skeleton-loading {
  0% {
    background-position: 200% 0;
  }
  100% {
    background-position: -200% 0;
  }
}

.skeleton-text {
  height: 1em;
  margin-bottom: var(--space-2);
}

.skeleton-title {
  height: 1.5em;
  width: 80%;
  margin-bottom: var(--space-3);
}

.skeleton-image {
  width: 100%;
  padding-top: 100%;
  position: relative;
}

/* Countdown Timer */
.countdown-timer {
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  padding: var(--space-2) var(--space-4);
  background: linear-gradient(135deg, var(--color-danger-base), var(--color-danger-dark));
  color: white;
  border-radius: var(--radius-md);
  font-weight: var(--font-weight-semibold);
  font-size: var(--font-size-sm);
  box-shadow: var(--shadow-md);
  animation: pulse 2s ease-in-out infinite;
}

@keyframes pulse {
  0%, 100% {
    transform: scale(1);
  }
  50% {
    transform: scale(1.02);
  }
}

.countdown-unit {
  display: flex;
  flex-direction: column;
  align-items: center;
  min-width: 32px;
}

.countdown-value {
  font-size: var(--font-size-lg);
  font-weight: var(--font-weight-bold);
  line-height: 1;
}

.countdown-label {
  font-size: var(--font-size-xs);
  text-transform: uppercase;
  opacity: 0.9;
  line-height: 1;
  margin-top: 2px;
}

/* Flash Sale Banner */
.flash-sale-banner {
  background: linear-gradient(135deg, var(--color-danger-base), var(--color-primary-500));
  color: white;
  padding: var(--space-4) var(--space-6);
  border-radius: var(--radius-lg);
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-4);
  box-shadow: var(--shadow-lg);
  margin-bottom: var(--space-6);
  overflow: hidden;
  position: relative;
}

.flash-sale-banner::before {
  content: '';
  position: absolute;
  top: -50%;
  right: -10%;
  width: 200px;
  height: 200%;
  background: rgba(255, 255, 255, 0.1);
  transform: rotate(15deg);
  animation: shimmer 3s infinite;
}

@keyframes shimmer {
  0% {
    transform: translateX(-100%) rotate(15deg);
  }
  100% {
    transform: translateX(300%) rotate(15deg);
  }
}

.flash-sale-content {
  flex: 1;
  z-index: 1;
}

.flash-sale-title {
  font-size: var(--font-size-2xl);
  font-weight: var(--font-weight-extrabold);
  margin: 0 0 var(--space-2) 0;
  text-shadow: 0 2px 4px rgba(0, 0, 0, 0.2);
}

.flash-sale-subtitle {
  font-size: var(--font-size-base);
  opacity: 0.95;
  margin: 0;
}

/* Filter Sidebar */
.filters {
  background: var(--color-bg-primary);
  border: 1px solid var(--color-border-light);
  border-radius: var(--radius-lg);
  padding: var(--space-5);
  position: sticky;
  top: var(--space-4);
}

.filter-group {
  margin-bottom: var(--space-5);
}

.filter-group label {
  display: block;
  font-weight: var(--font-weight-medium);
  margin-bottom: var(--space-2);
  color: var(--color-text-primary);
}

.filter-group input,
.filter-group select {
  width: 100%;
  padding: var(--space-2) var(--space-3);
  border: 1px solid var(--color-border-base);
  border-radius: var(--radius-md);
  font-size: var(--font-size-sm);
  transition: border-color var(--transition-base);
}

.filter-group input:focus,
.filter-group select:focus {
  outline: none;
  border-color: var(--color-primary-500);
}

/* Category Grid */
.category-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: var(--space-3);
}

@media (min-width: 768px) {
  .category-grid {
    grid-template-columns: repeat(4, 1fr);
  }
}

@media (min-width: 1024px) {
  .category-grid {
    grid-template-columns: repeat(6, 1fr);
  }
}

.category-card {
  background: var(--color-bg-primary);
  border: 1px solid var(--color-border-light);
  border-radius: var(--radius-lg);
  padding: var(--space-4);
  text-align: center;
  cursor: pointer;
  transition: all var(--transition-base);
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: var(--space-2);
}

.category-card:hover {
  border-color: var(--color-primary-500);
  background: linear-gradient(135deg, rgba(255, 107, 0, 0.05), rgba(255, 107, 0, 0.1));
  transform: translateY(-2px);
  box-shadow: var(--shadow-md);
}

.category-icon {
  font-size: var(--font-size-3xl);
  margin-bottom: var(--space-2);
}

.category-name {
  font-size: var(--font-size-sm);
  font-weight: var(--font-weight-medium);
  margin: 0;
  color: var(--color-text-primary);
}

/* ============================================================================
   6. RESPONSIVE DESIGN SYSTEM
   ============================================================================ */

/* Container Responsive Widths */
@media (min-width: 576px) {
  .container {
    max-width: var(--container-sm);
    padding-left: var(--space-5);
    padding-right: var(--space-5);
  }
}

@media (min-width: 768px) {
  .container {
    max-width: var(--container-md);
    padding-left: var(--space-6);
    padding-right: var(--space-6);
  }
}

@media (min-width: 1024px) {
  .container {
    max-width: var(--container-lg);
    padding-left: var(--space-8);
    padding-right: var(--space-8);
  }
}

@media (min-width: 1200px) {
  .container {
    max-width: var(--container-xl);
  }
}

@media (min-width: 1400px) {
  .container {
    max-width: var(--container-2xl);
  }
}

/* Responsive Typography */
@media (min-width: 768px) {
  h1 { font-size: var(--font-size-5xl); }
  h2 { font-size: var(--font-size-4xl); }
  h3 { font-size: var(--font-size-3xl); }
}

@media (min-width: 1024px) {
  h1 { font-size: var(--font-size-6xl); }
}

/* Responsive Display Utilities */
@media (min-width: 576px) {
  .d-sm-none { display: none; }
  .d-sm-block { display: block; }
  .d-sm-flex { display: flex; }
  .d-sm-grid { display: grid; }
}

@media (min-width: 768px) {
  .d-md-none { display: none; }
  .d-md-block { display: block; }
  .d-md-flex { display: flex; }
  .d-md-grid { display: grid; }
}

@media (min-width: 1024px) {
  .d-lg-none { display: none; }
  .d-lg-block { display: block; }
  .d-lg-flex { display: flex; }
  .d-lg-grid { display: grid; }
}

@media (min-width: 1200px) {
  .d-xl-none { display: none; }
  .d-xl-block { display: block; }
  .d-xl-flex { display: flex; }
  .d-xl-grid { display: grid; }
}

/* Responsive Grid */
@media (min-width: 576px) {
  .grid-cols-sm-2 { grid-template-columns: repeat(2, 1fr); }
  .grid-cols-sm-3 { grid-template-columns: repeat(3, 1fr); }
}

@media (min-width: 768px) {
  .grid-cols-md-2 { grid-template-columns: repeat(2, 1fr); }
  .grid-cols-md-3 { grid-template-columns: repeat(3, 1fr); }
  .grid-cols-md-4 { grid-template-columns: repeat(4, 1fr); }
}

@media (min-width: 1024px) {
  .grid-cols-lg-3 { grid-template-columns: repeat(3, 1fr); }
  .grid-cols-lg-4 { grid-template-columns: repeat(4, 1fr); }
  .grid-cols-lg-6 { grid-template-columns: repeat(6, 1fr); }
}

/* ============================================================================
   7. VISIBILITY & ACCESSIBILITY
   ============================================================================ */

/* Screen Reader Only */
.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border-width: 0;
}

/* Responsive Hiding */
@media (max-width: 575px) {
  .mobile-hidden { display: none !important; }
}

@media (min-width: 576px) and (max-width: 1023px) {
  .tablet-hidden { display: none !important; }
}

@media (min-width: 1024px) {
  .desktop-hidden { display: none !important; }
}

/* Print Styles */
@media print {
  .no-print { display: none !important; }

  a[href]:after {
    content: " (" attr(href) ")";
  }

  .card {
    box-shadow: none;
    border: 1px solid #000;
  }

  .btn {
    border: 1px solid #000;
  }
}

/* ============================================================================
   8. STATE & INTERACTION
   ============================================================================ */

/* Disabled State */
.disabled,
[disabled] {
  opacity: 0.5;
  cursor: not-allowed;
  pointer-events: none;
}

/* Pointer Utilities */
.cursor-pointer { cursor: pointer; }
.cursor-default { cursor: default; }
.cursor-not-allowed { cursor: not-allowed; }

/* User Select */
.select-none { user-select: none; }
.select-text { user-select: text; }
.select-all { user-select: all; }

/* Overflow */
.overflow-auto { overflow: auto; }
.overflow-hidden { overflow: hidden; }
.overflow-visible { overflow: visible; }
.overflow-scroll { overflow: scroll; }

/* Position */
.position-static { position: static; }
.position-relative { position: relative; }
.position-absolute { position: absolute; }
.position-fixed { position: fixed; }
.position-sticky { position: sticky; }

/* Shadow Utilities */
.shadow-none { box-shadow: none; }
.shadow-xs { box-shadow: var(--shadow-xs); }
.shadow-sm { box-shadow: var(--shadow-sm); }
.shadow { box-shadow: var(--shadow-base); }
.shadow-md { box-shadow: var(--shadow-md); }
.shadow-lg { box-shadow: var(--shadow-lg); }
.shadow-xl { box-shadow: var(--shadow-xl); }

/* Border Radius Utilities */
.rounded-none { border-radius: var(--radius-none); }
.rounded-sm { border-radius: var(--radius-sm); }
.rounded { border-radius: var(--radius-base); }
.rounded-md { border-radius: var(--radius-md); }
.rounded-lg { border-radius: var(--radius-lg); }
.rounded-xl { border-radius: var(--radius-xl); }
.rounded-2xl { border-radius: var(--radius-2xl); }
.rounded-full { border-radius: var(--radius-full); }

/* Transition Utilities */
.transition-none { transition: none; }
.transition-fast { transition: all var(--transition-fast); }
.transition { transition: all var(--transition-base); }
.transition-slow { transition: all var(--transition-slow); }

/* Hover Effects */
.hover-lift {
  transition: transform var(--transition-base), box-shadow var(--transition-base);
}

.hover-lift:hover {
  transform: translateY(-4px);
  box-shadow: var(--shadow-lg);
}

/* Background Colors */
.bg-primary { background-color: var(--color-primary-500); }
.bg-secondary { background-color: var(--color-secondary-900); }
.bg-white { background-color: var(--color-bg-primary); }
.bg-gray { background-color: var(--color-bg-secondary); }

/* Border Utilities */
.border { border: 1px solid var(--color-border-base); }
.border-0 { border: 0; }
.border-t { border-top: 1px solid var(--color-border-base); }
.border-b { border-bottom: 1px solid var(--color-border-base); }
.border-l { border-left: 1px solid var(--color-border-base); }
.border-r { border-right: 1px solid var(--color-border-base); }

/* Opacity */
.opacity-0 { opacity: 0; }
.opacity-25 { opacity: 0.25; }
.opacity-50 { opacity: 0.5; }
.opacity-75 { opacity: 0.75; }
.opacity-100 { opacity: 1; }

/* ============================================================================
   END OF GLOBAL DESIGN SYSTEM
   ============================================================================ */











/* Home Page Specific Styles */
.hero-section {
    background: radial-gradient(circle at 80% 20%, rgba(255, 107, 0, 0.15) 0%, #000000 70%);
    border-bottom: 1px solid var(--color-border-light);
    color: white;
    padding: calc(var(--spacing-unit) * 24) var(--spacing-8);
    text-align: center;
    border-radius: 0 0 var(--border-radius-xl) var(--border-radius-xl);
    margin-bottom: var(--spacing-12);
    position: relative;
    overflow: hidden;
}

.hero-section::before {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: url('data:image/svg+xml,<svg width="100" height="100" xmlns="http://www.w3.org/2000/svg"><circle cx="50" cy="50" r="40" fill="rgba(255,255,255,0.03)"/></svg>');
    opacity: 0.3;
}

.hero-content {
    position: relative;
    z-index: 1;
    max-width: 800px;
    margin: 0 auto;
}

.hero-section h1 {
    font-size: 3.5rem;
    font-weight: 700;
    margin-bottom: var(--spacing-6);
    text-shadow: 0 2px 10px rgba(0,0,0,0.5);
}

.hero-section p {
    font-size: var(--font-size-xl);
    margin-bottom: var(--spacing-8);
    opacity: 0.95;
}

.hero-buttons {
    display: flex;
    gap: var(--spacing-4);
    justify-content: center;
    flex-wrap: wrap;
}

.btn-hero {
    padding: var(--spacing-4) calc(var(--spacing-unit) * 10);
    font-size: var(--font-size-lg);
    border-radius: 50px;
    text-decoration: none;
    transition: all var(--transition);
    font-weight: 600;
}

.btn-hero-primary {
    background: var(--color-primary-500);
    color: black;
    box-shadow: var(--shadow-md);
}

.btn-hero-primary:hover {
    background: var(--color-primary-600);
    color: black;
    transform: translateY(-2px);
    box-shadow: var(--shadow-lg);
}

.btn-hero-secondary {
    background: rgba(255,255,255,0.05);
    color: white;
    border: 2px solid var(--color-border-base);
    backdrop-filter: blur(10px);
}

.btn-hero-secondary:hover {
    background: rgba(255,255,255,0.1);
    border-color: var(--color-primary-500);
    color: var(--color-primary-500);
    transform: translateY(-2px);
}

.features-section {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
    gap: var(--spacing-8);
    margin: var(--spacing-16) 0;
}

.feature-card {
    background: var(--color-bg-secondary);
    padding: var(--spacing-8);
    border-radius: var(--border-radius-lg);
    border: 1px solid var(--color-border-light);
    text-align: center;
    box-shadow: var(--shadow-sm);
    transition: transform var(--transition), box-shadow var(--transition);
}

.feature-card:hover {
    transform: translateY(-5px);
    box-shadow: var(--shadow-md);
}

.feature-icon {
    font-size: 3rem;
    margin-bottom: var(--spacing-4);
}

.section-title {
    text-align: center;
    font-size: var(--font-size-4xl);
    margin-bottom: var(--spacing-12);
    color: var(--color-text-primary);
}

.section-title::after {
    content: '';
    display: block;
    width: 80px;
    height: 4px;
    background: var(--color-primary-500);
    margin: var(--spacing-4) auto;
    border-radius: var(--border-radius-sm);
}

@media (max-width: 768px) {
    .hero-section h1 {
        font-size: 2rem;
    }

    .features-section {
        grid-template-columns: 1fr;
    }
}







/* Product Details Page Styles */

/* Main Layout */
.product-details-container {
    padding-top: var(--space-8);
    padding-bottom: var(--space-12);
}

.product-details-grid {
    display: grid;
    grid-template-columns: 1fr;
    gap: var(--space-8);
}

@media (min-width: 768px) {
    .product-details-grid {
        grid-template-columns: 1fr 1fr;
        gap: var(--space-12);
        align-items: start;
    }
}

/* Image Section */
.product-image-container {
    position: relative;
    border-radius: var(--radius-xl);
    overflow: hidden;
    background-color: var(--color-bg-secondary);
    box-shadow: var(--shadow-md);
    aspect-ratio: 1;
}

.product-detail-image {
    width: 100%;
    height: 100%;
    object-fit: contain; /* Changed to contain to ensure full product visibility */
    transition: transform var(--transition-base);
}

.product-image-container:hover .product-detail-image {
    transform: scale(1.05);
}

/* Info Section */
.product-info-container {
    display: flex;
    flex-direction: column;
    gap: var(--space-6);
}

.product-meta-header {
    border-bottom: 1px solid var(--color-border-light);
    padding-bottom: var(--space-4);
}

.product-category {
    font-size: var(--font-size-sm);
    color: var(--color-text-tertiary); /* Use tertiary for subtlety */
    text-transform: uppercase;
    letter-spacing: 0.05em;
    font-weight: var(--font-weight-semibold);
    margin-bottom: var(--space-2);
}

.product-title {
    font-size: var(--font-size-3xl);
    color: var(--color-text-primary);
    margin-bottom: var(--space-2);
}

.product-price-wrapper {
    display: flex;
    align-items: center;
    gap: var(--space-4);
    margin-top: var(--space-2);
}

.product-price {
    font-size: var(--font-size-2xl);
    font-weight: var(--font-weight-bold);
    color: var(--color-primary-500);
}

.product-price-original {
    font-size: var(--font-size-lg);
    color: var(--color-text-tertiary);
    text-decoration: line-through;
}

/* Tags */
.product-tags {
    display: flex;
    gap: var(--space-2);
    margin-top: var(--space-2);
}

.detail-badge {
    display: inline-block;
    padding: var(--space-1) var(--space-3);
    border-radius: var(--radius-full);
    font-size: var(--font-size-xs);
    font-weight: var(--font-weight-semibold);
    text-transform: uppercase;
}

.badge-new {
    background-color: var(--color-info-light);
    color: var(--color-info-dark);
}

.badge-sale {
    background-color: var(--color-danger-light);
    color: var(--color-danger-dark);
}

.badge-express {
    background-color: var(--color-success-light);
    color: var(--color-success-dark);
}

/* Description */
.product-description h3 {
    font-size: var(--font-size-lg);
    margin-bottom: var(--space-2);
}

.product-description p {
    color: var(--color-text-secondary);
    line-height: var(--line-height-relaxed);
}

/* Customization Options */
.product-options {
    display: flex;
    flex-direction: column;
    gap: var(--space-6);
    padding: var(--space-6) 0;
    border-top: 1px solid var(--color-border-light);
    border-bottom: 1px solid var(--color-border-light);
}

.option-group {
    display: flex;
    flex-direction: column;
    gap: var(--space-3);
}

.option-label {
    font-weight: var(--font-weight-semibold);
    color: var(--color-text-primary);
    font-size: var(--font-size-sm);
}

.option-values {
    display: flex;
    flex-wrap: wrap;
    gap: var(--space-3);
}

/* Color Options */
.color-option {
    width: 2rem;
    height: 2rem;
    border-radius: var(--radius-full);
    border: 2px solid var(--color-border-base);
    cursor: pointer;
    transition: all var(--transition-fast);
    position: relative;
    padding: 0;
    /* Map common colors directly in CSS or style inline in JS */
}

.color-option:hover {
    transform: scale(1.1);
    box-shadow: var(--shadow-sm);
}

.color-option.selected {
    border-color: var(--color-primary-500);
    box-shadow: 0 0 0 2px var(--color-bg-primary), 0 0 0 4px var(--color-primary-500);
}

/* Text Options (Size, etc.) */
.text-option {
    padding: var(--space-2) var(--space-4);
    border: 1px solid var(--color-border-base);
    border-radius: var(--radius-md);
    background-color: var(--color-bg-primary);
    color: var(--color-text-secondary);
    cursor: pointer;
    transition: all var(--transition-fast);
    min-width: 3rem;
    text-align: center;
}

.text-option:hover {
    border-color: var(--color-primary-300);
    color: var(--color-primary-500);
}

.text-option.selected {
    background-color: var(--color-primary-50);
    border-color: var(--color-primary-500);
    color: var(--color-primary-500);
    font-weight: var(--font-weight-medium);
}

/* Actions */
.product-actions {
    display: flex;
    flex-direction: column;
    gap: var(--space-4);
    margin-top: var(--space-4);
}

.quantity-selector {
    display: flex;
    align-items: center;
    gap: var(--space-4);
}

.qty-btn {
    width: 2.5rem;
    height: 2.5rem;
    display: flex;
    align-items: center;
    justify-content: center;
    border: 1px solid var(--color-border-base);
    border-radius: var(--radius-md);
    background-color: var(--color-bg-primary);
    font-size: var(--font-size-lg);
    cursor: pointer;
    transition: all var(--transition-fast);
}

.qty-btn:hover {
    border-color: var(--color-primary-500);
    color: var(--color-primary-500);
}

.qty-input {
    width: 4rem;
    height: 2.5rem;
    text-align: center;
    border-radius: var(--radius-md);
    border: 1px solid var(--color-border-base);
}

/* Additional Info */
.additional-info {
    margin-top: var(--space-12);
}

.info-tabs {
    display: flex;
    gap: var(--space-8);
    border-bottom: 1px solid var(--color-border-light);
    margin-bottom: var(--space-6);
}

.tab-btn {
    padding-bottom: var(--space-4);
    font-weight: var(--font-weight-medium);
    color: var(--color-text-secondary);
    border-bottom: 2px solid transparent;
    cursor: pointer;
    transition: all var(--transition-fast);
}

.tab-btn.active {
    color: var(--color-primary-500);
    border-bottom-color: var(--color-primary-500);
}

.tab-content {
    color: var(--color-text-secondary);
    line-height: var(--line-height-relaxed);
}

/* Loading State */
.loading-skeleton {
    animation: skeleton-loading 1.5s infinite linear;
    background: linear-gradient(90deg, var(--color-bg-secondary) 25%, var(--color-bg-tertiary) 50%, var(--color-bg-secondary) 75%);
    background-size: 200% 100%;
    border-radius: var(--radius-md);
    opacity: 0.7;
}

@keyframes skeleton-loading {
    0% { background-position: 200% 0; }
    100% { background-position: -200% 0; }
}



