'use client';

import { useState } from 'react';
import { Upload, FileUp, CheckCircle2, XCircle } from 'lucide-react';

interface S3UploaderProps {
  onUploadSuccess?: (url: string) => void;
  label?: string;
  className?: string;
}

export default function S3Uploader({ onUploadSuccess, label = 'Upload to S3', className = '' }: S3UploaderProps) {
  const [file, setFile] = useState<File | null>(null);
  const [uploading, setUploading] = useState(false);
  const [uploadedUrl, setUploadedUrl] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      setFile(e.target.files[0]);
      setError(null);
      setUploadedUrl(null);
    }
  };

  const handleUpload = async () => {
    if (!file) return;

    setUploading(true);
    setError(null);

    try {
      // 1. Get the pre-signed URL from our API route
      const response = await fetch('/api/upload', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          fileName: file.name,
          fileType: file.type,
        }),
      });

      if (!response.ok) {
        throw new Error('Failed to get pre-signed URL. Check your S3 configuration.');
      }

      const { signedUrl, fileUrl } = await response.json();

      // 2. Upload the file directly to S3 using the pre-signed URL
      const uploadResponse = await fetch(signedUrl, {
        method: 'PUT',
        headers: {
          'Content-Type': file.type,
        },
        body: file,
      });

      if (!uploadResponse.ok) {
        throw new Error('Failed to upload file to S3.');
      }

      // 3. Success! Set the uploaded URL
      setUploadedUrl(fileUrl);
      if (onUploadSuccess) {
        onUploadSuccess(fileUrl);
      }
    } catch (err: any) {
      setError(err.message || 'An error occurred during upload.');
    } finally {
      setUploading(false);
      setFile(null); // Clear the file selection on finish (optional)
    }
  };

  return (
    <div className={`p-6 border rounded-xl bg-surface-container shadow-[4px_4px_0px_0px_var(--color-on-surface)] border-2 border-on-surface w-full ${className}`}>
      <h2 className="text-xl font-bold font-headline-md uppercase tracking-tight mb-4 flex items-center gap-2 text-on-surface">
        <Upload className="w-5 h-5" />
        {label}
      </h2>

      <div className="mb-4">
        <label className="flex flex-col items-center justify-center w-full h-32 border-2 border-dashed border-gray-300 rounded-lg cursor-pointer hover:bg-gray-50 transition-colors">
          <div className="flex flex-col items-center justify-center pt-5 pb-6">
            <FileUp className="w-8 h-8 mb-3 text-gray-400" />
            <p className="mb-2 text-sm text-gray-500">
              <span className="font-semibold">Click to upload</span> or drag and drop
            </p>
            {file && (
              <p className="text-xs text-blue-600 font-medium">Selected: {file.name}</p>
            )}
          </div>
          <input
            type="file"
            className="hidden"
            onChange={handleFileChange}
            disabled={uploading}
          />
        </label>
      </div>

      {error && (
        <div className="mb-4 p-3 bg-red-50 text-red-600 rounded-lg flex items-start gap-2 text-sm">
          <XCircle className="w-5 h-5 shrink-0 mt-0.5" />
          <span>{error}</span>
        </div>
      )}

      {uploadedUrl && (
        <div className="mb-4 p-3 bg-green-50 text-green-700 rounded-lg text-sm">
          <div className="flex items-center gap-2 mb-2 font-medium">
            <CheckCircle2 className="w-5 h-5" />
            Upload Successful!
          </div>
          <a
            href={uploadedUrl}
            target="_blank"
            rel="noopener noreferrer"
            className="text-blue-600 hover:underline break-all"
          >
            {uploadedUrl}
          </a>
        </div>
      )}

      <button
        type="button"
        onClick={handleUpload}
        disabled={!file || uploading}
        className="w-full py-3 px-4 bg-primary-container hover:bg-on-surface text-on-surface hover:text-surface disabled:bg-surface-container disabled:text-on-surface/50 disabled:cursor-not-allowed font-bold uppercase tracking-widest border-2 border-on-surface shadow-[4px_4px_0px_0px_var(--color-on-surface)] hover:translate-y-[2px] hover:translate-x-[2px] hover:shadow-[2px_2px_0px_0px_var(--color-on-surface)] transition-all flex items-center justify-center gap-2 mt-2"
      >
        {uploading ? (
          <>
            <span className="w-4 h-4 border-2 border-current border-t-transparent rounded-full animate-spin" />
            Uploading...
          </>
        ) : (
          'Upload File'
        )}
      </button>
    </div>
  );
}



'use client';

import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { useEffect, useState } from 'react';
import { collection, onSnapshot } from 'firebase/firestore';
import { onAuthStateChanged } from 'firebase/auth';
import { auth, db } from '@/lib/firebase';

export default function FloatingCart() {
  const pathname = usePathname();

  // Hide on the cart page itself to avoid redundancy
  if (pathname === '/cart') return null;

  const [itemCount, setItemCount] = useState(0);

  useEffect(() => {
    // Helper to calculate local cart total
    const updateLocalCartCount = () => {
      const cartJson = localStorage.getItem('shop_cart_local');
      if (cartJson) {
        try {
          const items = JSON.parse(cartJson);
          const count = items.reduce((acc: number, item: any) => acc + (item.quantity || 1), 0);
          setItemCount(count);
        } catch {
          setItemCount(0);
        }
      } else {
        setItemCount(0);
      }
    };

    let unsubscribeSnapshot: (() => void) | null = null;

    const unsubscribeAuth = onAuthStateChanged(auth, (user) => {
      if (user) {
        // Authenticated -> use Firestore
        const cartRef = collection(db, 'users', user.uid, 'cart');
        unsubscribeSnapshot = onSnapshot(cartRef, (snapshot) => {
          let count = 0;
          snapshot.forEach((doc) => {
            count += doc.data().quantity || 1;
          });
          setItemCount(count);
        });
      } else {
        // Not authenticated -> use LocalStorage
        if (unsubscribeSnapshot) {
          unsubscribeSnapshot();
          unsubscribeSnapshot = null;
        }
        updateLocalCartCount();
      }
    });

    // Listen for custom 'cartUpdated' event dispatched by saveLocalCart
    const handleCartUpdate = () => {
      if (!auth.currentUser) {
        updateLocalCartCount();
      }
    };

    window.addEventListener('cartUpdated', handleCartUpdate);

    return () => {
      unsubscribeAuth();
      if (unsubscribeSnapshot) unsubscribeSnapshot();
      window.removeEventListener('cartUpdated', handleCartUpdate);
    };
  }, []);

  return (
    <Link
      href="/cart"
      className="fixed top-[88px] right-6 z-40 group animate-fadeIn"
      id="floating-cart"
    >
      <div className="relative bg-surface/80 backdrop-blur-xl border border-gray-100 shadow-xl rounded-2xl p-4 transition-all duration-300 hover:scale-110 hover:shadow-2xl active:scale-95 group-hover:border-[#ff6b00]/30">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-[#ff6b00] to-[#ff6b00] flex items-center justify-center text-white shadow-lg shadow-green-500/20">
            <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
              <path strokeLinecap="round" strokeLinejoin="round" d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z" />
            </svg>
          </div>

          <div className="hidden sm:block">
            <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest leading-none mb-1">Your Cart</p>
            <p className="text-sm font-bold text-gray-900 leading-none">
              {itemCount} {itemCount === 1 ? 'Item' : 'Items'}
            </p>
          </div>
        </div>

        {itemCount > 0 && (
          <span className="absolute -top-1.5 -right-1.5 bg-red-500 text-white text-[10px] font-black rounded-full w-5 h-5 flex items-center justify-center shadow-lg shadow-red-500/40 animate-pulse">
            {itemCount}
          </span>
        )}

        {/* Hover Tip */}
        <div className="absolute top-full mt-2 right-0 bg-gray-900 text-white text-[10px] font-bold py-1 px-3 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap pointer-events-none shadow-xl">
          View Cart →
        </div>
      </div>
    </Link>
  );
}



'use client';

import { useEffect, useState, useCallback } from 'react';
import Link from 'next/link';
import { User as FirebaseUser } from 'firebase/auth';
import { Timestamp } from 'firebase/firestore';
import { subscribeToAuthChanges, getUserProfile } from '@/lib/api/auth';
import {
  getProductReviews,
  addReview,
  getReviewStats,
  deleteReview,
  hasUserReviewed,
  Review,
  ReviewStats,
} from '@/lib/api/reviews';
import Icon from '@/components/Icon';

interface ProductReviewsProps {
  productId: string | number;
}

function StarRating({
  rating,
  size = 'text-lg',
}: {
  rating: number;
  size?: string;
}) {
  return (
    <div className="flex items-center gap-0.5">
      {[1, 2, 3, 4, 5].map((star) => (
        <Icon
          key={star}
          name={star <= Math.round(rating) ? 'star' : 'star_border'}
          className={`${size} text-amber-500`}
        />
      ))}
    </div>
  );
}

function StarSelector({
  value,
  onChange,
}: {
  value: number;
  onChange: (rating: number) => void;
}) {
  const [hoverValue, setHoverValue] = useState(0);

  return (
    <div className="flex items-center gap-1">
      {[1, 2, 3, 4, 5].map((star) => (
        <button
          key={star}
          type="button"
          onClick={() => onChange(star)}
          onMouseEnter={() => setHoverValue(star)}
          onMouseLeave={() => setHoverValue(0)}
          className="transition-transform hover:scale-125 active:scale-95 cursor-pointer"
        >
          <Icon
            name={star <= (hoverValue || value) ? 'star' : 'star_border'}
            className="text-2xl text-amber-500"
          />
        </button>
      ))}
      {value > 0 && (
        <span className="ml-2 font-body-md text-sm text-secondary">
          {value} / 5
        </span>
      )}
    </div>
  );
}

function formatDate(date: Timestamp | Date): string {
  const d = date instanceof Timestamp ? date.toDate() : new Date(date as any);
  return d.toLocaleDateString('en-KE', {
    year: 'numeric',
    month: 'short',
    day: 'numeric',
  });
}

export default function ProductReviews({ productId }: ProductReviewsProps) {
  const [reviews, setReviews] = useState<Review[]>([]);
  const [stats, setStats] = useState<ReviewStats | null>(null);
  const [user, setUser] = useState<FirebaseUser | null>(null);
  const [userName, setUserName] = useState('');
  const [userHasReviewed, setUserHasReviewed] = useState(false);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState('');

  // Form state
  const [rating, setRating] = useState(0);
  const [comment, setComment] = useState('');

  const fetchReviews = useCallback(async () => {
    try {
      const [fetchedReviews, fetchedStats] = await Promise.all([
        getProductReviews(productId),
        getReviewStats(productId),
      ]);
      setReviews(fetchedReviews);
      setStats(fetchedStats);
    } catch (err) {
      console.error('Error fetching reviews:', err);
    }
  }, [productId]);

  const checkUserReview = useCallback(async () => {
    const reviewed = await hasUserReviewed(productId);
    setUserHasReviewed(reviewed);
  }, [productId]);

  // Subscribe to auth changes
  useEffect(() => {
    const unsubscribe = subscribeToAuthChanges(async (firebaseUser) => {
      setUser(firebaseUser);
      if (firebaseUser) {
        // Try to get display name from profile
        try {
          const profile = await getUserProfile(firebaseUser.uid);
          if (profile) {
            setUserName(
              [profile.first_name, profile.last_name].filter(Boolean).join(' ') ||
                firebaseUser.email ||
                'Anonymous'
            );
          } else {
            setUserName(firebaseUser.displayName || firebaseUser.email || 'Anonymous');
          }
        } catch {
          setUserName(firebaseUser.displayName || firebaseUser.email || 'Anonymous');
        }
      }
    });
    return () => unsubscribe();
  }, []);

  // Load reviews and check user review status
  useEffect(() => {
    const load = async () => {
      setLoading(true);
      await fetchReviews();
      if (user) {
        await checkUserReview();
      }
      setLoading(false);
    };
    load();
  }, [fetchReviews, checkUserReview, user]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (rating === 0) {
      setError('Please select a star rating.');
      return;
    }

    if (!comment.trim()) {
      setError('Please write a comment.');
      return;
    }

    setSubmitting(true);
    try {
      await addReview(productId, rating, comment.trim());
      setRating(0);
      setComment('');
      await fetchReviews();
      await checkUserReview();
    } catch (err: any) {
      setError(err.message || 'Failed to submit review.');
    } finally {
      setSubmitting(false);
    }
  };

  const handleDelete = async (reviewId: string) => {
    if (!confirm('Are you sure you want to delete your review?')) return;

    try {
      await deleteReview(productId, reviewId);
      await fetchReviews();
      await checkUserReview();
    } catch (err: any) {
      setError(err.message || 'Failed to delete review.');
    }
  };

  if (loading) {
    return (
      <div className="border-2 border-on-surface bg-surface p-8 shadow-[4px_4px_0px_0px_var(--color-on-surface)]">
        <div className="animate-pulse space-y-4">
          <div className="h-6 bg-gray-200 rounded w-48" />
          <div className="h-4 bg-gray-200 rounded w-32" />
          <div className="space-y-3 mt-6">
            <div className="h-20 bg-gray-200 rounded" />
            <div className="h-20 bg-gray-200 rounded" />
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Section Title */}
      <h2 className="font-headline-md text-2xl text-on-surface font-bold uppercase tracking-wider">
        Customer Reviews
      </h2>

      {/* Stats Header */}
      {stats && stats.totalReviews > 0 && (
        <div className="border-2 border-on-surface bg-surface p-6 shadow-[4px_4px_0px_0px_var(--color-on-surface)]">
          <div className="flex flex-col md:flex-row gap-8">
            {/* Average Rating */}
            <div className="flex flex-col items-center justify-center md:min-w-[160px]">
              <span className="font-headline-md text-5xl font-black text-on-surface">
                {stats.averageRating.toFixed(1)}
              </span>
              <StarRating rating={stats.averageRating} size="text-xl" />
              <span className="font-body-md text-sm text-secondary mt-1">
                {stats.totalReviews} {stats.totalReviews === 1 ? 'review' : 'reviews'}
              </span>
            </div>

            {/* Distribution Bars */}
            <div className="flex-1 space-y-2">
              {[5, 4, 3, 2, 1].map((starLevel) => {
                const count = stats.distribution[starLevel - 1];
                const percentage =
                  stats.totalReviews > 0
                    ? (count / stats.totalReviews) * 100
                    : 0;
                return (
                  <div key={starLevel} className="flex items-center gap-3">
                    <span className="font-body-md text-sm font-bold text-on-surface w-12 text-right">
                      {starLevel} star
                    </span>
                    <div className="flex-1 h-4 bg-gray-100 border-2 border-on-surface overflow-hidden">
                      <div
                        className="h-full bg-amber-500 transition-all duration-500"
                        style={{ width: `${percentage}%` }}
                      />
                    </div>
                    <span className="font-body-md text-xs text-secondary w-8">
                      {count}
                    </span>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      )}

      {/* Write Review Section */}
      <div className="border-2 border-on-surface bg-surface p-6 shadow-[4px_4px_0px_0px_var(--color-on-surface)]">
        {!user ? (
          /* Login Prompt */
          <div className="text-center py-4">
            <p className="font-body-md text-secondary mb-3">
              Sign in to write a review
            </p>
            <Link
              href="/login"
              className="inline-block bg-primary-container text-on-primary-container font-bold text-sm uppercase tracking-wider px-6 py-3 border-2 border-on-surface shadow-[4px_4px_0px_0px_var(--color-on-surface)] hover:-translate-y-1 hover:shadow-[6px_6px_0px_0px_var(--color-on-surface)] active:scale-95 active:translate-y-0.5 transition-all"
            >
              Sign In
            </Link>
          </div>
        ) : userHasReviewed ? (
          <p className="font-body-md text-secondary text-center py-4">
            You have already reviewed this product.
          </p>
        ) : (
          /* Review Form */
          <form onSubmit={handleSubmit} className="space-y-4">
            <label className="font-extrabold text-xs uppercase tracking-wider text-on-surface block">
              Write a Review
            </label>

            {/* Star Selector */}
            <div>
              <label className="font-extrabold text-xs uppercase tracking-wider text-secondary block mb-2">
                Your Rating
              </label>
              <StarSelector value={rating} onChange={setRating} />
            </div>

            {/* Comment */}
            <div>
              <label className="font-extrabold text-xs uppercase tracking-wider text-secondary block mb-2">
                Your Review
              </label>
              <textarea
                value={comment}
                onChange={(e) => setComment(e.target.value)}
                placeholder="Share your experience with this product..."
                rows={4}
                className="w-full font-body-md text-sm text-on-surface bg-surface border-2 border-on-surface p-3 focus:outline-none focus:ring-2 focus:ring-amber-500 resize-none placeholder:text-secondary/50"
              />
            </div>

            {/* Error Message */}
            {error && (
              <div className="bg-error-container text-error font-body-md text-sm p-3 border-2 border-error">
                {error}
              </div>
            )}

            {/* Submit Button */}
            <button
              type="submit"
              disabled={submitting}
              className="bg-primary-container text-on-primary-container font-bold text-sm uppercase tracking-wider px-6 py-3 border-2 border-on-surface shadow-[4px_4px_0px_0px_var(--color-on-surface)] hover:-translate-y-1 hover:shadow-[6px_6px_0px_0px_var(--color-on-surface)] active:scale-95 active:translate-y-0.5 transition-all disabled:opacity-50 disabled:cursor-not-allowed disabled:hover:translate-y-0 disabled:hover:shadow-[4px_4px_0px_0px_var(--color-on-surface)]"
            >
              {submitting ? 'Submitting...' : 'Submit Review'}
            </button>
          </form>
        )}
      </div>

      {/* Reviews List */}
      <div className="space-y-4">
        {reviews.length === 0 ? (
          <div className="border-2 border-on-surface border-dashed bg-surface p-8 text-center">
            <Icon name="star_border" className="text-4xl text-secondary/40 mx-auto mb-2" />
            <p className="font-body-md text-secondary">
              No reviews yet. Be the first to review!
            </p>
          </div>
        ) : (
          reviews.map((review) => (
            <div
              key={review.id}
              className="border-2 border-on-surface bg-surface p-5 shadow-[4px_4px_0px_0px_var(--color-on-surface)]"
            >
              <div className="flex items-start justify-between gap-4">
                <div className="flex-1">
                  {/* Name & Date */}
                  <div className="flex items-center gap-3 mb-1">
                    <span className="font-headline-md text-sm font-bold text-on-surface">
                      {review.userName}
                    </span>
                    <span className="font-body-md text-xs text-secondary">
                      {formatDate(review.createdAt)}
                    </span>
                  </div>

                  {/* Stars */}
                  <StarRating rating={review.rating} size="text-base" />

                  {/* Comment */}
                  <p className="font-body-md text-sm text-on-surface mt-2 leading-relaxed">
                    {review.comment}
                  </p>
                </div>

                {/* Delete Button (own review only) */}
                {user && user.uid === review.userId && (
                  <button
                    onClick={() => handleDelete(review.id!)}
                    className="text-secondary hover:text-error transition-colors p-1 cursor-pointer"
                    title="Delete review"
                  >
                    <Icon name="delete" className="text-lg" />
                  </button>
                )}
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
}



import { S3Client, PutObjectCommand } from '@aws-sdk/client-s3';
import { getSignedUrl } from '@aws-sdk/s3-request-presigner';

// Initialize the S3 client using environment variables
const s3Client = new S3Client({
  region: process.env.APP_AWS_REGION || 'us-east-1',
  credentials: {
    accessKeyId: process.env.APP_AWS_ACCESS_KEY_ID || '',
    secretAccessKey: process.env.APP_AWS_SECRET_ACCESS_KEY || '',
  },
});

/**
 * Generates a pre-signed URL for uploading a file to S3.
 *
 * @param fileName - The unique name of the file to save in the bucket
 * @param fileType - The MIME type of the file
 * @returns An object containing the pre-signed upload URL and the final accessible URL
 */
export async function generatePresignedUploadUrl(fileName: string, fileType: string) {
  const bucketName = process.env.APP_AWS_S3_BUCKET_NAME;

  if (!bucketName) {
    throw new Error('APP_AWS_S3_BUCKET_NAME environment variable is not defined.');
  }

  const command = new PutObjectCommand({
    Bucket: bucketName,
    Key: fileName,
    ContentType: fileType,
  });

  // URL expires in 60 seconds
  const signedUrl = await getSignedUrl(s3Client, command, { expiresIn: 60 });

  return {
    signedUrl,
    // Note: If your bucket is public, this URL can be used to view the file.
    // If not, you'll need to generate download pre-signed URLs or use CloudFront.
    fileUrl: `https://${bucketName}.s3.${process.env.APP_AWS_REGION || 'us-east-1'}.amazonaws.com/${fileName}`,
  };
}



rules_version = '2';

service cloud.firestore {
  match /databases/{database}/documents {

    // Products: Anyone can read. Merchants can create and update their own. Admins can delete, Merchants can delete their own.
    match /products/{productId} {
      allow read: if true;
      allow create: if request.auth != null && (get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'merchant' && request.resource.data.merchantId == request.auth.uid);
      allow update: if request.auth != null && (get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'merchant' && resource.data.merchantId == request.auth.uid);
      allow delete: if request.auth != null && (get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'admin' || (get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'merchant' && resource.data.merchantId == request.auth.uid));

      // Reviews: Anyone can read, authenticated users can create (one per user), users can delete own reviews
      match /reviews/{reviewId} {
        allow read: if true;
        allow create: if request.auth != null && request.resource.data.userId == request.auth.uid;
        allow delete: if request.auth != null && resource.data.userId == request.auth.uid;
        allow update: if false;
      }
    }

    // Users: Users can read and update their own profile document, but cannot change role. They can only change merchantStatus to pending.
    match /users/{userId} {
      allow read: if request.auth != null && request.auth.uid == userId;
      allow update: if request.auth != null && request.auth.uid == userId && 
        (!request.resource.data.diff(resource.data).affectedKeys().hasAny(['role'])) && 
        (!request.resource.data.diff(resource.data).affectedKeys().hasAny(['merchantStatus']) || request.resource.data.merchantStatus == 'pending');
      allow create: if request.auth != null && request.auth.uid == userId;
      allow delete: if request.auth != null && (request.auth.uid == userId || get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'admin');

      // Allow admins full access to write user profiles
      allow update: if request.auth != null && get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'admin';
      // Allow admins to read all user profiles
      allow read: if request.auth != null && get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'admin';

      // Cart Items: Users can only read and write to their own cart
      match /cart/{cartItemId} {
        allow read, write: if request.auth != null && request.auth.uid == userId;
      }

      // Wishlist: Users can only read and write their own wishlist
      match /wishlist/{wishlistItemId} {
        allow read, write: if request.auth != null && request.auth.uid == userId;
      }
    }

    // Orders: Users can read and create their own orders. Admins can read all orders. Merchants can read/update their orders.
    match /orders/{orderId} {
      allow create: if request.auth != null && request.resource.data.userId == request.auth.uid;
      allow read: if request.auth != null && (resource.data.userId == request.auth.uid || get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'admin' || (get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'merchant' && resource.data.merchantId == request.auth.uid));
      allow update: if request.auth != null && (get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'admin' || (get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'merchant' && resource.data.merchantId == request.auth.uid));
      allow delete: if request.auth != null && get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'admin';
    }

    // Carts collection: Users can create and read their own carts
    match /carts/{cartId} {
      allow create: if request.auth != null && request.resource.data.userId == request.auth.uid;
      allow read: if request.auth != null && resource.data.userId == request.auth.uid;
    }

    // Checkouts collection: Users can create and read their own checkouts
    match /checkouts/{checkoutId} {
      allow create: if request.auth != null && request.resource.data.userId == request.auth.uid;
      allow read: if request.auth != null && resource.data.userId == request.auth.uid;
    }

    // Contact Messages: Anyone can create, only admins can read
    match /contact_messages/{messageId} {
      allow create: if true;
      allow read: if request.auth != null && get(/databases/$(database)/documents/users/$(request.auth.uid)).data.role == 'admin';
    }

  }
}



const fs = require('fs'); const path = require('path'); function walk(dir) { let results = []; const list = fs.readdirSync(dir); list.forEach(file => { file = path.join(dir, file); const stat = fs.statSync(file); if (stat && stat.isDirectory() && !file.includes('node_modules') && !file.includes('.next')) { results = results.concat(walk(file)); } else if (file.endsWith('.tsx') || file.endsWith('.ts')) { results.push(file); } }); return results; } const files = walk('./src'); const iconNames = new Set(); files.forEach(f => { const content = fs.readFileSync(f, 'utf8'); const matches = content.matchAll(/<Icon[^>]*name=[\"\']([a-zA-Z0-9_]+)[\"\']/g); for (const m of matches) iconNames.add(m[1]); const matches2 = content.matchAll(/icon:\s*[\"\']([a-zA-Z0-9_]+)[\"\']/g); for (const m of matches2) iconNames.add(m[1]); }); console.log('All icons found:', Array.from(iconNames));



'use client';

import { useEffect, useState } from 'react';
import Link from 'next/link';
import { getCart, removeFromCart, updateCartItem, CartItem } from '@/lib/api/cart';
import { auth } from '@/lib/firebase';
import { onAuthStateChanged } from 'firebase/auth';
import { getUserProfile } from '@/lib/api/auth';
import Icon from '@/components/Icon';

export default function CartPage() {
  const [items, setItems] = useState<CartItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [total, setTotal] = useState(0);
  const [userRole, setUserRole] = useState<'customer' | 'admin' | 'merchant' | 'guest'>('guest');

  const loadCart = async () => {
    try {
      const cart = await getCart();
      const cartItems = cart.CartItems || [];
      setItems(cartItems);
      calculateTotal(cartItems);
    } catch (error) {
      console.error('Error loading cart:', error);
    } finally {
      setLoading(false);
    }
  };

  const calculateTotal = (cartItems: CartItem[]) => {
    const t = cartItems.reduce((sum, item) => {
      if (!item.Product) return sum;
      const price = parseFloat(String(item.Product.price));
      const discount = item.Product.discount || 0;
      const finalPrice = discount > 0 ? price * (1 - discount / 100) : price;
      return sum + finalPrice * item.quantity;
    }, 0);
    setTotal(t);
  };

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (user) => {
      if (user) {
        try {
          const profile = await getUserProfile(user.uid);
          if (profile && profile.role) {
            setUserRole(profile.role);
          } else {
            setUserRole('customer');
          }
          if (!profile || !['admin', 'merchant'].includes(profile.role as string)) {
            loadCart();
          } else {
            setLoading(false);
          }
        } catch (err) {
          console.error("Error fetching user profile:", err);
          setUserRole('customer');
          loadCart();
        }
      } else {
        setUserRole('guest');
        loadCart();
      }
    });
    return () => unsubscribe();
  }, []);

  const handleQuantityChange = async (productId: number | string, currentQty: number, change: number) => {
    const newQty = currentQty + change;
    if (newQty < 1) return;

    // Optimistic state update
    const updatedItems = items.map(item => {
      if (item.product_id == productId) {
        return { ...item, quantity: newQty };
      }
      return item;
    });
    setItems(updatedItems);
    calculateTotal(updatedItems);

    try {
      await updateCartItem(productId, newQty);
    } catch (err) {
      console.error('Error updating quantity:', err);
      // Revert if error
      loadCart();
    }
  };

  const handleRemove = async (productId: number | string) => {
    if (confirm('Remove this item from your cart?')) {
      // Optimistic state update
      const filtered = items.filter(item => item.product_id != productId);
      setItems(filtered);
      calculateTotal(filtered);

      try {
        await removeFromCart(productId);
      } catch (err) {
        console.error('Error removing item:', err);
        loadCart();
      }
    }
  };

  return (
    <main className="max-w-[1440px] mx-auto px-6 md:px-16 py-16 flex-grow">
      <h1 className="font-headline-md text-3xl md:text-5xl font-black mb-10 uppercase tracking-tighter text-on-surface">
        Your Cart
      </h1>

      {userRole === 'admin' || userRole === 'merchant' ? (
        <div className="border-2 border-error p-12 bg-error-container text-center flex flex-col items-center justify-center max-w-[600px] mx-auto">
          <Icon name="block" className="text-5xl mb-4 text-error" />
          <h3 className="font-headline-md text-xl font-bold uppercase mb-2 text-error">Access Denied</h3>
          <p className="text-sm text-error mb-6 max-w-[300px]">Admins and Merchants cannot purchase items.</p>
          <Link 
            href={userRole === 'admin' ? "/admin" : "/merchant"} 
            className="px-6 py-3 bg-error text-white font-bold text-xs uppercase tracking-wider border-2 border-error shadow-sm active:scale-95 transition-transform"
          >
            Return to Dashboard
          </Link>
        </div>
      ) : loading ? (
        <div className="flex flex-col items-center justify-center py-20">
          <Icon name="sync" className="text-4xl animate-spin text-primary-container" />
          <p className="mt-4 font-bold text-sm tracking-widest text-secondary uppercase">Loading your cart...</p>
        </div>
      ) : items.length === 0 ? (
        <div className="border-2 border-on-surface p-12 bg-surface text-center flex flex-col items-center justify-center max-w-[600px] mx-auto">
          <Icon name="shopping_bag" className="text-5xl mb-4 text-secondary" />
          <h3 className="font-headline-md text-xl font-bold uppercase mb-2">Your cart is empty</h3>
          <p className="text-sm text-secondary mb-6 max-w-[300px]">Add some great items to get started!</p>
          <Link 
            href="/products" 
            className="px-6 py-3 bg-primary-container text-on-primary-container font-bold text-xs uppercase tracking-wider border-2 border-on-surface shadow-sm active:scale-95 transition-transform"
          >
            Browse Products
          </Link>
        </div>
      ) : (
        <div className="flex flex-col lg:flex-row gap-12 items-start">
          {/* Items Section */}
          <div className="flex-grow w-full space-y-6">
            {/* Table Header (Desktop Only) */}
            <div className="hidden md:grid grid-cols-12 pb-2 border-b-2 border-on-surface font-bold text-xs uppercase tracking-wider text-secondary">
              <div className="col-span-6">Product</div>
              <div className="col-span-2 text-center">Price</div>
              <div className="col-span-2 text-center">Quantity</div>
              <div className="col-span-2 text-right">Total</div>
            </div>

            {/* Cart Items List */}
            <div className="divide-y-2 divide-surface-container-highest">
              {items.map(item => {
                const product = item.Product;
                if (!product) return null;
                const originalPrice = parseFloat(String(product.price));
                const discount = product.discount || 0;
                const unitPrice = discount > 0 ? originalPrice * (1 - discount / 100) : originalPrice;
                const itemTotal = unitPrice * item.quantity;

                return (
                  <div 
                    key={item.id} 
                    className="grid grid-cols-1 md:grid-cols-12 items-center py-6 gap-6 hover:border-on-surface transition-all duration-300"
                  >
                    {/* Item Details */}
                    <div className="col-span-1 md:col-span-6 flex gap-4">
                      <div className="w-20 md:w-24 bg-surface-container-high overflow-hidden border border-on-surface flex-shrink-0">
                        <img 
                          alt={product.name} 
                          className="w-full h-auto object-contain" 
                          src={product.image_url || 'https://via.placeholder.com/150'}
                        />
                      </div>
                      <div className="flex flex-col justify-center">
                        <h3 className="font-headline-md text-sm md:text-base font-extrabold uppercase text-on-surface">
                          {product.name}
                        </h3>
                        <p className="text-xs text-secondary uppercase font-semibold mt-1">
                          Category: {product.category || 'Apparel'}
                        </p>
                        <button 
                          onClick={() => handleRemove(product.id)}
                          className="text-left text-xs font-bold text-error underline mt-3 uppercase tracking-wider hover:text-red-700"
                        >
                          Remove
                        </button>
                      </div>
                    </div>

                    {/* Unit Price */}
                    <div className="hidden md:block col-span-1 md:col-span-2 text-center font-headline-md text-sm md:text-base font-extrabold">
                      Ksh {unitPrice.toFixed(2)}
                      {discount > 0 && (
                        <div className="text-xs text-secondary line-through font-normal">Ksh {originalPrice.toFixed(2)}</div>
                      )}
                    </div>

                    {/* Quantity Selectors */}
                    <div className="col-span-1 md:col-span-2 flex justify-start md:justify-center">
                      <div className="flex border-2 border-on-surface bg-surface">
                        <button 
                          onClick={() => handleQuantityChange(product.id, item.quantity, -1)}
                          className="px-3 py-1 font-bold hover:bg-surface-container active:bg-surface-dim transition-colors border-r-2 border-on-surface text-sm"
                        >
                          -
                        </button>
                        <span className="px-4 py-1 font-extrabold flex items-center justify-center text-sm min-w-[40px]">
                          {item.quantity}
                        </span>
                        <button 
                          onClick={() => handleQuantityChange(product.id, item.quantity, 1)}
                          className="px-3 py-1 font-bold hover:bg-surface-container active:bg-surface-dim transition-colors border-l-2 border-on-surface text-sm"
                        >
                          +
                        </button>
                      </div>
                    </div>

                    {/* Total Price */}
                    <div className="col-span-1 md:col-span-2 text-right font-headline-md text-base md:text-lg font-black text-primary-container">
                      Ksh {itemTotal.toFixed(2)}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Checkout Column */}
          <div className="w-full lg:max-w-md bg-surface border-2 border-on-surface p-8">
            <h3 className="font-headline-md text-lg font-extrabold mb-6 uppercase tracking-wider text-on-surface">
              Order Summary
            </h3>

            <div className="space-y-4">
              <div className="flex justify-between border-b border-surface-container pb-3 font-semibold text-sm">
                <span className="text-secondary uppercase tracking-wider">Subtotal</span>
                <span className="font-extrabold">Ksh {total.toFixed(2)}</span>
              </div>

              <div className="flex justify-between border-b border-surface-container pb-3 font-semibold text-sm">
                <span className="text-secondary uppercase tracking-wider">Shipping</span>
                <span className="font-extrabold text-primary-container">FREE</span>
              </div>

              <div className="flex justify-between pb-3 pt-2 font-black text-lg">
                <span className="uppercase tracking-widest text-on-surface">Total</span>
                <span className="text-on-surface">Ksh {total.toFixed(2)}</span>
              </div>
            </div>

            <Link 
              href="/checkout" 
              className="mt-8 w-full h-14 bg-primary-container text-on-primary-container font-headline-md font-bold uppercase tracking-wider text-sm border-b-4 border-on-surface flex items-center justify-center transition-all active:scale-[0.98] hover:bg-amber-500"
            >
              Proceed to Checkout
            </Link>

            <Link 
              href="/products" 
              className="mt-4 w-full h-12 border-2 border-on-surface font-bold uppercase tracking-wider text-xs flex items-center justify-center hover:bg-surface-container-low transition-colors"
            >
              Continue Shopping
            </Link>
          </div>
        </div>
      )}
    </main>
  );
}



'use client';

import { useEffect, useState } from 'react';
import Link from 'next/link';
import { getProducts } from '@/lib/api/products';
import { addToCart } from '@/lib/api/cart';
import { Product } from '@/lib/data/products-data';
import Icon from '@/components/Icon';

export default function LandingPage() {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const [addingToCart, setAddingToCart] = useState<Record<number, boolean>>({});
  const [addedToCart, setAddedToCart] = useState<Record<number, boolean>>({});
  const [email, setEmail] = useState('');
  const [subscribed, setSubscribed] = useState(false);

  useEffect(() => {
    const loadProducts = async () => {
      try {
        const data = await getProducts({ limit: 8 });
        setProducts(data);
      } catch (error) {
        console.error('Error loading products:', error);
      } finally {
        setLoading(false);
      }
    };
    loadProducts();
  }, []);

  const handleAddToCart = async (productId: number) => {
    setAddingToCart(prev => ({ ...prev, [productId]: true }));
    try {
      await addToCart(productId, 1);
      setAddedToCart(prev => ({ ...prev, [productId]: true }));
      setTimeout(() => {
        setAddedToCart(prev => ({ ...prev, [productId]: false }));
        setAddingToCart(prev => ({ ...prev, [productId]: false }));
      }, 2000);
    } catch (err: any) {
      console.error(err);
      setAddingToCart(prev => ({ ...prev, [productId]: false }));
    }
  };

  const handleSubscribe = (e: React.FormEvent) => {
    e.preventDefault();
    if (email) {
      setSubscribed(true);
      setEmail('');
      setTimeout(() => setSubscribed(false), 3000);
    }
  };

  return (
    <div className="bg-background text-on-surface">

      {/* ═══════════════════════════════════════════════════════════
          1. HERO SECTION
         ═══════════════════════════════════════════════════════════ */}
