                    {cat.name}
                  </h3>
                </Link>
              ))}
            </div>
          </div>
        </div>
      </section>

      {/* ═══════════════════════════════════════════════════════════
          4. FEATURED PRODUCTS
         ═══════════════════════════════════════════════════════════ */}
      <section className="py-20 md:py-28 bg-background">
        <div className="max-w-[1440px] mx-auto px-6 md:px-16">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4 mb-14">
