'use client';

import { useEffect, useState } from 'react';
import { useParams } from 'next/navigation';
import Link from 'next/link';
import { getProduct } from '@/lib/api/products';
import { addToCart } from '@/lib/api/cart';
import { addToWishlist, removeFromWishlist, isInWishlist } from '@/lib/api/wishlist';
import { Product } from '@/lib/data/products-data';
import Icon from '@/components/Icon';
import ProductReviews from '@/components/shop/ProductReviews';
import ProductRatingBadge from '@/components/shop/ProductRatingBadge';
import './detail.css';

const mapColorToCss = (name: string): string => {
  const lower = name.toLowerCase();
  if (lower.includes('black')) return '#1a1c1c';
  if (lower.includes('white')) return '#ffffff';
  if (lower.includes('red')) return '#ff6b00';
  if (lower.includes('blue')) return '#00658f';
  if (lower.includes('green')) return '#ffdcc3';
  if (lower.includes('orange')) return '#ff8c00';
  if (lower.includes('gray') || lower.includes('grey') || lower.includes('silver')) return '#c6c6c6';
  return '#ff8c00';
};

export default function ProductDetailPage() {
  const params = useParams();
  const productId = params.id as string;

  const [product, setProduct] = useState<Product | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(false);
  const [selectedColor, setSelectedColor] = useState<string | null>(null);
  const [selectedSize, setSelectedSize] = useState<string | null>(null);
  const [quantity, setQuantity] = useState(1);
  const [cartStatus, setCartStatus] = useState<'idle' | 'adding' | 'added' | 'error'>('idle');
  const [activeImage, setActiveImage] = useState<string | null>(null);
  const [isWishlisted, setIsWishlisted] = useState(false);
  const [wishlistLoading, setWishlistLoading] = useState(false);

  useEffect(() => {
    const loadProduct = async () => {
      if (!productId) {
        setError(true);
        setLoading(false);
        return;
      }
      try {
        const data = await getProduct(productId);
        setProduct(data);
        setActiveImage(data.image_url);
        if (data.colors && data.colors.length > 0) setSelectedColor(data.colors[0]);
        if (data.sizes && data.sizes.length > 0) setSelectedSize(data.sizes[0]);

        const wishlisted = await isInWishlist(productId);
        setIsWishlisted(wishlisted);
      } catch {
        setError(true);
      } finally {
        setLoading(false);
      }
    };
    loadProduct();
  }, [productId]);

  const handleAddToCart = async () => {
    if (!product) return;
    setCartStatus('adding');
    try {
      await addToCart(product.id, quantity);
      setCartStatus('added');
      setTimeout(() => setCartStatus('idle'), 2000);
    } catch (err: any) {
      setCartStatus('error');
      setTimeout(() => setCartStatus('idle'), 2000);
    }
  };

  const handleToggleWishlist = async () => {
    if (!product) return;
    setWishlistLoading(true);
    try {
      if (isWishlisted) {
        await removeFromWishlist(product.id);
        setIsWishlisted(false);
      } else {
        await addToWishlist(product.id);
        setIsWishlisted(true);
      }
    } catch (err) {
      console.error('Wishlist error:', err);
    } finally {
      setWishlistLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center py-32 flex-grow">
        <Icon name="sync" className="text-4xl animate-spin text-primary-container" />
        <p className="mt-4 font-bold text-xs tracking-widest text-secondary uppercase">Loading product specifications...</p>
      </div>
    );
  }

  if (error || !product) {
    return (
      <div className="max-w-[600px] mx-auto my-20 p-12 bg-surface border-2 border-on-surface text-center flex flex-col items-center justify-center">
        <Icon name="error" className="text-5xl mb-4 text-error" />
        <h3 className="font-headline-md text-xl font-bold uppercase mb-2">Product Not Found</h3>
        <p className="text-sm text-secondary mb-6 max-w-[320px]">We couldn't retrieve the specified catalog items. They may have been deregistered by an administrator.</p>
        <Link 
          href="/products" 
          className="px-6 py-3 bg-primary-container text-on-primary-container font-bold text-xs uppercase tracking-wider border-2 border-on-surface shadow-sm active:scale-95 transition-transform"
        >
          Back to Catalog
        </Link>
      </div>
    );
  }

  const discount = product.discount || 0;
  const originalPrice = parseFloat(String(product.price));
  const finalPrice = discount > 0 ? originalPrice * (1 - discount / 100) : originalPrice;

  return (
    <main className="max-w-[1440px] mx-auto px-6 md:px-16 py-12 flex-grow space-y-8">

      {/* Breadcrumb Navigation */}
      <nav className="font-bold text-[10px] uppercase tracking-wider text-secondary flex items-center gap-1.5 pb-2 border-b-2 border-surface-container">
        <Link href="/" className="hover:text-on-surface">Home</Link>
        <span>/</span>
        <Link href="/products" className="hover:text-on-surface">Shop</Link>
        <span>/</span>
        <span className="text-on-surface truncate max-w-[200px]">{product.name}</span>
      </nav>

      {/* Main Details Grid */}
      <section className="grid grid-cols-1 lg:grid-cols-12 gap-12 items-start">

        {/* Left Column: Picture Gallery */}
        <div className="lg:col-span-6 space-y-4">
          <div className="relative bg-surface-container-low border-4 border-on-surface shadow-[6px_6px_0px_0px_var(--color-on-surface)] overflow-hidden flex items-center justify-center">
            <img 
              src={activeImage || product.image_url} 
              alt={product.name} 
              className="w-full h-auto object-contain"
            />
            {product.tags && product.tags.length > 0 && (
              <div className="absolute top-4 left-4 flex flex-wrap gap-2">
                {product.tags.map(tag => (
                  <span key={tag} className="bg-primary-container text-on-primary-container text-[9px] font-black uppercase px-2 py-0.5 border border-on-surface shadow-sm">
                    {tag}
                  </span>
                ))}
              </div>
            )}
            {discount > 0 && (
              <span className="absolute top-4 right-4 bg-red-50 text-error border-2 border-error text-[10px] font-black uppercase px-2.5 py-1">
                -{discount}% OFF
              </span>
            )}
          </div>

          {/* Additional Images Roll */}
          {product.additional_images && product.additional_images.length > 0 && (
            <div className="flex gap-3 overflow-x-auto no-scrollbar py-2">
              <button 
                onClick={() => setActiveImage(product.image_url)}
                className={`w-16 h-20 md:w-20 md:h-24 bg-surface-container-low border-2 overflow-hidden flex-shrink-0 active:scale-95 transition-all ${
                  activeImage === product.image_url ? 'border-primary-container' : 'border-on-surface'
                }`}
              >
                <img src={product.image_url} alt="Base main" className="w-full h-auto object-contain" />
              </button>
              {product.additional_images.map((img, idx) => (
                <button 
                  key={idx}
                  onClick={() => setActiveImage(img)}
                  className={`w-16 h-20 md:w-20 md:h-24 bg-surface-container-low border-2 overflow-hidden flex-shrink-0 active:scale-95 transition-all ${
                    activeImage === img ? 'border-primary-container' : 'border-on-surface'
                  }`}
                >
                  <img src={img} alt={`Gallery ${idx + 1}`} className="w-full h-auto object-contain" />
                </button>
              ))}
            </div>
          )}
        </div>

        {/* Right Column: Specifications & Configuration */}
        <div className="lg:col-span-6 space-y-8 bg-surface border-2 border-on-surface p-6 md:p-8 shadow-[4px_4px_0px_0px_var(--color-on-surface)]">
          {/* Header */}
          <div className="border-b-2 border-surface-container pb-4 space-y-2">
            <span className="bg-surface-container text-on-surface border border-on-surface text-[9px] font-black uppercase px-2 py-0.5 tracking-wider">
              {product.category || 'Apparel'}
            </span>
            <h1 className="font-headline-md text-2xl md:text-3xl font-black uppercase tracking-tight text-on-surface">
              {product.name}
            </h1>

            <div className="flex items-center gap-3 pt-1">
              <span className="font-headline-md text-2xl font-black text-on-surface">Ksh {finalPrice.toFixed(2)}</span>
              {discount > 0 && (
                <span className="text-sm font-bold text-secondary line-through">Ksh {originalPrice.toFixed(2)}</span>
              )}
              <ProductRatingBadge productId={product.id} />
            </div>
          </div>

          {/* Description */}
          <div className="space-y-2">
            <h3 className="font-headline-md text-xs font-black uppercase tracking-widest text-on-surface">Product Specifications</h3>
            <p className="font-body-md text-xs text-secondary leading-relaxed font-semibold">
              {product.description || 'Premium engineered sports apparel curated utilizing extreme-velocity structural textures, optimized for peak retail execution.'}
            </p>
          </div>

          {/* Merchant Info */}
          <Link href={`/store/${product.merchantId || 'admin'}`} className="flex items-start gap-3 bg-surface-container-lowest p-3 border-2 border-on-surface-variant shadow-[2px_2px_0px_0px_rgba(26,28,28,0.2)] hover:border-primary-container transition-colors group block">
            <div className="w-10 h-10 bg-primary-container text-on-primary-container flex items-center justify-center font-black text-sm shrink-0 border-2 border-on-surface uppercase">
              {product.merchantName ? product.merchantName.substring(0,2) : 'JU'}
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-xs font-black text-on-surface uppercase truncate tracking-wider flex items-center gap-1">
                {product.merchantName || 'JUJ4 Official Store'}
                {product.merchantStatus === 'verified' && (
                  <Icon name="verified" className="text-[14px] text-blue-500" />
                )}
              </p>
              <p className="text-[10px] text-secondary font-bold mt-0.5 leading-snug">
                {product.merchantInfo || 'Verified premium merchant with 100% positive feedback.'}
              </p>
            </div>
          </Link>

          {/* Option Settings */}
          <div className="space-y-4 border-t-2 border-surface-container pt-4">
            {/* Colors */}
            {product.colors && product.colors.length > 0 && (
              <div className="space-y-2">
                <label className="font-extrabold text-[10px] uppercase tracking-widest block text-secondary">
                  Select Color: <span className="text-on-surface font-black uppercase">{selectedColor}</span>
                </label>
                <div className="flex gap-2">
                  {product.colors.map(color => (
                    <button
                      key={color}
                      onClick={() => setSelectedColor(color)}
                      style={{ backgroundColor: mapColorToCss(color) }}
                      className={`w-8 h-8 rounded-full border-2 transition-transform active:scale-90 ${
                        color === selectedColor ? 'border-primary-container scale-105 shadow-sm' : 'border-on-surface'
                      }`}
                      title={color}
                    />
                  ))}
                </div>
              </div>
            )}

            {/* Sizes */}
            {product.sizes && product.sizes.length > 0 && (
              <div className="space-y-2 pt-2">
                <label className="font-extrabold text-[10px] uppercase tracking-widest block text-secondary">
                  Select Size: <span className="text-on-surface font-black">{selectedSize}</span>
                </label>
                <div className="flex flex-wrap gap-2">
                  {product.sizes.map(size => (
                    <button
                      key={size}
                      onClick={() => setSelectedSize(size)}
                      className={`px-4 py-2 border-2 text-xs font-extrabold uppercase transition-all ${
                        size === selectedSize 
                          ? 'bg-primary-container text-on-primary-container border-on-surface' 
                          : 'bg-surface text-on-surface border-on-surface hover:bg-surface-container'
                      }`}
                    >
                      {size}
                    </button>
                  ))}
                </div>
              </div>
            )}
          </div>

          {/* Cart Quantity Adjustments & Primary Call-to-Action */}
          <div className="space-y-4 border-t-2 border-surface-container pt-6">
            <div className="flex flex-col sm:flex-row gap-4 items-start sm:items-center">
              {/* Quantity Box */}
              <div className="space-y-1.5">
                <label className="font-extrabold text-[10px] uppercase tracking-widest block text-secondary">Qty</label>
                <div className="flex border-2 border-on-surface bg-surface w-32">
                  <button 
                    onClick={() => setQuantity(q => Math.max(1, q - 1))}
                    className="px-3 py-2 font-bold hover:bg-surface-container active:bg-surface-dim transition-colors border-r-2 border-on-surface text-sm flex-1"
                  >
                    -
                  </button>
                  <span className="px-4 py-2 font-extrabold flex items-center justify-center text-sm min-w-[40px]">
                    {quantity}
                  </span>
                  <button 
                    onClick={() => setQuantity(q => Math.min(10, q + 1))}
                    className="px-3 py-2 font-bold hover:bg-surface-container active:bg-surface-dim transition-colors border-l-2 border-on-surface text-sm flex-1"
                  >
                    +
                  </button>
                </div>
              </div>

              {/* Add Button */}
              <div className="flex-1 w-full pt-5 flex gap-2">
                <button
                  onClick={handleAddToCart}
                  disabled={cartStatus === 'adding'}
                  className={`flex-1 h-12 bg-primary-container text-on-primary-container font-headline-md font-bold uppercase tracking-wider text-xs border-2 border-on-surface transition-transform active:scale-95 shadow-[4px_4px_0px_0px_var(--color-on-surface)] active:translate-y-0.5 active:shadow-[1px_1px_0px_0px_var(--color-on-surface)] hover:bg-amber-500 disabled:opacity-50 flex items-center justify-center gap-2 ${
                    cartStatus === 'added' ? '!bg-green-600 !text-white' : ''
                  }`}
                >
                  <Icon name={cartStatus === 'added' ? 'check' : 'shopping_cart'} className="text-sm font-black" />
                  <span>
                    {cartStatus === 'adding' ? 'Adding to Cart...' : cartStatus === 'added' ? 'Added successfully ✓' : cartStatus === 'error' ? 'Pipeline error' : 'Add to Shopping Cart'}
                  </span>
                </button>
                <button
                  onClick={handleToggleWishlist}
                  disabled={wishlistLoading}
                  className={`w-12 h-12 bg-surface border-2 border-on-surface shadow-[4px_4px_0px_0px_var(--color-on-surface)] flex items-center justify-center hover:bg-surface-container active:scale-95 active:translate-y-0.5 active:shadow-[1px_1px_0px_0px_var(--color-on-surface)] transition-all ${isWishlisted ? 'text-error' : 'text-on-surface'}`}
                  title="Toggle Wishlist"
                >
                  <Icon name={isWishlisted ? 'favorite' : 'favorite_border'} className="text-xl" />
                </button>
              </div>
            </div>

            <div className="pt-2 text-[10px] font-black text-green-700 uppercase tracking-widest flex items-center gap-1.5">
              <Icon name="verified" className="text-xs font-black" />
              <span>In Stock and Ready for Express Delivery</span>
            </div>
          </div>

          {/* Delivery & Return Policies Grid */}
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 border-t-2 border-surface-container pt-6">
            <div className="flex gap-3 items-start p-3 bg-surface border border-on-surface-variant">
              <Icon name="local_shipping" className="text-primary-container text-2xl font-bold" />
              <div>
                <h4 className="font-extrabold text-[10px] uppercase text-on-surface">Free Delivery</h4>
                <p className="text-[9px] text-secondary font-semibold uppercase mt-0.5">Complimentary for orders over Ksh 150</p>
              </div>
            </div>
            <div className="flex gap-3 items-start p-3 bg-surface border border-on-surface-variant">
              <Icon name="swap_horiz" className="text-primary-container text-2xl font-bold" />
              <div>
                <h4 className="font-extrabold text-[10px] uppercase text-on-surface">30 Days Return</h4>
                <p className="text-[9px] text-secondary font-semibold uppercase mt-0.5">Hassle-free operations guarantee</p>
              </div>
            </div>
          </div>

        </div>

      </section>

      {/* Reviews Section */}
      <section className="border-t-4 border-on-surface pt-12 mt-12">
        <ProductReviews productId={productId} />
      </section>

    </main>
  );
}



'use client';

import { useEffect, useState } from 'react';
import { useParams } from 'next/navigation';
import Link from 'next/link';
import { getProducts } from '@/lib/api/products';
import { getUserProfile, User } from '@/lib/api/auth';
import { Product } from '@/lib/data/products-data';
import Icon from '@/components/Icon';
import ProductRatingBadge from '@/components/shop/ProductRatingBadge';
import { Globe, Mail, Phone } from 'lucide-react';
import { UserDocument } from '@/types/schema';

export default function MerchantStorePage() {
  const params = useParams();
  const merchantId = params.merchantId as string;

  const [merchant, setMerchant] = useState<User | null>(null);
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const [merchantLoading, setMerchantLoading] = useState(true);

  useEffect(() => {
    const fetchMerchantAndProducts = async () => {
      try {
        if (merchantId !== 'admin') {
          const profile = await getUserProfile(merchantId);
          setMerchant(profile);
        } else {
          setMerchant({
            uid: 'admin',
            email: 'admin@juj4.com',
            role: 'admin',
            storeName: 'JUJ4 Official Store',
            businessCategories: ['Retail'],
            location: 'Global',
          });
        }
      } catch (error) {
        console.error('Error fetching merchant profile:', error);
      } finally {
        setMerchantLoading(false);
      }

      try {
        const data = await getProducts({ merchantId });
        setProducts(data);
      } catch (error) {
        console.error('Error fetching merchant products:', error);
      } finally {
        setLoading(false);
      }
    };

    if (merchantId) {
      fetchMerchantAndProducts();
    }
  }, [merchantId]);

  if (merchantLoading) {
    return (
      <div className="flex flex-col items-center justify-center py-32 flex-grow bg-background">
        <Icon name="sync" className="text-4xl animate-spin text-primary-container" />
        <p className="mt-4 font-bold text-xs tracking-widest text-secondary uppercase">Loading Merchant Profile...</p>
      </div>
    );
  }

  const storeName = merchant?.storeName || (merchant?.first_name ? `${merchant.first_name} ${merchant.last_name || ''}` : 'Unknown Merchant');
  const m = merchant as (User & UserDocument) | null;

  return (
    <div className="bg-background flex-grow flex flex-col">
      {/* Merchant Header Hero */}
      <section 
        className="text-white py-12 md:py-20 border-b-4 border-primary-container relative overflow-hidden"
        style={{
          backgroundColor: m?.bannerUrl ? '#000' : '#1a1c1c', // bg-on-surface
          backgroundImage: m?.bannerUrl ? `url(${m.bannerUrl})` : 'none',
          backgroundSize: 'cover',
          backgroundPosition: 'center',
        }}
      >
        <div className="absolute inset-0 bg-black/60 pointer-events-none"></div>
        {!m?.bannerUrl && (
          <div className="absolute inset-0 opacity-10 pointer-events-none">
            <div className="absolute top-[10%] left-[5%] w-32 h-32 border-2 border-primary-container/30 rotate-45 animate-pulse" />
            <div className="absolute bottom-[10%] right-[10%] w-48 h-48 border-2 border-white/20 rotate-12" />
          </div>
        )}

        <div className="max-w-[1440px] mx-auto px-6 md:px-16 relative z-10 flex flex-col md:flex-row gap-8 items-center md:items-start">
          {m?.logoUrl ? (
            <img 
              src={m.logoUrl} 
              alt={`${storeName} Logo`} 
              className="w-32 h-32 md:w-40 md:h-40 object-cover bg-surface border-4 border-surface shadow-[4px_4px_0px_0px_rgba(255,255,255,0.2)] shrink-0"
            />
          ) : (
            <div className="w-32 h-32 md:w-40 md:h-40 bg-primary-container text-on-primary-container flex items-center justify-center font-black text-5xl md:text-6xl uppercase border-4 border-surface shadow-[4px_4px_0px_0px_rgba(255,255,255,0.2)] shrink-0">
              {storeName.substring(0, 2)}
            </div>
          )}

          <div className="text-center md:text-left flex-1">
            <h1 className="font-headline-lg text-4xl md:text-5xl font-black uppercase tracking-tighter mb-2">
              {storeName}
            </h1>

            <div className="flex flex-wrap gap-4 justify-center md:justify-start text-sm font-bold text-white/70 mb-4">
              {m?.businessCategories?.length ? (
                m.businessCategories.map((cat, idx) => (
                  <span key={idx} className="flex items-center gap-1 bg-white/10 px-3 py-1 uppercase tracking-wider backdrop-blur-sm">
                    <Icon name="store" className="text-[14px]" /> {cat}
                  </span>
                ))
              ) : (m as any)?.businessCategory ? (
                <span className="flex items-center gap-1 bg-white/10 px-3 py-1 uppercase tracking-wider backdrop-blur-sm">
                  <Icon name="store" className="text-[14px]" /> {(m as any).businessCategory}
                </span>
              ) : null}
              {m?.offeringType && (
                <span className="flex items-center gap-1 bg-white/10 px-3 py-1 uppercase tracking-wider backdrop-blur-sm">
                  <Icon name="shopping_bag" className="text-[14px]" /> {m.offeringType}
                </span>
              )}
              {m?.location && (
                <span className="flex items-center gap-1 bg-white/10 px-3 py-1 uppercase tracking-wider backdrop-blur-sm">
                  <Icon name="location_on" className="text-[14px]" /> {m.location}
                </span>
              )}
              {m?.merchantStatus === 'verified' && (
                <span className="flex items-center gap-1 bg-white/10 px-3 py-1 uppercase tracking-wider text-primary-container backdrop-blur-sm border border-primary-container/30">
                  <Icon name="verified" className="text-[14px]" /> Verified Seller
                </span>
              )}
            </div>

            <p className="text-sm max-w-2xl text-white/90 leading-relaxed font-medium mb-6">
              {m?.storeDescription || `Welcome to the official storefront for ${storeName}. Browse our entire catalog of premium items below.`}
            </p>

            {/* Contact & Socials */}
            <div className="flex flex-wrap items-center justify-center md:justify-start gap-6 text-sm">
              {/* Contact Info */}
              {(m?.storeContactEmail || m?.storeContactPhone) && (
                <div className="flex items-center gap-4 text-white/80">
                  {m?.storeContactEmail && (
                    <a href={`mailto:${m.storeContactEmail}`} className="flex items-center gap-1.5 hover:text-white transition-colors">
                      <Mail className="w-4 h-4" />
                      <span className="font-bold">{m.storeContactEmail}</span>
                    </a>
                  )}
                  {m?.storeContactPhone && (
                    <a href={`tel:${m.storeContactPhone}`} className="flex items-center gap-1.5 hover:text-white transition-colors">
                      <Phone className="w-4 h-4" />
                      <span className="font-bold">{m.storeContactPhone}</span>
                    </a>
                  )}
                </div>
              )}

              {/* Separator if both exist */}
              {(m?.storeContactEmail || m?.storeContactPhone) && m?.socialMediaLinks && Object.values(m.socialMediaLinks).some(Boolean) && (
                <div className="w-px h-4 bg-white/20 hidden md:block"></div>
              )}

              {/* Social Links */}
              {m?.socialMediaLinks && (
                <div className="flex items-center gap-3">
                  {m.socialMediaLinks.instagram && (
                    <a href={`https://instagram.com/${m.socialMediaLinks.instagram.replace('@', '')}`} target="_blank" rel="noreferrer" className="w-8 h-8 rounded-full bg-white/10 flex items-center justify-center hover:bg-primary-container hover:text-on-primary-container transition-colors font-black text-[10px]" title="Instagram">
                      IG
                    </a>
                  )}
                  {m.socialMediaLinks.twitter && (
                    <a href={`https://twitter.com/${m.socialMediaLinks.twitter.replace('@', '')}`} target="_blank" rel="noreferrer" className="w-8 h-8 rounded-full bg-white/10 flex items-center justify-center hover:bg-primary-container hover:text-on-primary-container transition-colors font-black text-[10px]" title="Twitter">
                      X
                    </a>
                  )}
                  {m.socialMediaLinks.facebook && (
                    <a href={m.socialMediaLinks.facebook.startsWith('http') ? m.socialMediaLinks.facebook : `https://${m.socialMediaLinks.facebook}`} target="_blank" rel="noreferrer" className="w-8 h-8 rounded-full bg-white/10 flex items-center justify-center hover:bg-primary-container hover:text-on-primary-container transition-colors font-black text-[10px]" title="Facebook">
                      FB
                    </a>
                  )}
                  {m.socialMediaLinks.website && (
                    <a href={m.socialMediaLinks.website.startsWith('http') ? m.socialMediaLinks.website : `https://${m.socialMediaLinks.website}`} target="_blank" rel="noreferrer" className="w-8 h-8 rounded-full bg-white/10 flex items-center justify-center hover:bg-primary-container hover:text-on-primary-container transition-colors" title="Website">
                      <Globe className="w-4 h-4" />
                    </a>
                  )}
                </div>
              )}
            </div>

          </div>
        </div>
      </section>

      {/* Catalog Section */}
      <section className="max-w-[1440px] w-full mx-auto px-6 md:px-16 py-12 md:py-16">
        <div className="flex items-center justify-between mb-8 border-b-2 border-on-surface pb-4">
          <h2 className="font-headline-md text-2xl md:text-3xl font-black uppercase tracking-tight text-on-surface">
            Merchant Catalog
          </h2>
          <span className="font-bold text-xs uppercase tracking-wider text-secondary bg-surface-container-low px-3 py-1 rounded">
            {loading ? '...' : `${products.length} Items`}
          </span>
        </div>

        {loading ? (
          <div className="flex flex-col items-center justify-center py-24 bg-surface border-2 border-on-surface">
            <Icon name="sync" className="text-4xl animate-spin text-primary-container" />
            <p className="mt-4 font-bold text-xs tracking-widest text-secondary uppercase">Loading Catalog...</p>
          </div>
        ) : products.length === 0 ? (
          <div className="p-12 text-center flex flex-col items-center justify-center bg-surface border-2 border-on-surface shadow-[4px_4px_0px_0px_var(--color-on-surface)]">
            <Icon name="inventory_2" className="text-5xl text-secondary mb-4" />
            <h4 className="font-extrabold uppercase text-lg text-on-surface">No Products Available</h4>
            <p className="text-sm text-secondary mt-2 max-w-[320px]">This merchant hasn't listed any products yet or they are currently out of stock.</p>
            <Link href="/products" className="mt-6 px-6 py-3 bg-on-surface text-surface font-bold uppercase text-xs tracking-widest border-2 border-on-surface hover:bg-surface-dim transition-colors">
              Browse Other Stores
            </Link>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 xl:grid-cols-4 gap-6">
            {products.map((product) => {
              const discount = product.discount || 0;
              const originalPrice = parseFloat(String(product.price));
              const finalPrice = discount > 0 ? originalPrice * (1 - discount / 100) : originalPrice;

              return (
                <article 
                  key={product.id} 
                  className="bg-surface border-2 border-on-surface shadow-[4px_4px_0px_0px_var(--color-on-surface)] hover:-translate-y-1 hover:shadow-[6px_6px_0px_0px_var(--color-on-surface)] transition-all flex flex-col relative group"
                >
                  <Link href={`/products/${product.id}`} className="block relative bg-surface-container-low aspect-square border-b-2 border-on-surface overflow-hidden">
                    <img 
                      src={product.image_url || 'https://via.placeholder.com/300'} 
                      alt={product.name} 
                      className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
                    />
                    {discount > 0 && (
                      <span className="absolute top-3 right-3 bg-error text-white text-[10px] font-black px-2.5 py-1 uppercase shadow-sm border border-on-surface">
                        -{discount}% OFF
                      </span>
                    )}
                  </Link>

                  <div className="p-4 flex-1 flex flex-col">
                    <p className="text-primary-container font-extrabold text-xl mb-1">
                      Ksh {finalPrice.toLocaleString('en-US', { minimumFractionDigits: 0, maximumFractionDigits: 0 })}
                    </p>

                    <Link href={`/products/${product.id}`}>
                      <h3 className="font-bold text-sm text-on-surface line-clamp-2 mb-2 hover:underline">{product.name}</h3>
                    </Link>

                    <div className="mt-auto pt-4 border-t border-surface-container flex items-center justify-between">
                      <ProductRatingBadge productId={product.id} />
                      <Link href={`/products/${product.id}`} className="text-[10px] font-black uppercase tracking-widest text-secondary hover:text-primary-container flex items-center gap-1">
                        View <Icon name="arrow_forward" className="text-[12px]" />
                      </Link>
                    </div>
                  </div>
                </article>
              );
            })}
          </div>
        )}
      </section>
    </div>
  );
}



'use client';

import { useEffect, useState } from 'react';
import Link from 'next/link';
import { getWishlist, removeFromWishlist } from '@/lib/api/wishlist';
import { addToCart } from '@/lib/api/cart';
import { Product } from '@/lib/data/products-data';
import { auth } from '@/lib/firebase';
import { onAuthStateChanged } from 'firebase/auth';
import { getUserProfile } from '@/lib/api/auth';
import Icon from '@/components/Icon';

interface Toast {
  id: number;
  message: string;
  type: 'success' | 'info';
}

export default function WishlistPage() {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const [removingId, setRemovingId] = useState<number | null>(null);
  const [addingToCart, setAddingToCart] = useState<Record<number, boolean>>({});
  const [addedToCart, setAddedToCart] = useState<Record<number, boolean>>({});
  const [userRole, setUserRole] = useState<'customer' | 'admin' | 'merchant' | 'guest'>('guest');
  const [toasts, setToasts] = useState<Toast[]>([]);

  const showToast = (message: string, type: 'success' | 'info' = 'success') => {
    const id = Date.now();
    setToasts(prev => [...prev, { id, message, type }]);
    setTimeout(() => {
      setToasts(prev => prev.filter(t => t.id !== id));
    }, 3000);
  };

  const fetchWishlist = async () => {
    setLoading(true);
    try {
      const data = await getWishlist();
      setProducts(data);
    } catch (error) {
      console.error('Error loading wishlist:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (user) => {
      if (user) {
        try {
          const profile = await getUserProfile(user.uid);
          if (profile && profile.role) {
            setUserRole(profile.role);
          } else {
            setUserRole('customer');
          }
          fetchWishlist();
        } catch (err) {
          console.error("Error fetching user profile:", err);
          setUserRole('customer');
        }
      } else {
        setUserRole('guest');
        setProducts([]);
        setLoading(false);
      }
    });
    return () => unsubscribe();
  }, []);

  // Listen for external wishlist changes
  useEffect(() => {
    const handleUpdate = () => fetchWishlist();
    window.addEventListener('wishlistUpdated', handleUpdate);
    return () => window.removeEventListener('wishlistUpdated', handleUpdate);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const handleRemove = async (productId: number) => {
    setRemovingId(productId);
    try {
      await removeFromWishlist(productId);
      setProducts(prev => prev.filter(p => p.id !== productId));
      showToast('Item removed from wishlist', 'info');
    } catch (error) {
      console.error('Error removing from wishlist:', error);
    } finally {
      setRemovingId(null);
    }
  };

  const handleAddToCart = async (e: React.MouseEvent, productId: number) => {
    e.preventDefault();
    setAddingToCart(prev => ({ ...prev, [productId]: true }));
    try {
      await addToCart(productId, 1);
      setAddedToCart(prev => ({ ...prev, [productId]: true }));
      showToast('Item added to cart!', 'success');
      setTimeout(() => {
        setAddedToCart(prev => ({ ...prev, [productId]: false }));
        setAddingToCart(prev => ({ ...prev, [productId]: false }));
      }, 2000);
    } catch (err) {
      console.error(err);
      setAddingToCart(prev => ({ ...prev, [productId]: false }));
    }
  };

  return (
    <main className="max-w-[1440px] mx-auto px-6 md:px-16 py-12 flex-grow">

      {/* Page Header */}
      <header className="mb-12">
        <p className="font-extrabold text-xs text-primary-container uppercase tracking-widest mb-1.5">Favorites</p>
        <h1 className="font-headline-md text-3xl md:text-5xl font-black uppercase tracking-tighter text-on-surface">
          My Wishlist
        </h1>
        <p className="font-body-md text-sm text-secondary uppercase font-semibold mt-2">
          Products you&apos;ve saved for later. Your curated collection of must-haves.
        </p>
      </header>

      {/* Loading State */}
      {loading ? (
        <div className="flex flex-col items-center justify-center py-24 bg-surface border-2 border-on-surface shadow-[4px_4px_0px_0px_var(--color-on-surface)]">
          <Icon name="sync" className="text-4xl animate-spin text-primary-container" />
          <p className="mt-4 font-bold text-xs tracking-widest text-secondary uppercase">Loading Wishlist...</p>
        </div>
      ) : products.length === 0 ? (
        /* Empty State */
        <div className="flex flex-col items-center justify-center py-24 bg-surface border-2 border-on-surface shadow-[4px_4px_0px_0px_var(--color-on-surface)]">
          <div className="w-20 h-20 flex items-center justify-center bg-surface-container border-2 border-on-surface mb-6">
            <Icon name="favorite" className="text-4xl text-secondary" />
          </div>
          <h2 className="font-headline-md text-lg font-black uppercase tracking-wider text-on-surface mb-2">
            Your wishlist is empty
          </h2>
          <p className="font-body-md text-sm text-secondary max-w-md text-center mb-8">
            You haven&apos;t saved any items yet. Browse our collection and tap the heart icon to add products you love.
          </p>
          <Link
            href="/products"
            className="px-8 py-3 bg-primary-container text-on-primary-container font-headline-md font-bold text-xs uppercase tracking-wider border-2 border-on-surface shadow-[4px_4px_0px_0px_var(--color-on-surface)] hover:-translate-y-1 hover:shadow-[6px_6px_0px_0px_var(--color-on-surface)] active:scale-95 active:translate-y-0.5 active:shadow-[1px_1px_0px_0px_var(--color-on-surface)] transition-all"
          >
            Browse Products
          </Link>
        </div>
      ) : (
        /* Wishlist Grid */
        <>
          <div className="flex items-center border-b-2 border-surface-container pb-4 mb-8">
            <div className="font-bold text-xs uppercase tracking-wider text-secondary">
              {products.length} item{products.length !== 1 ? 's' : ''} saved
            </div>
          </div>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
            {products.map((product) => {
              const discount = product.discount || 0;
              const originalPrice = parseFloat(String(product.price));
              const finalPrice = discount > 0 ? originalPrice * (1 - discount / 100) : originalPrice;

              return (
                <article
                  key={product.id}
                  className="bg-surface border-2 border-on-surface shadow-[4px_4px_0px_0px_var(--color-on-surface)] flex flex-col group hover:-translate-y-1 hover:shadow-[6px_6px_0px_0px_var(--color-on-surface)] transition-all"
                >
                  {/* Product Image */}
                  <Link
                    href={`/products/${product.id}`}
                    className="block relative overflow-hidden bg-surface-container-low border-b-2 border-on-surface aspect-[4/3]"
                  >
                    <img
                      src={product.image_url || 'https://via.placeholder.com/150'}
                      alt={product.name}
                      className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
                      loading="lazy"
                    />
                    {discount > 0 && (
                      <span className="absolute top-3 right-3 bg-error-container text-on-error-container border border-error text-[10px] font-black uppercase px-2.5 py-1">
                        -{discount}%
                      </span>
                    )}

                    {/* Remove Button (top-left) */}
                    <button
                      onClick={(e) => {
                        e.preventDefault();
                        handleRemove(product.id);
                      }}
                      disabled={removingId === product.id}
                      className="absolute top-3 left-3 w-9 h-9 flex items-center justify-center bg-surface border-2 border-on-surface shadow-[2px_2px_0px_0px_var(--color-on-surface)] hover:bg-red-50 hover:text-error active:scale-95 active:translate-y-0.5 active:shadow-[0px_0px_0px_0px_var(--color-on-surface)] transition-all disabled:opacity-50"
                      aria-label="Remove from wishlist"
                    >
                      <Icon
                        name={removingId === product.id ? 'sync' : 'delete'}
                        className={`text-base ${removingId === product.id ? 'animate-spin' : ''}`}
                      />
                    </button>
                  </Link>

                  {/* Product Info */}
                  <div className="p-5 flex flex-col flex-grow">
                    <h3 className="font-headline-md text-sm font-black uppercase text-on-surface mb-1 truncate">
                      {product.name}
                    </h3>
                    <p className="text-[10px] font-bold text-secondary uppercase tracking-wider mb-4">
                      Category: {product.category || 'Apparel'}
                    </p>

                    {/* Price & Actions */}
                    <div className="mt-auto space-y-3">
                      <div className="flex flex-col">
                        <span className="font-headline-md text-base font-black text-on-surface">
                          Ksh {finalPrice.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                        </span>
                        {discount > 0 && (
                          <span className="text-[10px] text-secondary line-through font-bold">
                            Ksh {originalPrice.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                          </span>
                        )}
                      </div>

                      {(userRole === 'customer' || userRole === 'guest') && (
                        <button
                          onClick={(e) => handleAddToCart(e, product.id)}
                          disabled={addingToCart[product.id]}
                          className={`w-full py-2.5 border-2 border-on-surface bg-primary-container text-on-primary-container font-headline-md font-bold text-[10px] uppercase tracking-wider transition-all active:scale-95 shadow-[3px_3px_0px_0px_var(--color-on-surface)] active:translate-y-0.5 active:shadow-[1px_1px_0px_0px_var(--color-on-surface)] hover:bg-amber-500 disabled:opacity-50 flex items-center justify-center gap-2 ${addedToCart[product.id] ? '!bg-green-600 !text-white' : ''}`}
                        >
                          <Icon name={addedToCart[product.id] ? 'check_circle' : 'shopping_cart'} className="text-sm" />
                          {addingToCart[product.id] ? (addedToCart[product.id] ? 'Added ✓' : 'Adding...') : 'Add to Cart'}
                        </button>
                      )}
                    </div>
                  </div>
                </article>
              );
            })}
          </div>
        </>
      )}

      {/* Toast Notifications */}
      <div className="fixed bottom-6 right-6 z-50 flex flex-col gap-3 pointer-events-none">
        {toasts.map((toast) => (
          <div
            key={toast.id}
            className={`pointer-events-auto px-5 py-3 border-2 border-on-surface shadow-[4px_4px_0px_0px_var(--color-on-surface)] font-bold text-xs uppercase tracking-wider flex items-center gap-2 animate-[slideInRight_0.3s_ease-out] ${
              toast.type === 'success'
                ? 'bg-surface-container text-green-500 dark:text-green-400'
                : 'bg-surface-container text-on-surface'
            }`}
          >
            <Icon
              name={toast.type === 'success' ? 'check_circle' : 'info'}
              className="text-base"
            />
            {toast.message}
          </div>
        ))}
      </div>

      {/* Inline animation keyframes */}
      <style jsx>{`
        @keyframes slideInRight {
          from {
            opacity: 0;
            transform: translateX(100%);
          }
          to {
            opacity: 1;
            transform: translateX(0);
          }
        }
      `}</style>
    </main>
  );
}



import { clearCart } from './cart';
import { db, auth } from '@/lib/firebase';
import { collection, addDoc, Timestamp, doc, updateDoc, increment } from 'firebase/firestore';
import { Order, OrderStatus, Cart, Checkout } from '@/types/schema';

export const createOrder = async (orderData: Partial<Order>): Promise<Order> => {
  const user = auth.currentUser;
  if (!user) throw new Error("User must be logged in to create an order");

  try {
    // 1. Create Cart document
    const cartItems = orderData.items?.map(item => ({
      productId: item.productId,
      quantity: item.quantity,
      addedAt: Timestamp.now()
    })) || [];

    const newCart: Cart = {
      userId: user.uid,
      items: cartItems,
      totalAmount: orderData.totalAmount || 0,
      createdAt: Timestamp.now(),
      updatedAt: Timestamp.now(),
    };
    const cartDocRef = await addDoc(collection(db, 'carts'), newCart);

    // 2. Create Checkout document
    const newCheckout: Checkout = {
      userId: user.uid,
      cartId: cartDocRef.id,
      contactInformation: orderData.contactInformation,
      shippingAddress: orderData.shippingAddress,
      shippingInformation: orderData.shippingInformation,
      status: 'completed',
      totalAmount: orderData.totalAmount || 0,
      createdAt: Timestamp.now(),
      updatedAt: Timestamp.now(),
    };
    const checkoutDocRef = await addDoc(collection(db, 'checkouts'), newCheckout);

    // Group items by merchantId
    const itemsByMerchant: Record<string, any[]> = {};
    for (const item of orderData.items || []) {
      const mId = (item as any).merchantId || 'admin';
      if (!itemsByMerchant[mId]) itemsByMerchant[mId] = [];
      itemsByMerchant[mId].push(item);
    }

    // 3. Create Order documents for each merchant
    let firstOrder: Order | null = null;
    let firstOrderId = '';

    for (const merchantId in itemsByMerchant) {
      const mItems = itemsByMerchant[merchantId];
      const mTotal = mItems.reduce((sum, item) => sum + (item.price * item.quantity), 0);

      const newOrder: Order = {
        userId: user.uid,
        merchantId: merchantId,
        cartId: cartDocRef.id,
        checkoutId: checkoutDocRef.id,
        status: 'pending' as OrderStatus,
        totalAmount: mTotal,
        contactInformation: orderData.contactInformation,
        shippingAddress: orderData.shippingAddress || {
          street: '', city: '', zipCode: '', country: ''
        },
        shippingInformation: orderData.shippingInformation,
        items: mItems,
        createdAt: Timestamp.now(),
        updatedAt: Timestamp.now(),
      };

      const orderDocRef = await addDoc(collection(db, 'orders'), newOrder);
      if (!firstOrder) {
        firstOrder = newOrder;
        firstOrderId = orderDocRef.id;
      }
    }

    // 4. Update Product Stock
    if (orderData.items && orderData.items.length > 0) {
      await Promise.all(orderData.items.map(async (item) => {
        if (item.productId) {
          const productRef = doc(db, 'products', item.productId);
          await updateDoc(productRef, {
            stock: increment(-item.quantity)
          }).catch(err => {
            console.error(`Failed to update stock for product ${item.productId}:`, err);
          });
        }
      }));
    }

    await clearCart();

    if (!firstOrder) throw new Error("Failed to create order");

    return {
      ...firstOrder,
      id: firstOrderId,
    };
  } catch (error) {
    console.error('Error creating order:', error);
    throw error;
  }
};

export const getMyOrders = async (): Promise<Order[]> => {
  const user = auth.currentUser;
  if (!user) return [];

  try {
    const { getDocs, query, where } = await import('firebase/firestore');
    const q = query(
      collection(db, 'orders'),
      where('userId', '==', user.uid)
    );
    const snapshot = await getDocs(q);
    const orders = snapshot.docs.map(docSnap => ({
      id: docSnap.id,
      ...docSnap.data()
    })) as Order[];

    // Sort client-side to avoid composite index requirement
    orders.sort((a, b) => {
      const timeA = a.createdAt ? (a.createdAt as any).seconds || 0 : 0;
      const timeB = b.createdAt ? (b.createdAt as any).seconds || 0 : 0;
      return timeB - timeA;
    });

    return orders;
  } catch (error) {
    console.error('Error fetching user orders:', error);
    return [];
  }
};

export const getAllOrders = async (): Promise<Order[]> => {
  try {
    const { getDocs, query, orderBy } = await import('firebase/firestore');
    const q = query(collection(db, 'orders'), orderBy('createdAt', 'desc'));
    const snapshot = await getDocs(q);
    return snapshot.docs.map(doc => ({
      id: doc.id,
      ...doc.data()
    })) as Order[];
  } catch (error) {
    console.error('Error fetching all orders:', error);
    return [];
  }
};



