'use client';

import { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { createOrder } from '@/lib/api/order';
import { getCart, CartItem } from '@/lib/api/cart';
import { getUserProfile, User } from '@/lib/api/auth';
import { auth } from '@/lib/firebase';
import { onAuthStateChanged } from 'firebase/auth';
import Icon from '@/components/Icon';

export default function CheckoutPage() {
  const router = useRouter();
  const [total, setTotal] = useState(0);
  const [itemCount, setItemCount] = useState(0);
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [submitting, setSubmitting] = useState(false);
  const [loading, setLoading] = useState(true);
  const [userProfile, setUserProfile] = useState<User | null>(null);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (user) => {
      if (!user) {
        router.push('/login?redirect=/checkout');
        return;
      }

      const loadCartSummary = async () => {
      try {
        const profile = await getUserProfile(user.uid);
        if (profile) setUserProfile(profile);

        if (profile && ['admin', 'merchant'].includes(profile.role as string)) {
          setLoading(false);
          return;
        }

        const cart = await getCart();
        if (!cart || !cart.CartItems || cart.CartItems.length === 0) {
          router.push('/cart');
          return;
        }
        setItemCount(cart.CartItems.length);
        setCartItems(cart.CartItems);
        const t = cart.CartItems.reduce(
          (sum: number, item: CartItem) => {
            if (!item.Product) return sum;
            const price = parseFloat(String(item.Product.price));
            const discount = item.Product.discount || 0;
            const finalPrice = discount > 0 ? price * (1 - discount / 100) : price;
            return sum + finalPrice * item.quantity;
          },
          0
        );
        setTotal(t);
      } catch (err) {
        console.error('Failed to load cart summary', err);
      } finally {
        setLoading(false);
      }
    };
    loadCartSummary();
    });

    return () => unsubscribe();
  }, [router]);

  const handleSubmit = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!confirm('Confirm order placement?')) return;

    const formData = new FormData(e.currentTarget);
    const orderData = {
      totalAmount: total,
      contactInformation: {
        fullName: formData.get('fullName') as string,
        email: formData.get('email') as string,
        phone: formData.get('phone') as string,
      },
      shippingAddress: {
        street: formData.get('address') as string,
        city: formData.get('city') as string,
        zipCode: '',
        country: '',
      },
      shippingInformation: {
        method: 'FREE EXPRESS',
        cost: 0,
      },
      items: cartItems.map(item => ({
        productId: item.product_id.toString(),
        name: item.Product?.name || 'Unknown',
        price: item.Product?.price ? parseFloat(String(item.Product.price)) : 0,
        quantity: item.quantity,
        merchantId: item.Product?.merchantId || 'admin',
      }))
    };

    setSubmitting(true);
    try {
      const order = await createOrder(orderData);
      if (order) {
        router.push(`/order-confirmation?id=${order.id}`);
      }
    } catch (err) {
      console.error(err);
      alert('Failed to place order. Please try again.');
    } finally {
      setSubmitting(false);
    }
  };

  if (loading) {
    return (
      <main className="max-w-[1440px] mx-auto px-6 md:px-16 py-16 flex-grow flex flex-col items-center justify-center min-h-[400px]">
        <Icon name="sync" className="text-4xl animate-spin text-primary-container" />
        <p className="mt-4 font-bold text-sm tracking-widest text-secondary uppercase">Loading checkout information...</p>
      </main>
    );
  }

  if (userProfile && ['admin', 'merchant'].includes(userProfile.role as string)) {
    return (
      <main className="max-w-[1440px] mx-auto px-6 md:px-16 py-16 flex-grow">
        <h1 className="font-headline-md text-3xl md:text-5xl font-black mb-10 uppercase tracking-tighter text-on-surface">
          Checkout
        </h1>
        <div className="border-2 border-error p-12 bg-red-50 text-center flex flex-col items-center justify-center max-w-[600px] mx-auto">
          <Icon name="block" className="text-5xl mb-4 text-error" />
          <h3 className="font-headline-md text-xl font-bold uppercase mb-2 text-error">Access Denied</h3>
          <p className="text-sm text-error mb-6 max-w-[300px]">Admins and Merchants cannot purchase items.</p>
          <Link 
            href={userProfile.role === 'admin' ? "/admin" : "/merchant"} 
            className="px-6 py-3 bg-error text-white font-bold text-xs uppercase tracking-wider border-2 border-error shadow-sm active:scale-95 transition-transform"
          >
            Return to Dashboard
          </Link>
        </div>
      </main>
    );
  }

  return (
    <main className="max-w-[1440px] mx-auto px-6 md:px-16 py-16 flex-grow">
      <h1 className="font-headline-md text-3xl md:text-5xl font-black mb-10 uppercase tracking-tighter text-on-surface">
        Checkout
      </h1>

      <form onSubmit={handleSubmit} className="flex flex-col lg:flex-row gap-12 items-start">
        {/* Left Column: Shipping & Payment forms */}
        <div className="flex-grow w-full space-y-8">

          {/* Shipping Information Card */}
          <div className="border-2 border-on-surface bg-surface p-8">
            <h3 className="font-headline-md text-xl font-bold uppercase tracking-wider text-on-surface pb-3 border-b-2 border-on-surface mb-6">
              Shipping Information
            </h3>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-1 col-span-1 md:col-span-2">
                <label htmlFor="fullName" className="font-bold text-xs uppercase tracking-wider text-on-surface block">
                  Full Name
                </label>
                <input
                  type="text"
                  id="fullName"
                  name="fullName"
                  defaultValue={userProfile ? `${userProfile.first_name || ''} ${userProfile.last_name || ''}`.trim() : ''}
                  required
                  className="w-full h-14 px-4 border-2 border-on-surface rounded-none font-medium bg-surface text-on-surface transition-all focus:border-primary-container focus:ring-0"
                />
              </div>

              <div className="space-y-1 col-span-1 md:col-span-2">
                <label htmlFor="email" className="font-bold text-xs uppercase tracking-wider text-on-surface block">
                  Email Address
                </label>
                <input
                  type="email"
                  id="email"
                  name="email"
                  defaultValue={userProfile?.email || ''}
                  required
                  className="w-full h-14 px-4 border-2 border-on-surface rounded-none font-medium bg-surface text-on-surface transition-all focus:border-primary-container focus:ring-0"
                />
              </div>

              <div className="space-y-1 col-span-1 md:col-span-2">
                <label htmlFor="phone" className="font-bold text-xs uppercase tracking-wider text-on-surface block">
                  Phone Number
                </label>
                <input
                  type="tel"
                  id="phone"
                  name="phone"
                  defaultValue={userProfile?.phone || ''}
                  className="w-full h-14 px-4 border-2 border-on-surface rounded-none font-medium bg-surface text-on-surface transition-all focus:border-primary-container focus:ring-0"
                />
              </div>

              <div className="space-y-1 col-span-1 md:col-span-2">
                <label htmlFor="address" className="font-bold text-xs uppercase tracking-wider text-on-surface block">
                  Shipping Address
                </label>
                <input
                  type="text"
                  id="address"
                  name="address"
                  defaultValue={userProfile?.location || ''}
                  required
                  className="w-full h-14 px-4 border-2 border-on-surface rounded-none font-medium bg-surface text-on-surface transition-all focus:border-primary-container focus:ring-0"
                />
              </div>

              <div className="space-y-1 col-span-1 md:col-span-2">
                <label htmlFor="city" className="font-bold text-xs uppercase tracking-wider text-on-surface block">
                  City
                </label>
                <input
                  type="text"
                  id="city"
                  name="city"
                  defaultValue="New York"
                  required
                  className="w-full h-14 px-4 border-2 border-on-surface rounded-none font-medium bg-surface text-on-surface transition-all focus:border-primary-container focus:ring-0"
                />
              </div>
            </div>
          </div>

          {/* Payment Information Card */}
          <div className="border-2 border-on-surface bg-surface p-8">
            <h3 className="font-headline-md text-xl font-bold uppercase tracking-wider text-on-surface pb-3 border-b-2 border-on-surface mb-6">
              Payment Information
            </h3>

            <div className="space-y-4">
              <div className="space-y-1">
                <label htmlFor="cardNumber" className="font-bold text-xs uppercase tracking-wider text-secondary block">
                  Card Number (Demo Mode Only)
                </label>
                <div className="relative">
                  <input
                    type="text"
                    id="cardNumber"
                    defaultValue="4242 4242 4242 4242"
                    disabled
                    style={{ background: '#f3f4f6' }}
                    className="w-full h-14 pl-4 pr-12 border-2 border-surface-container-highest rounded-none font-medium text-secondary cursor-not-allowed"
                  />
                  <Icon name="lock" className="absolute right-4 top-4 text-secondary" />
                </div>
              </div>
            </div>
          </div>

        </div>

        {/* Right Column: Order Summary & Info */}
        <div className="w-full lg:max-w-md space-y-6">

          {/* Demo Mode Alert Banner */}
          <div className="border-2 border-on-surface p-6 bg-primary-fixed text-on-primary-fixed-variant relative overflow-hidden">
            <div className="flex gap-3 items-start relative z-10">
              <Icon name="info" className="text-2xl text-on-primary-fixed-variant" />
              <div>
                <h4 className="font-bold text-sm uppercase tracking-wider mb-1">Demo Environment</h4>
                <p className="text-xs leading-relaxed opacity-90 font-medium">
                  This checkout is in demo mode. No payment will be processed, and no real credit card numbers will be verified.
                </p>
              </div>
            </div>
            <div className="absolute -bottom-8 -right-8 w-20 h-20 bg-primary-container opacity-10 rounded-full"></div>
          </div>

          {/* Summary Details */}
          <div className="border-2 border-on-surface p-8 bg-surface">
            <h3 className="font-headline-md text-lg font-extrabold mb-6 uppercase tracking-wider text-on-surface border-b-2 border-on-surface pb-2">
              Order Summary
            </h3>

            <div className="space-y-4">
              <div className="flex justify-between border-b border-surface-container pb-3 text-sm">
                <span className="text-secondary font-bold uppercase tracking-wider">Items in Cart</span>
                <span className="font-extrabold text-on-surface">{itemCount} {itemCount === 1 ? 'Item' : 'Items'}</span>
              </div>

              <div className="flex justify-between border-b border-surface-container pb-3 text-sm">
                <span className="text-secondary font-bold uppercase tracking-wider">Shipping</span>
                <span className="font-black text-primary-container uppercase tracking-wider">FREE EXPRESS</span>
              </div>

              <div className="flex justify-between pt-3 pb-1 font-black text-lg border-t-2 border-on-surface border-dashed">
                <span className="uppercase tracking-widest text-on-surface">Total to Pay</span>
                <span className="text-primary-container text-xl md:text-2xl font-black">Ksh {total.toFixed(2)}</span>
              </div>
            </div>

            {/* Heavy Neobrutalist Submit Button */}
            <button
              type="submit"
              disabled={submitting}
              className="mt-8 w-full h-14 bg-primary-container text-on-primary-container font-headline-md font-extrabold uppercase tracking-wider text-sm border-b-4 border-on-surface flex items-center justify-center transition-all active:scale-[0.98] hover:bg-amber-500 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {submitting ? 'Placing Order...' : 'Place Order'}
            </button>

            <Link
              href="/cart"
              className="mt-4 w-full h-12 border-2 border-on-surface font-bold uppercase tracking-wider text-xs flex items-center justify-center hover:bg-surface-container-low transition-colors"
            >
              Back to Cart
            </Link>
          </div>

        </div>
      </form>
    </main>
  );
}



'use client';

import { useState } from 'react';
import Link from 'next/link';
import Image from 'next/image';
import { sendPasswordResetEmail } from 'firebase/auth';
import { auth } from '@/lib/firebase';
import Icon from '@/components/Icon';

type Status = 'idle' | 'submitting' | 'success' | 'error';

export default function ForgotPasswordPage() {
  const [email, setEmail] = useState('');
  const [status, setStatus] = useState<Status>('idle');
  const [errorMessage, setErrorMessage] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setStatus('submitting');
    setErrorMessage('');

    try {
      await sendPasswordResetEmail(auth, email);
      setStatus('success');
    } catch (err: any) {
      setStatus('error');
      const code = err?.code || '';
      if (code === 'auth/invalid-email') {
        setErrorMessage('Please enter a valid email address.');
      } else if (code === 'auth/user-not-found') {
        setErrorMessage('No account found with this email address.');
      } else {
        setErrorMessage('Something went wrong. Please try again later.');
      }
    }
  };

  return (
    <main className="flex-grow flex items-center justify-center py-20 px-4 md:px-16 min-h-[calc(100vh-140px)]">
      <div className="w-full max-w-[520px] bg-surface border-2 border-on-background shadow-[4px_4px_0px_0px_var(--color-on-surface)]">
        {/* Header */}
        <div className="bg-on-background text-background p-8 md:p-10">
          <Link href="/" className="inline-block mb-6 flex items-center gap-2">
            <Image src="/Logo.svg" alt="Logo" width={40} height={40} className="w-auto h-10 invert hue-rotate-180 dark:invert-0 dark:hue-rotate-0" style={{ width: 'auto' }} />
            <Image src="/name.svg" alt="JUJ4" width={100} height={40} className="w-auto h-6 invert hue-rotate-180 dark:invert-0 dark:hue-rotate-0" />
          </Link>
          <h1 className="font-headline-md text-2xl md:text-3xl font-black uppercase tracking-tight mb-2">
            Reset Password
          </h1>
          <p className="font-body-md text-sm opacity-80 leading-relaxed">
            Enter the email address associated with your account and we&apos;ll send you a link to reset your password.
          </p>
        </div>

        {/* Form Body */}
        <div className="p-8 md:p-10">
          {/* Success State */}
          {status === 'success' ? (
            <div className="space-y-6">
              <div className="flex items-start gap-4 p-4 bg-green-50 border-2 border-green-600">
                <Icon name="check_circle" className="text-green-600 text-2xl mt-0.5" />
                <div>
                  <p className="font-bold text-sm text-green-800 mb-1">Password reset email sent!</p>
                  <p className="text-xs text-green-700 leading-relaxed">
                    Check your inbox for a link to reset your password. If it doesn&apos;t appear within a few minutes, check your spam folder.
                  </p>
                </div>
              </div>

              <button
                type="button"
                onClick={() => {
                  setStatus('idle');
                  setEmail('');
                }}
                className="w-full h-14 border-2 border-on-background font-headline-md font-bold uppercase tracking-wider text-sm transition-all hover:bg-surface-container-low active:scale-[0.98] flex items-center justify-center gap-2"
              >
                <Icon name="refresh" className="text-lg" />
                Send Another Link
              </button>

              <Link
                href="/login"
                className="w-full h-14 bg-on-background text-white font-headline-md font-bold uppercase tracking-wider text-sm transition-all hover:bg-neutral-800 active:scale-[0.98] flex items-center justify-center gap-2"
              >
                <Icon name="arrow_back" className="text-lg" />
                Back to Sign In
              </Link>
            </div>
          ) : (
            /* Form State */
            <form onSubmit={handleSubmit} className="space-y-6">
              {/* Error Message */}
              {status === 'error' && errorMessage && (
                <div className="p-4 bg-error-container border-2 border-error text-on-error-container font-semibold text-sm flex items-start gap-3">
                  <Icon name="error" className="text-error text-xl mt-0.5 shrink-0" />
                  <span>{errorMessage}</span>
                </div>
              )}

              <div className="space-y-2">
                <label
                  className="font-bold text-xs tracking-wider block text-on-background uppercase"
                  htmlFor="reset-email"
                >
                  Email Address
                </label>
                <input
                  className="w-full h-14 px-4 border border-on-background rounded-none font-medium transition-all"
                  id="reset-email"
                  placeholder="name@domain.com"
                  type="email"
                  required
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  autoComplete="email"
                  disabled={status === 'submitting'}
                />
              </div>

              <button
                className="w-full h-14 bg-primary-container text-on-primary-container font-headline-md font-bold uppercase tracking-wider text-sm transition-all active:scale-[0.98] border-b-4 border-on-background flex items-center justify-center hover:bg-amber-500 disabled:opacity-60 disabled:cursor-not-allowed"
                type="submit"
                disabled={status === 'submitting'}
              >
                {status === 'submitting' ? (
                  <>
                    <Icon name="progress_activity" className="text-lg mr-2 animate-spin" />
                    Sending...
                  </>
                ) : (
                  'Send Reset Link'
                )}
              </button>

              <div className="relative py-2">
                <div className="absolute inset-0 flex items-center">
                  <div className="w-full border-t border-surface-container-highest"></div>
                </div>
                <div className="relative flex justify-center text-xs uppercase">
                  <span className="bg-surface px-3 text-secondary font-bold tracking-wider">
                    Or
                  </span>
                </div>
              </div>

              <Link
                href="/login"
                className="w-full h-14 border-2 border-on-background font-headline-md font-bold uppercase tracking-wider text-sm transition-all hover:bg-surface-container-low active:scale-[0.98] flex items-center justify-center gap-2"
              >
                <Icon name="arrow_back" className="text-lg" />
                Back to Sign In
              </Link>

              <p className="text-xs text-secondary text-center leading-relaxed">
                Don&apos;t have an account?{' '}
                <Link
                  href="/register"
                  className="underline font-bold text-on-background hover:text-primary-container"
                >
                  Create one here
                </Link>
              </p>
            </form>
          )}
        </div>
      </div>
    </main>
  );
}



@import url('https://fonts.googleapis.com/css2?family=Montserrat:wght@400;500;700;800;900&family=Inter:wght@300;400;500;600;700&display=swap');
@import "tailwindcss";

@custom-variant dark (&:is(.dark *));

@theme {
  /* ─── BOLT Color Palette ─── */

  --color-on-secondary-fixed: #1b1b1b;
  --color-on-surface-variant: #564334;
  --color-on-background: #1a1c1c;
  --color-secondary-fixed-dim: #c6c6c6;
  --color-surface-container-highest: #e2e2e2;
  --color-on-surface: #1a1c1c;
  --color-on-secondary-container: #646464;
  --color-on-primary: #ffffff;
  --color-primary-fixed: #ffdcc3;
  --color-on-primary-fixed-variant: #6e3900;
  --color-surface-bright: #f9f9f9;
  --color-surface-tint: #904d00;
  --color-surface: #f9f9f9;
  --color-secondary-container: #e2e2e2;
  --color-error-container: #ffdad6;
  --color-on-tertiary-container: #004360;
  --color-inverse-surface: #2f3131;
  --color-on-error-container: #93000a;
  --color-on-tertiary: #ffffff;
  --color-surface-container-lowest: #ffffff;
  --color-primary-fixed-dim: #ffb77d;
  --color-tertiary-container: #00b5fc;
  --color-inverse-on-surface: #f0f1f1;
  --color-tertiary-fixed: #c7e7ff;
  --color-background: #f9f9f9;
  --color-secondary: #5e5e5e;
  --color-primary: #904d00;
  --color-tertiary: #00658f;
  --color-on-tertiary-fixed-variant: #004c6c;
  --color-on-secondary: #ffffff;
  --color-secondary-fixed: #e2e2e2;
  --color-on-secondary-fixed-variant: #474747;
  --color-inverse-primary: #ffb77d;
  --color-surface-variant: #e2e2e2;
  --color-error: #ba1a1a;
  --color-surface-container: #eeeeee;
  --color-on-error: #ffffff;
  --color-outline: #897362;
  --color-surface-container-high: #e8e8e8;
  --color-on-primary-fixed: #2f1500;
  --color-tertiary-fixed-dim: #85cfff;
  --color-on-primary-container: #623200;
  --color-surface-container-low: #f3f3f4;
  --color-surface-dim: #dadada;
  --color-outline-variant: #ddc1ae;
  --color-on-tertiary-fixed: #001e2e;
  --color-primary-container: #ff8c00;

  /* Typography / Fonts */
  --font-headline-md: "Montserrat", sans-serif;
  --font-body-md: "Inter", sans-serif;
}

@layer base {
  .dark {
    --color-background: #121212;
    --color-on-background: #e2e2e2;
    --color-surface: #1a1a1a;
    --color-on-surface: #f9f9f9;
    --color-surface-container: #222222;
    --color-surface-container-low: #1e1e1e;
    --color-surface-container-lowest: #0a0a0a;
    --color-surface-container-highest: #333333;
    --color-surface-dim: #2a2a2a;
    --color-secondary: #a3a3a3;
    --color-outline: #e2e2e2;
    --color-on-surface-variant: #e2e2e2;
    --color-primary-container: #ff8c00;
    --color-on-primary-container: #1a1c1c;
    --color-error: #ff5252;
    --color-error-container: #5c0000;
    --color-on-error-container: #ffdad6;
  }
}

body {
  font-family: 'Inter', sans-serif;
  background-color: var(--color-background);
  color: var(--color-on-background);
}

.bolt-headline {
  font-family: 'Montserrat', sans-serif;
}

/* Material Symbols Integration */
.material-symbols-outlined {
  font-variation-settings: 'FILL' 0, 'wght' 400, 'GRAD' 0, 'opsz' 24;
  display: inline-block;
  vertical-align: middle;
}

/* Neobrutalist Borders and Hover Shadows */
.auth-card-border {
  border: 2px solid var(--color-on-surface);
}

.auth-card-shadow {
  transition: all 0.2s cubic-bezier(0.16, 1, 0.3, 1);
}

.auth-card-shadow:hover {
  transform: translate(-3px, -3px);
  box-shadow: 4px 4px 0px 0px var(--color-on-surface);
}

/* Global Heavy Border Overrides */
.heavy-border {
  border: 2px solid var(--color-on-surface);
}

/* Interactive Input Focus */
input:focus, select:focus, textarea:focus {
  outline: none !important;
  border-color: #ff8c00 !important;
  border-width: 2px !important;
  box-shadow: none !important;
}

/* Default input background to match theme (prevents white flash in dark mode) */
input, select, textarea {
  background-color: var(--color-surface);
  color: var(--color-on-surface);
}

/* Hide scrollbar utility */
.no-scrollbar::-webkit-scrollbar {
  display: none;
}

.section-title {
  font-family: 'Montserrat', sans-serif;
  font-size: 1.8rem;
  font-weight: 800;
  color: var(--color-on-surface);
  line-height: 1.2;
  margin-bottom: 16px;
}

@media (min-width: 768px) {
  .section-title {
    font-size: 2.5rem;
  }
}

.section-subtitle {
  color: var(--color-secondary);
  font-size: 1.05rem;
  line-height: 1.7;
  max-width: 640px;
}

/* ─── Badge ─── */
.badge {
  display: inline-flex;
  align-items: center;
  padding: 4px 12px;
  font-size: 0.7rem;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.04em;
  border-radius: 0.25rem;
  background: var(--color-primary-container);
  color: var(--color-on-primary-container);
}

/* ─── Scrollbar ─── */
::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-track {
  background: var(--color-surface-container);
}

::-webkit-scrollbar-thumb {
  background: var(--color-secondary-container);
  border: 1px solid var(--color-surface-container-highest);
}

::-webkit-scrollbar-thumb:hover {
  background: var(--color-secondary);
}

.custom-scrollbar::-webkit-scrollbar {
  width: 4px;
}
.custom-scrollbar::-webkit-scrollbar-thumb {
  background: var(--color-outline-variant);
  border-radius: 10px;
}

.sidebar-item:hover {
  background-color: var(--color-surface);
  color: var(--color-primary-container);
}
.active-category {
  background-color: var(--color-surface);
  color: var(--color-primary-container);
  border-right: 4px solid var(--color-primary-container);
}
.product-card {
  transition: transform 0.2s ease, box-shadow 0.2s ease;
}
.product-card:hover {
  transform: translateY(-4px);
  box-shadow: 0 10px 25px -5px rgba(0, 0, 0, 0.1);
  border-color: var(--color-primary-container);
}



"use client";

import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import { onAuthStateChanged } from "firebase/auth";
import { doc, getDoc } from "firebase/firestore";
import { auth, db } from "@/lib/firebase";
import Link from "next/link";
import { Package, ShoppingCart, LayoutDashboard, Settings } from "lucide-react";

export default function MerchantLayout({ children }: { children: React.ReactNode }) {
  const [loading, setLoading] = useState(true);
  const [isMerchant, setIsMerchant] = useState(false);
  const router = useRouter();

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (user) => {
      if (!user) {
        // Not logged in -> redirect to auth screen
        router.push("/login?redirect=/merchant");
      } else {
        // Check if the user has the 'merchant' role in Firestore
        try {
          const userDoc = await getDoc(doc(db, "users", user.uid));
          if (userDoc.exists() && userDoc.data()?.role === "merchant") {
            setIsMerchant(true);
          } else {
            // Logged in, but NOT a merchant -> redirect to home
            router.push("/");
          }
        } catch (error) {
          console.error("Error checking merchant access:", error);
          router.push("/");
        }
      }
      setLoading(false);
    });

    return () => unsubscribe();
  }, [router]);

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-surface">
        <div className="text-center">
          <div className="w-16 h-16 border-4 border-on-surface border-t-primary-container rounded-full animate-spin mx-auto mb-6 shadow-[4px_4px_0px_0px_var(--color-on-surface)]"></div>
          <h2 className="font-headline-md font-black uppercase text-on-surface tracking-widest text-xl">
            Verifying Merchant Access...
          </h2>
        </div>
      </div>
    );
  }

  if (!isMerchant) {
    return null;
  }

  return (
    <div className="flex flex-col md:flex-row min-h-screen bg-surface">
      {/* Sidebar Navigation for Merchant */}
      <aside className="w-full md:w-64 bg-on-surface text-surface dark:bg-surface-container-low dark:text-on-surface flex flex-col border-b-4 md:border-b-0 md:border-r-4 border-on-surface shrink-0 transition-colors">
        <div className="p-4 md:p-6 border-b-4 border-on-surface border-dashed transition-colors">
          <h2 className="font-headline-md font-black text-xl md:text-2xl tracking-tight text-primary-container">
            MERCHANT HUB
          </h2>
        </div>
        <nav className="p-2 md:p-4 flex flex-row md:flex-col overflow-x-auto md:space-y-4 font-body-lg font-bold hide-scrollbar">
          <Link href="/merchant" className="flex items-center gap-2 md:gap-3 p-3 hover:bg-surface hover:text-on-surface dark:hover:bg-surface-container-high dark:hover:text-primary-container border-2 border-transparent hover:border-on-surface transition-colors rounded-none shrink-0">
            <LayoutDashboard size={20} className="md:w-6 md:h-6" />
            <span className="text-sm md:text-base">Dashboard</span>
          </Link>
          <Link href="/merchant/products" className="flex items-center gap-2 md:gap-3 p-3 hover:bg-surface hover:text-on-surface dark:hover:bg-surface-container-high dark:hover:text-primary-container border-2 border-transparent hover:border-on-surface transition-colors rounded-none shrink-0">
            <Package size={20} className="md:w-6 md:h-6" />
            <span className="text-sm md:text-base">My Products</span>
          </Link>
          <Link href="/merchant/orders" className="flex items-center gap-2 md:gap-3 p-3 hover:bg-surface hover:text-on-surface dark:hover:bg-surface-container-high dark:hover:text-primary-container border-2 border-transparent hover:border-on-surface transition-colors rounded-none shrink-0">
            <ShoppingCart size={20} className="md:w-6 md:h-6" />
            <span className="text-sm md:text-base">My Orders</span>
          </Link>
          <Link href="/merchant/settings" className="flex items-center gap-2 md:gap-3 p-3 hover:bg-surface hover:text-on-surface dark:hover:bg-surface-container-high dark:hover:text-primary-container border-2 border-transparent hover:border-on-surface transition-colors rounded-none shrink-0">
            <Settings size={20} className="md:w-6 md:h-6" />
            <span className="text-sm md:text-base">Settings</span>
          </Link>
        </nav>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 overflow-auto">
        {children}
      </main>
    </div>
  );
}



"use client";

import React, { useEffect, useState } from "react";
import { collection, query, where, getDocs, doc, updateDoc, Timestamp } from "firebase/firestore";
import { auth, db } from "@/lib/firebase";
import { Order } from "@/types/schema";

export default function MerchantOrders() {
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const [expandedOrderId, setExpandedOrderId] = useState<string | null>(null);

  useEffect(() => {
    const fetchOrders = async () => {
      const user = auth.currentUser;
      if (!user) return;

      try {
        const ordersQuery = query(
          collection(db, "orders"), 
          where("merchantId", "==", user.uid)
        );
        const snapshot = await getDocs(ordersQuery);
        const ordersList = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Order));
        // Sort client-side to avoid requiring a composite index in Firestore
        ordersList.sort((a, b) => {
          const timeA = a.createdAt ? (a.createdAt as { seconds?: number }).seconds || 0 : 0;
          const timeB = b.createdAt ? (b.createdAt as { seconds?: number }).seconds || 0 : 0;
          return timeB - timeA;
        });
        setOrders(ordersList);
      } catch (error) {
        console.error("Error fetching merchant orders:", error);
      } finally {
        setLoading(false);
      }
    };

    if (auth.currentUser) {
      fetchOrders();
    } else {
      const unsubscribe = auth.onAuthStateChanged((user) => {
        if (user) fetchOrders();
      });
      return () => unsubscribe();
    }
  }, []);

  const handleUpdateOrderStatus = async (orderId: string, newStatus: string) => {
    try {
      await updateDoc(doc(db, 'orders', orderId), {
        status: newStatus,
        updatedAt: Timestamp.now()
      });
      setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status: newStatus as any } : o));
    } catch (err) {
      console.error('Error updating order status:', err);
      alert('Failed to update order status.');
    }
  };

  const toggleDetails = (orderId: string) => {
    if (expandedOrderId === orderId) {
      setExpandedOrderId(null);
    } else {
      setExpandedOrderId(orderId);
    }
  };

  if (loading) {
    return <div className="p-8">Loading orders...</div>;
  }

  return (
    <div className="p-8">
      <h1 className="font-headline-lg font-black text-4xl mb-8 uppercase border-b-4 border-on-surface inline-block pb-2">
        My Orders
      </h1>

      <div className="bg-surface border-4 border-on-surface overflow-x-auto">
        <table className="w-full text-left border-collapse min-w-[600px]">
          <thead>
            <tr className="bg-on-surface text-surface uppercase font-bold text-sm">
              <th className="p-4 border-b-4 border-on-surface">Order ID</th>
              <th className="p-4 border-b-4 border-on-surface">Date</th>
              <th className="p-4 border-b-4 border-on-surface">Status</th>
              <th className="p-4 border-b-4 border-on-surface">Total</th>
              <th className="p-4 border-b-4 border-on-surface text-right">Actions</th>
            </tr>
          </thead>
          <tbody>
            {orders.length === 0 ? (
              <tr>
                <td colSpan={5} className="p-8 text-center font-bold">No orders found.</td>
              </tr>
            ) : (
              orders.map((order) => {
                const date = order.createdAt ? new Date((order.createdAt as { seconds?: number }).seconds! * 1000).toLocaleDateString() : 'N/A';
                const isExpanded = expandedOrderId === order.id;

                return (
                  <React.Fragment key={order.id}>
                    <tr className="border-b border-on-surface hover:bg-surface-dim transition-colors">
                      <td className="p-4 font-mono text-sm">{order.id}</td>
                      <td className="p-4">{date}</td>
                      <td className="p-4">
                        <select 
                          value={order.status}
                          onChange={(e) => order.id && handleUpdateOrderStatus(order.id, e.target.value)}
                          className="text-[10px] px-2 py-1 font-black uppercase border-2 border-on-surface cursor-pointer outline-none bg-secondary-container text-on-surface"
                        >
                          <option value="pending">PENDING</option>
                          <option value="processing">PROCESSING</option>
                          <option value="shipped">SHIPPED</option>
                          <option value="delivered">DELIVERED</option>
                          <option value="cancelled">CANCELLED</option>
                        </select>
                      </td>
                      <td className="p-4 font-bold">Ksh {order.totalAmount.toFixed(2)}</td>
                      <td className="p-4 text-right">
                        <button 
                          onClick={() => order.id && toggleDetails(order.id)}
                          className="text-sm border-2 border-on-surface px-3 py-1 font-bold hover:bg-on-surface hover:text-surface transition-colors"
                        >
                          {isExpanded ? 'Hide Details' : 'View Details'}
                        </button>
                      </td>
                    </tr>
                    {isExpanded && (
                      <tr className="bg-surface-dim border-b-4 border-on-surface">
                        <td colSpan={5} className="p-6">
                          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                            <div>
                              <h4 className="font-bold uppercase text-sm border-b-2 border-on-surface pb-1 mb-4">Customer Info</h4>
                              <p className="text-sm mb-1"><span className="font-bold">Name:</span> {order.contactInformation?.fullName || 'N/A'}</p>
                              <p className="text-sm mb-1"><span className="font-bold">Email:</span> {order.contactInformation?.email || 'N/A'}</p>
                              <p className="text-sm mb-4"><span className="font-bold">Phone:</span> {order.contactInformation?.phone || 'N/A'}</p>

                              <h4 className="font-bold uppercase text-sm border-b-2 border-on-surface pb-1 mb-4">Shipping Address</h4>
                              <p className="text-sm mb-1">{order.shippingAddress?.street}</p>
                              <p className="text-sm mb-1">{order.shippingAddress?.city}, {order.shippingAddress?.zipCode}</p>
                              <p className="text-sm">{order.shippingAddress?.country}</p>
                            </div>
                            <div>
                              <h4 className="font-bold uppercase text-sm border-b-2 border-on-surface pb-1 mb-4">Order Items</h4>
                              <div className="space-y-4">
                                {order.items.map((item: { name: string; quantity: number; price: number }, idx: number) => (
                                  <div key={idx} className="flex justify-between items-center border-b border-on-surface pb-2">
                                    <div>
                                      <p className="font-bold text-sm">{item.name}</p>
                                      <p className="text-xs text-secondary">Qty: {item.quantity}</p>
                                    </div>
                                    <p className="font-bold text-sm">Ksh {(item.price * item.quantity).toFixed(2)}</p>
                                  </div>
                                ))}
                                <div className="flex justify-between items-center pt-2">
                                  <p className="font-black uppercase text-sm">Order Total</p>
                                  <p className="font-black text-lg">Ksh {order.totalAmount.toFixed(2)}</p>
                                </div>
                              </div>
                            </div>
                          </div>
                        </td>
                      </tr>
                    )}
                  </React.Fragment>
                );
              })
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}



'use client';

import { useState } from 'react';
import Link from 'next/link';
import Image from 'next/image';
import Icon from '@/components/Icon';

